                gsap.set(overlay, { rotation: 0 })
                if (wheelRef.current) {
                  wheelRef.current.style.transform  = ''
                  wheelRef.current.style.transition = ''
                }
              },
            })
          }
        },
      })[0]

      draggableRef.current = d
    }

