    return () => {
      if (draggableRef.current) { draggableRef.current.kill(); draggableRef.current = null }
      if (wheelRef.current) {
        wheelRef.current.style.transform  = ''
        wheelRef.current.style.transition = ''
      }
    }
  }, [open])   // ← only open; live values read via refs

