                    const fill = slot.rarity === 'legendary' ? (i%2===0?'#5C3D00':'#4A3000')
                      : slot.rarity === 'epic' ? (i%2===0?'#4A1A6B':'#3A1255')
                      : slot.rarity === 'rare' ? (i%2===0?'#1A4060':'#14335A')
                      : slot.rarity === 'uncommon' ? (i%2===0?'#1A4A30':'#143D25')
                      : (i%2===0?'#2A2E48':'#222640')

                    return (
                      <g key={i}>
                         <path
                           d={`M${cx},${cy} L${x1},${y1} A${r},${r} 0 0,1 ${x2},${y2} Z`}
                           fill={dark ? fill : (i%2===0?'#F5F0FF':'#FFF8EC')}
                           stroke={dark?'rgba(255,255,255,0.08)':'rgba(0,0,0,0.06)'}
                           strokeWidth="1"
                           style={{ filter: spinning ? 'brightness(1.15) contrast(1.1)' : 'none' }}
                         />
                        {slot.img ? (
                          <>
                            {/* Game asset image for exclusive slots */}
                            <image
                              href={slot.img}
                              x={lx - 18} y={ly - 20}
                              width="36" height="36"
                              preserveAspectRatio="xMidYMid meet"
                              transform={`rotate(${labelAngle}, ${lx}, ${ly})`}
                              style={{ filter: 'drop-shadow(0 1px 3px rgba(0,0,0,0.5))' }}
                            />
                            <text x={lx} y={ly+24} textAnchor="middle"
                              fontSize="6.5" fontWeight="800" fill={slot.color}
                              fontFamily="'Fredoka One',cursive"
                              transform={`rotate(${labelAngle}, ${lx}, ${ly})`}>
                              {slot.label.length > 12 ? slot.label.slice(0,12)+'…' : slot.label}
                            </text>
                          </>
                        ) : (
                          <>
                            <text x={lx} y={ly-6} textAnchor="middle" fontSize="20"
                              transform={`rotate(${labelAngle}, ${lx}, ${ly})`}>
                              {slot.icon}
                            </text>
                            <text x={lx} y={ly+10} textAnchor="middle"
                              fontSize="7" fontWeight="800" fill={slot.color}
                              fontFamily="'Fredoka One',cursive"
                              transform={`rotate(${labelAngle}, ${lx}, ${ly})`}>
                              {slot.label.length > 12 ? slot.label.slice(0,12)+'…' : slot.label}
                            </text>
                          </>
                        )}
                      </g>
                    )
                      } catch(e) {
                        console.error('Error rendering slot', i, e)
                        return null
                      }
                    })}
                  {/* Center circle */}
                  <circle cx="150" cy="150" r="32" fill={dark?'#0a0c1c':'#fff'}
                    stroke={dark?'rgba(255,215,0,0.3)':'rgba(255,215,0,0.4)'} strokeWidth="3" />
                  <text x="150" y="155" textAnchor="middle" fontSize="22">🎰</text>
                </svg>
                ) : (
                  <div style={{
                    width: '100%', height: '100%', display: 'flex',
                    alignItems: 'center', justifyContent: 'center',
                    color: tc.textMuted, fontSize: 14, minHeight: 200
                  }}>
                    Loading wheel...
                  </div>
                )}

                {/* Transparent drag overlay — always in DOM, Draggable target */}
                <div
                  ref={dragOverlayRef}
                  style={{
                    position: 'absolute',
                    top: 0, left: 0,
                    width: 280, height: 280,
                    borderRadius: '50%',
                    zIndex: 4,
                    cursor: spinning ? 'not-allowed' : 'grab',
                    WebkitTapHighlightColor: 'transparent',
                    touchAction: 'none',
                    pointerEvents: spinning ? 'none' : 'auto',
                  }}
                />
              </div>

              {/* Drag hint */}
              <div style={{
                textAlign: 'center', fontSize: 11, color: tc.textMuted,
                marginBottom: 16, fontWeight: 600,
                opacity: spinning ? 0 : 0.7, transition: 'opacity 0.3s',
                userSelect: 'none',
              }}>
                {hasFreeSpins ? '👆 Putar atau seret roda' : '👆 Seret cepat untuk spin'}
              </div>

              {/* Spin buttons */}
              <div className="spin-btns">
                {isMultiActive ? (
                  <>
                    {/* During multi-spin sequence: show progress + skip */}
                    <div style={{
                      display: 'flex', alignItems: 'center', gap: 8, justifyContent: 'center',
                      padding: '8px 0', width: '100%',
                    }}>
                      {/* Progress dots */}
                      {multiQueue.map((_, i) => (
                        <div key={i} style={{
                          width: 28, height: 28, borderRadius: '50%',
                          background: i < multiIdx
                            ? 'linear-gradient(135deg,#4ECDC4,#00B894)'
                            : i === multiIdx && spinning
                              ? 'linear-gradient(135deg,#A29BFE,#6C5CE7)'
                              : dark ? 'rgba(255,255,255,0.08)' : 'rgba(0,0,0,0.06)',
                          display: 'flex', alignItems: 'center', justifyContent: 'center',
                          fontSize: 11, fontWeight: 800, color: i < multiIdx ? '#fff' : tc.textMuted,
                          transition: 'all 0.3s',
                          animation: i === multiIdx && spinning ? 'pulse 1s ease infinite' : 'none',
                          border: i === multiIdx ? '2px solid #A29BFE' : '2px solid transparent',
                        }}>
                          {i < multiIdx ? '✓' : i + 1}
                        </div>
                      ))}
                    </div>
                    <button className="spin-btn multi" onClick={skipMultiSpin}
                      style={{ background: 'linear-gradient(135deg,#636E72,#2D3436)' }}>
                      ⏩ Skip — Lihat Semua
                    </button>
                  </>
                ) : (
                  <>
                    <button className="spin-btn free" disabled={spinning || !hasFreeSpins}
                      onClick={() => doSpin(true)}>
                      {spinning ? '⏳ Spinning...' : hasFreeSpins ? '🎁 Free Spin!' : '✓ Sudah Klaim'}
                    </button>
                    <button className="spin-btn paid" disabled={spinning || coins < extraSpinCost}
                      onClick={() => doSpin(false)}>
                      🪙 {extraSpinCost}
                    </button>
                    <button className="spin-btn multi" disabled={spinning || coins < multiCost}
                      onClick={doMultiSpin}>
                      {spinning ? '⏳' : `5× 🪙 ${multiCost}`}
                    </button>
                  </>
                )}
              </div>

              {/* Pity indicator */}
              <div style={{ textAlign: 'center', fontSize: 11, color: tc.textMuted, fontWeight: 600 }}>
                Pity: {pityCounter}/50 — {pityCounter >= 45 ? '🔥 Hampir Epic!' : 'Epic guaranteed setelah 50 spin'}
              </div>
              <div className="pity-bar">
                <div className="pity-fill" style={{ width: `${Math.min(pityCounter/50*100, 100)}%` }} />
              </div>

              {/* Coin balance */}
              <div style={{ textAlign: 'center', marginTop: 14, fontSize: 13, color: tc.textMuted }}>
                💰 Saldo: <strong style={{ color: '#FFD700' }}>{coins}</strong> coin
              </div>
            </>
          )}

          {/* ── COLLECTION TAB ── */}
          {tab === 'collection' && (
            <>
              <div style={{ marginBottom: 16 }}>
                <div style={{ fontFamily: "'Fredoka One',cursive", fontSize: 16, color: textMain, marginBottom: 6 }}>
                  Koleksi Eksklusif ({wonExclusives.length}/{WHEEL_EXCLUSIVES.length})
                </div>
                <div style={{ fontSize: 12, color: tc.textMuted, lineHeight: 1.5 }}>
                  Item eksklusif yang hanya bisa didapat dari Lucky Wheel. Tidak dijual di Shop!
                </div>
              </div>
              <div className="collection-grid">
                {WHEEL_EXCLUSIVES.map(item => {
                  const owned = wonExclusives.includes(item.id)
                  return (
                    <div key={item.id} className={`collection-item ${owned?'owned':'locked'}`}>
                      <div style={{
                        position: 'absolute', top: 8, right: 8,
                        background: `${RARITY_COLORS[item.rarity]}22`,
                        color: RARITY_COLORS[item.rarity],
                        fontSize: 9, fontWeight: 800, padding: '2px 8px',
                        borderRadius: 100, border: `1px solid ${RARITY_COLORS[item.rarity]}44`,
                      }}>
                        {RARITY_LABELS[item.rarity]}
                      </div>
                      {item.img ? (
                        <img src={item.img} alt={item.name}
                          style={{ filter: owned ? 'none' : 'grayscale(100%) brightness(0.4)' }} />
                      ) : (
                        <div style={{ fontSize: 40, marginBottom: 8 }}>{owned ? item.icon : '🔒'}</div>
                      )}
                      <div style={{ fontFamily: "'Fredoka One',cursive", fontSize: 13, color: owned ? textMain : tc.textMuted, marginBottom: 2 }}>
                        {item.name}
                      </div>
                      <div style={{ fontSize: 10, color: tc.textMuted }}>
                        {item.game === 'space-shooter' ? '🚀 Space Shooter' :
                         item.game === 'voxel-racer' ? '🚗 Voxel Racer' :
                         item.game === 'neon-dash' ? '💎 Neon Dash' : item.game}
                      </div>
                      {owned && (
                        <div style={{ marginTop: 6, fontSize: 10, color: '#4ECDC4', fontWeight: 800 }}>✓ Dimiliki</div>
                      )}
                    </div>
                  )
                })}
              </div>
            </>
          )}

          {/* ── HISTORY TAB ── */}
          {tab === 'history' && (
            <>
              <div style={{ fontFamily: "'Fredoka One',cursive", fontSize: 16, color: textMain, marginBottom: 12 }}>
                📜 Riwayat Spin
              </div>
              {spinHistory.length === 0 ? (
                <div style={{ textAlign: 'center', padding: 40, color: tc.textMuted, fontSize: 14 }}>
                  Belum ada riwayat spin
                </div>
              ) : (
                spinHistory.map((h, i) => (
                  <div key={i} className="history-item">
                    <span style={{ fontSize: 22 }}>{h.icon}</span>
                    <div style={{ flex: 1 }}>
                      <div style={{ fontFamily: "'Fredoka One',cursive", fontSize: 13, color: textMain }}>{h.label}</div>
                      <div style={{ fontSize: 10, color: tc.textMuted }}>
                        {new Date(h.date).toLocaleDateString('id-ID')} {new Date(h.date).toLocaleTimeString('id-ID', {hour:'2-digit',minute:'2-digit'})}
                      </div>
                    </div>
                    <span style={{
                      background: `${RARITY_COLORS[h.rarity]}22`,
                      color: RARITY_COLORS[h.rarity],
                      fontSize: 10, fontWeight: 800, padding: '3px 8px',
                      borderRadius: 100,
                    }}>
                      {RARITY_LABELS[h.rarity]}
                    </span>
                  </div>
                ))
              )}
            </>
          )}
        </div>
      </div>

      {/* ── Result Modal ── */}
      {result && (
        <div className="wheel-result" onClick={() => setResult(null)}>
          {/* Confetti for epic+ */}
          {(result.rarity === 'epic' || result.rarity === 'legendary') && (
            <div className="wheel-confetti">
              {Array.from({length: 40}).map((_, i) => (
                <span key={i} style={{
                  left: `${Math.random()*100}%`,
                  background: ['#FFD700','#FF6B6B','#A29BFE','#4ECDC4','#FF8C00','#E040FB'][i%6],
                  borderRadius: Math.random() > 0.5 ? '50%' : '2px',
                  width: `${6+Math.random()*8}px`,
                  height: `${6+Math.random()*8}px`,
                  animationDelay: `${Math.random()*1.5}s`,
                  animationDuration: `${2+Math.random()*2}s`,
                }} />
              ))}
            </div>
          )}

          <div className="result-card" onClick={e => e.stopPropagation()}>
            <div className="result-banner" style={{
              background: `linear-gradient(90deg, ${RARITY_COLORS[result.rarity]}, ${RARITY_COLORS[result.rarity]}88, ${RARITY_COLORS[result.rarity]})`,
            }} />

            <div className="result-rarity" style={{
              background: `${RARITY_COLORS[result.rarity]}22`,
              color: RARITY_COLORS[result.rarity],
              border: `1px solid ${RARITY_COLORS[result.rarity]}44`,
            }}>
              {RARITY_LABELS[result.rarity]}
            </div>

            {result.img ? (
              <img className="result-img" src={result.img} alt={result.label} />
            ) : (
              <div className="result-icon">{result.icon}</div>
            )}

            <div className="result-name" style={{ color: textMain }}>{result.label}</div>
            <div className="result-desc">
              {result.desc || (result.type === 'coin' ? `+${result.amount} coin ditambahkan ke saldomu!`
                : result.type === 'xp' ? `+${result.amount} XP bonus!`
                : 'Kamu mendapatkan hadiah!')}
              {result.isDupe && (
                <div style={{ marginTop: 6, fontSize: 11, color: '#FFD700', fontWeight: 700 }}>
                  ♻️ Item sudah dimiliki — konversi ke coin!
                </div>
              )}
            </div>

            <button className="result-close-btn" onClick={() => setResult(null)}>
              {result.rarity === 'legendary' ? '🌟 Keren!' : result.rarity === 'epic' ? '✨ Mantap!' : '👍 OK'}
            </button>
          </div>
        </div>
      )}

      {/* ── Individual Reward Reveal (during sequential 5× spin) ── */}
      {multiCurrentReward && (
        <div className="multi-result" onClick={advanceMultiSpin}>
          {/* Confetti if high rarity */}
          {(multiCurrentReward.rarity === 'epic' || multiCurrentReward.rarity === 'legendary') && (
            <div className="wheel-confetti">
              {Array.from({length: 40}).map((_, i) => (
                <span key={i} style={{
                  left: `${Math.random()*100}%`,
                  background: ['#FFD700','#FF6B6B','#A29BFE','#4ECDC4','#FF8C00','#E040FB'][i%6],
                  borderRadius: Math.random() > 0.5 ? '50%' : '2px',
                  width: `${6+Math.random()*8}px`,
                  height: `${6+Math.random()*8}px`,
                  animationDelay: `${Math.random()*1}s`,
                  animationDuration: `${2+Math.random()*2}s`,
                }} />
              ))}
            </div>
          )}
          <div className="result-card" onClick={e => e.stopPropagation()} style={{ padding: '36px 24px' }}>
            {/* Spin number */}
            <div style={{
              fontSize: 11, fontWeight: 800, color: tc.textMuted, textTransform: 'uppercase',
              letterSpacing: 1, marginBottom: 8,
            }}>
              Spin {multiIdx} / {multiQueue ? multiQueue.length : MULTI_COUNT}
            </div>

            {/* Rarity badge */}
            <div className="result-rarity" style={{
              background: `${RARITY_COLORS[multiCurrentReward.rarity]}22`,
              color: RARITY_COLORS[multiCurrentReward.rarity],
              border: `1.5px solid ${RARITY_COLORS[multiCurrentReward.rarity]}44`,
            }}>
              {RARITY_LABELS[multiCurrentReward.rarity]}
            </div>

            {/* Icon / Image */}
            {multiCurrentReward.img ? (
              <img src={multiCurrentReward.img} alt={multiCurrentReward.label} className="result-img" />
            ) : (
              <div className="result-icon">{multiCurrentReward.icon}</div>
            )}

            {/* Name + desc */}
            <div className="result-name" style={{ color: textMain }}>{multiCurrentReward.label}</div>
            <div className="result-desc">
              {multiCurrentReward.type === 'coin' ? `+${multiCurrentReward.amount} coin`
                : multiCurrentReward.type === 'xp' ? `+${multiCurrentReward.amount} XP`
                : multiCurrentReward.type === 'exclusive' ? (multiCurrentReward.isDupe ? '♻️ Dupe → coin' : '🆕 Item baru!')
                : 'Reward'}
            </div>

            {/* Previously revealed items (mini) */}
            {multiRevealed.length > 1 && (
              <div style={{
                display: 'flex', gap: 6, justifyContent: 'center', marginBottom: 16, flexWrap: 'wrap',
              }}>
                {multiRevealed.slice(0, -1).map((r, i) => (
                  <div key={i} style={{
                    width: 32, height: 32, borderRadius: 10, fontSize: 18,
                    display: 'flex', alignItems: 'center', justifyContent: 'center',
                    background: `${RARITY_COLORS[r.rarity]}15`,
                    border: `1px solid ${RARITY_COLORS[r.rarity]}33`,
                  }}>
                    {r.img ? <img src={r.img} alt="" style={{ width: 22, height: 22, objectFit: 'contain' }} /> : <span style={{ fontSize: 16 }}>{r.icon}</span>}
                  </div>
                ))}
              </div>
            )}

            {/* Buttons */}
            <div style={{ display: 'flex', gap: 10, justifyContent: 'center' }}>
              <button className="result-close-btn" onClick={advanceMultiSpin}>
                {multiIdx >= (multiQueue ? multiQueue.length : MULTI_COUNT) ? '🎉 Lihat Hasil!' : '▶ Lanjut'}
              </button>
              {multiQueue && multiIdx < multiQueue.length && (
                <button className="result-close-btn" onClick={skipMultiSpin}
                  style={{ background: 'linear-gradient(135deg,#636E72,#2D3436)', boxShadow: 'none' }}>
                  ⏩ Skip
                </button>
              )}
            </div>
          </div>
        </div>
      )}

      {/* ── Multi-Result Modal (5× Spin) ── */}
      {multiResults && (
        <div className="multi-result" onClick={() => setMultiResults(null)}>
          {/* Confetti if any epic+ */}
          {multiResults.some(r => r.rarity === 'epic' || r.rarity === 'legendary') && (
            <div className="wheel-confetti">
              {Array.from({length: 40}).map((_, i) => (
                <span key={i} style={{
                  left: `${Math.random()*100}%`,
                  background: ['#FFD700','#FF6B6B','#A29BFE','#4ECDC4','#FF8C00','#E040FB'][i%6],
                  borderRadius: Math.random() > 0.5 ? '50%' : '2px',
                  width: `${6+Math.random()*8}px`,
                  height: `${6+Math.random()*8}px`,
                  animationDelay: `${Math.random()*1.5}s`,
                  animationDuration: `${2+Math.random()*2}s`,
                }} />
              ))}
            </div>
          )}

          <div className="multi-card" onClick={e => e.stopPropagation()}>
            <div style={{
              fontFamily: "'Fredoka One',cursive", fontSize: 22,
              background: 'linear-gradient(135deg,#E040FB,#AB47BC)',
              WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent',
              marginBottom: 4,
            }}>🎰 5× Spin Results!</div>
            <div style={{ fontSize: 12, color: tc.textMuted, marginBottom: 16, fontWeight: 600 }}>
              {multiResults.filter(r => r.rarity === 'epic' || r.rarity === 'legendary').length > 0
                ? `✨ ${multiResults.filter(r => r.rarity === 'epic' || r.rarity === 'legendary').length} item langka!`
                : 'Hasil spinmu:'}
            </div>

            {/* Summary stats */}
            <div className="multi-summary">
              {(() => {
                const totalCoins = multiResults.reduce((s, r) => s + (r.type === 'coin' ? r.amount : r.type === 'xp' ? Math.round(r.amount / 5) : 0), 0)
                const totalXP = multiResults.reduce((s, r) => s + (r.type === 'xp' ? r.amount : 0), 0)
                const exclusiveCount = multiResults.filter(r => r.type === 'exclusive').length
                return (<>
                  {totalCoins > 0 && <div className="multi-stat">🪙 +{totalCoins} Coin</div>}
                  {totalXP > 0 && <div className="multi-stat">⭐ +{totalXP} XP</div>}
                  {exclusiveCount > 0 && <div className="multi-stat">🎁 {exclusiveCount} Exclusive</div>}
                </>)
              })()}
            </div>

            {/* Individual results */}
            {multiResults.map((reward, i) => {
              const rarityClass = reward.rarity === 'legendary' ? 'legendary' : reward.rarity === 'epic' ? 'epic' : ''
              return (
                <div key={i} className={`multi-item ${rarityClass}`}
                  style={{ animationDelay: `${i * 0.08}s` }}>
                  {reward.img ? (
                    <img src={reward.img} alt={reward.label}
                      style={{ width: 36, height: 36, objectFit: 'contain', borderRadius: 8 }} />
                  ) : (
                    <span style={{ fontSize: 28, width: 36, textAlign: 'center' }}>{reward.icon}</span>
                  )}
                  <div style={{ flex: 1, minWidth: 0 }}>
                    <div style={{
                      fontFamily: "'Fredoka One',cursive", fontSize: 13,
                      color: textMain, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis',
                    }}>{reward.label}</div>
                    <div style={{ fontSize: 10, color: tc.textMuted }}>
                      {reward.type === 'coin' ? `+${reward.amount} coin`
                        : reward.type === 'xp' ? `+${reward.amount} XP`
                        : reward.type === 'exclusive' ? (reward.isDupe ? '♻️ Dupe → coin' : '🆕 Baru!')
                        : 'Reward'}
                    </div>
                  </div>
                  <span style={{
                    background: `${RARITY_COLORS[reward.rarity]}22`,
                    color: RARITY_COLORS[reward.rarity],
                    fontSize: 9, fontWeight: 800, padding: '3px 8px',
                    borderRadius: 100, border: `1px solid ${RARITY_COLORS[reward.rarity]}44`,
                    flexShrink: 0,
                  }}>
                    {RARITY_LABELS[reward.rarity]}
                  </span>
                </div>
              )
            })}

            <button className="result-close-btn" style={{ marginTop: 16 }}
              onClick={() => setMultiResults(null)}>
              {multiResults.some(r => r.rarity === 'legendary') ? '🌟 Mantap!' : '✨ Oke!'}
            </button>
          </div>
        </div>
      )}
    </>,
    document.body
  )
}

import { useEffect, useRef, useCallback } from 'react'
import gsap from 'gsap'

/**
 * Mascot Component v2 (Brainy) — Interactive SVG companion
 * 
 * @param {string}  skin        — Mascot skin ID
 * @param {string}  hat         — Mascot hat ID
 * @param {number}  size        — Visual size in pixels
 * @param {boolean} interactive — Enable hover/click reactions
 * @param {string}  expression  — 'happy'|'excited'|'shy'|'surprised'|'wink'|'sad'|'smug'|'think'|'sleep'
 * @param {boolean} trackEyes   — Enable cursor eye-tracking
 * @param {function} onTap      — Callback when mascot is tapped/clicked
 */
export default function Mascot({
  skin = 'neon-blue',
  hat = null,
  size = 120,
  interactive = true,
  expression = 'happy',
  trackEyes = true,
  onTap,
}) {
  const rootRef = useRef(null)
  const bodyRef = useRef(null)
  const eyeL = useRef(null)
  const eyeR = useRef(null)
  const mouthRef = useRef(null)
  const blushRef = useRef(null)
  const hatRef = useRef(null)
  const floatTween = useRef(null)
  const rotateTween = useRef(null)
  const blinkTimer = useRef(null)

  // ─── Skin palette ───
  const skins = {
    'neon-blue':     { main: '#00d2ff', glow: '#00d2ffaa', sec: '#00a8cc', accent: '#fff' },
    'classic-pink':  { main: '#ff7eb3', glow: '#ff7eb3aa', sec: '#de6097', accent: '#fff' },
    'stealth-black': { main: '#2d3436', glow: '#636e72',   sec: '#000000', accent: '#00d2ff' },
    'cyber-pink':    { main: '#FF6B9D', glow: '#FF6B9Daa', sec: '#D4437A', accent: '#fff' },
    'emerald-green': { main: '#55EFC4', glow: '#00B894aa', sec: '#00B894', accent: '#fff' },
    'royal-gold':    { main: '#FFD700', glow: '#FFD700cc', sec: '#DAA520', accent: '#fff' },
    'hologram':      { main: '#a29bfe', glow: '#6c5ce788', sec: '#6c5ce7', accent: '#fff', opacity: 0.6 },
  }
  const s = skins[skin] || skins['neon-blue']

  // ─── Mouth paths per expression ───
  const MOUTHS = {
    happy:     'M40 70 Q50 78 60 70',
    excited:   'M38 69 Q50 82 62 69',
    shy:       'M44 71 Q50 75 56 71',
    surprised: 'M45 72 Q50 77 55 72',
    wink:      'M40 70 Q50 78 60 70',
    sad:       'M42 74 Q50 68 58 74',
    smug:      'M40 71 Q48 76 60 69',
    think:     'M44 72 L56 72',
    sleep:     'M42 72 Q50 76 58 72',
  }

  // ─── Eye shapes per expression ───
  const EYE_SHAPES = {
    happy:     { lRx: 3.5, lRy: 3.5, rRx: 3.5, rRy: 3.5 },
    excited:   { lRx: 4,   lRy: 4.5, rRx: 4,   rRy: 4.5 },
    shy:       { lRx: 3,   lRy: 3,   rRx: 3,   rRy: 3   },
    surprised: { lRx: 4.5, lRy: 5,   rRx: 4.5, rRy: 5   },
    wink:      { lRx: 3.5, lRy: 3.5, rRx: 3.5, rRy: 0.8 },
    sad:       { lRx: 3,   lRy: 2.8, rRx: 3,   rRy: 2.8 },
    smug:      { lRx: 3,   lRy: 2.5, rRx: 3.5, rRy: 3.5 },
    think:     { lRx: 3.5, lRy: 3.5, rRx: 2,   rRy: 3.5 },
    sleep:     { lRx: 4,   lRy: 0.6, rRx: 4,   rRy: 0.6 },
  }

  // ─── Idle float + blink ───
  useEffect(() => {
    if (!bodyRef.current) return

    floatTween.current = gsap.to(bodyRef.current, {
      y: -6, duration: 2.2, repeat: -1, yoyo: true, ease: 'sine.inOut',
    })
    rotateTween.current = gsap.to(bodyRef.current, {
      rotation: 2, duration: 3, repeat: -1, yoyo: true, ease: 'power1.inOut',
    })

    const blink = () => {
      if (!eyeL.current || !eyeR.current) return
      if (expression === 'sleep') {
        blinkTimer.current = setTimeout(blink, 3000 + Math.random() * 3000)
        return
      }
      gsap.to([eyeL.current, eyeR.current], {
        scaleY: 0.1, duration: 0.1, yoyo: true, repeat: 1,
        transformOrigin: 'center center',
        onComplete: () => {
          blinkTimer.current = setTimeout(blink, 2000 + Math.random() * 4000)
        },
      })
    }
    blinkTimer.current = setTimeout(blink, 1500)

    return () => {
      floatTween.current?.kill()
      rotateTween.current?.kill()
      clearTimeout(blinkTimer.current)
    }
  }, [expression])

  // ─── Eye tracking ───
  useEffect(() => {
    if (!trackEyes || expression === 'sleep') return
    const onMove = (e) => {
      if (!rootRef.current || !eyeL.current || !eyeR.current) return
      const rect = rootRef.current.getBoundingClientRect()
      const cx = rect.left + rect.width / 2
      const cy = rect.top + rect.height / 2
      const dx = (e.clientX - cx) / window.innerWidth * 3.5
      const dy = (e.clientY - cy) / window.innerHeight * 2.5
      const clampX = Math.max(-2.5, Math.min(2.5, dx))
      const clampY = Math.max(-2, Math.min(2, dy))
      gsap.to(eyeL.current, { attr: { cx: 42 + clampX, cy: 61 + clampY }, duration: 0.2, ease: 'power2.out', overwrite: true })
      gsap.to(eyeR.current, { attr: { cx: 58 + clampX, cy: 61 + clampY }, duration: 0.2, ease: 'power2.out', overwrite: true })
    }
    window.addEventListener('mousemove', onMove, { passive: true })
    return () => window.removeEventListener('mousemove', onMove)
  }, [trackEyes, expression])

  // ─── Animate expression transition ───
  useEffect(() => {
    if (!mouthRef.current) return
    const mouth = MOUTHS[expression] || MOUTHS.happy
    const eye = EYE_SHAPES[expression] || EYE_SHAPES.happy
    const showBlush = expression === 'shy' || expression === 'excited'

    gsap.to(mouthRef.current, { attr: { d: mouth }, duration: 0.3, ease: 'power2.out' })
    if (eyeL.current) gsap.to(eyeL.current, { attr: { rx: eye.lRx, ry: eye.lRy }, duration: 0.25, ease: 'power2.out' })
    if (eyeR.current) gsap.to(eyeR.current, { attr: { rx: eye.rRx, ry: eye.rRy }, duration: 0.25, ease: 'power2.out' })
    if (blushRef.current) gsap.to(blushRef.current, { opacity: showBlush ? 0.35 : 0, duration: 0.3 })
  }, [expression])

  // ─── Hover / Click ───
  const onMascotClick = () => {
    if (!interactive || !bodyRef.current) return
    gsap.to(bodyRef.current, {
      scale: 1.15, rotation: 360, duration: 0.6, ease: 'back.out(1.5)',
      onComplete: () => gsap.set(bodyRef.current, { rotation: 0 }),
    })
    onTap?.()
  }
  const onEnter = () => {
    if (!interactive || !bodyRef.current) return
    gsap.to(bodyRef.current, { scale: 1.08, duration: 0.3, ease: 'power2.out' })
  }
  const onLeave = () => {
    if (!interactive || !bodyRef.current) return
    gsap.to(bodyRef.current, { scale: 1, duration: 0.4, ease: 'elastic.out(1,0.5)' })
  }

  const sleepBubbles = expression === 'sleep'

  return (
    <div
      ref={rootRef}
      style={{
        width: size, height: size,
        display: 'flex', alignItems: 'center', justifyContent: 'center',
        cursor: interactive ? 'pointer' : 'default',
        userSelect: 'none', position: 'relative',
      }}
      onClick={onMascotClick}
      onMouseEnter={onEnter}
      onMouseLeave={onLeave}
      data-mascot-root
    >
      <svg
        viewBox="0 0 100 100"
        style={{
          width: '100%', height: '100%',
          filter: `drop-shadow(0 0 12px ${s.glow})`,
          overflow: 'visible',
        }}
      >
        <defs>
          <radialGradient id={`mg-${skin}`} cx="50%" cy="50%" r="50%">
            <stop offset="0%" stopColor={s.accent} stopOpacity="0.6" />
            <stop offset="100%" stopColor={s.main} stopOpacity="0" />
          </radialGradient>
        </defs>

        <g ref={bodyRef}>
          {/* Main body */}
          <circle cx="50" cy="55" r="32" fill={s.main} stroke={s.sec} strokeWidth="2" style={{ opacity: s.opacity || 1 }} />
          <circle cx="50" cy="55" r="28" fill={`url(#mg-${skin})`} style={{ opacity: 0.8 }} />

          {/* Brain circuit lines */}
          <g style={{ opacity: 0.4 }} stroke={s.accent} fill="none" strokeWidth="1.5" strokeLinecap="round">
            <path d="M40 38 Q50 32 60 38" />
            <path d="M35 45 Q50 40 65 45" />
            <path d="M50 35 L50 45" strokeWidth="1" />
          </g>

          {/* Visor / face area */}
          <rect x="32" y="52" width="36" height="18" rx="9" fill="rgba(0,0,0,0.6)" />

          {/* Eyes */}
          <ellipse ref={eyeL} cx="42" cy="61" rx="3.5" ry="3.5" fill={s.accent} />
          <ellipse ref={eyeR} cx="58" cy="61" rx="3.5" ry="3.5" fill={s.accent} />

          {/* Blush circles (hidden by default) */}
          <g ref={blushRef} opacity="0">
            <circle cx="33" cy="66" r="4" fill="#FF6B9D" opacity="0.5" />
            <circle cx="67" cy="66" r="4" fill="#FF6B9D" opacity="0.5" />
          </g>

          {/* Mouth */}
          <path
            ref={mouthRef}
            d={MOUTHS[expression] || MOUTHS.happy}
            fill="none"
            stroke={s.accent}
            strokeWidth="1.5"
            strokeLinecap="round"
          />

          {/* Thrusters */}
          <g fill={s.main} style={{ opacity: s.opacity || 1 }}>
            <path d="M38 85 L42 95 L46 85" />
            <path d="M54 85 L58 95 L62 85" />
          </g>

          {/* Dynamic Hat */}
          <g ref={hatRef}>
            {hat === 'grad-cap' && (
              <g transform="translate(25,22) scale(0.8)">
                <path d="M0 15 L32 0 L64 15 L32 30 Z" fill="#2C3E50" stroke="#000" strokeWidth="0.5" />
                <rect x="15" y="15" width="34" height="10" fill="#2C3E50" />
                <rect x="60" y="15" width="2" height="15" fill="#F1C40F" />
              </g>
            )}
            {hat === 'gamer-headset' && (
              <g stroke={s.accent} strokeWidth="4" fill="none">
                <path d="M20 60 Q50 20 80 60" />
                <rect x="16" y="58" width="12" height="20" rx="4" fill="#2d3436" stroke="none" />
                <rect x="72" y="58" width="12" height="20" rx="4" fill="#2d3436" stroke="none" />
              </g>
            )}
            {hat === 'wizard-hat' && (
              <g transform="translate(15,-10) scale(1.1)">
                <path d="M10 45 Q35 45 60 45 L35 10 Z" fill="#6c5ce7" stroke="#4834d4" />
                <path d="M30 25 L40 25" stroke="#FDCB6E" strokeWidth="2" />
              </g>
            )}
            {hat === 'crown' && (
              <g transform="translate(25,18)">
                <path d="M0 15 L10 0 L25 12 L40 0 L50 15 L50 25 L0 25 Z" fill="#FFD700" stroke="#DAA520" />
                <circle cx="25" cy="18" r="3" fill="#FDCB6E" />
              </g>
            )}
            {hat === 'detective' && (
              <path d="M25 45 Q50 35 75 45 L75 52 Q50 52 25 52 Z M20 52 L80 52 L80 56 Q50 56 20 56 Z" fill="#8d6e63" />
            )}
            {hat === 'chef-hat' && (
              <g transform="translate(32,10)">
                <circle cx="10" cy="15" r="12" fill="#fff" stroke="#ddd" />
                <circle cx="25" cy="15" r="12" fill="#fff" stroke="#ddd" />
                <rect x="5" y="25" width="26" height="15" fill="#fff" stroke="#ddd" />
              </g>
            )}
          </g>

          {/* Sleep ZZZ */}
          {sleepBubbles && (
            <g>
              <text x="68" y="42" fill={s.accent} fontSize="8" fontWeight="700" opacity="0.5">
                <animate attributeName="opacity" values="0;0.7;0" dur="2.5s" repeatCount="indefinite" />
                <animate attributeName="y" values="42;35" dur="2.5s" repeatCount="indefinite" />
                z
              </text>
              <text x="74" y="36" fill={s.accent} fontSize="10" fontWeight="700" opacity="0.5">
                <animate attributeName="opacity" values="0;0.6;0" dur="3s" begin="0.5s" repeatCount="indefinite" />
                <animate attributeName="y" values="36;28" dur="3s" begin="0.5s" repeatCount="indefinite" />
                Z
              </text>
              <text x="78" y="28" fill={s.accent} fontSize="13" fontWeight="700" opacity="0.5">
                <animate attributeName="opacity" values="0;0.5;0" dur="3.5s" begin="1s" repeatCount="indefinite" />
                <animate attributeName="y" values="28;18" dur="3.5s" begin="1s" repeatCount="indefinite" />
                Z
              </text>
            </g>
          )}
        </g>
      </svg>
    </div>
  )
}

import { useMatch } from '../context/MatchContext.jsx'
import { useThemeColors } from '../hooks/useThemeColors.js'
import { useSound } from '../hooks/useSound.js'
import { useState, useEffect } from 'react'
import { auth } from '../firebase.js'

export default function MatchInviteToast() {
  const { incomingInvites, acceptMatch, declineMatch, setActiveMatch } = useMatch()
  const { play } = useSound()
  const tc = useThemeColors()

  const [activeInvite, setActiveInvite] = useState(null)
  const [isExiting, setIsExiting] = useState(false)
  const [processing, setProcessing] = useState(null) // 'accept' | 'ignore' | null

  useEffect(() => {
    if (incomingInvites.length > 0 && !activeInvite) {
      setActiveInvite(incomingInvites[0])
      setIsExiting(false)
      play('level_up')
    } else if (incomingInvites.length === 0 && activeInvite) {
      handleClose()
    }
  }, [incomingInvites, activeInvite, play])

  const handleClose = () => {
    setIsExiting(true)
    setTimeout(() => {
      setActiveInvite(null)
      setIsExiting(false)
    }, 400)
  }

  const handleAccept = async () => {
    if (!activeInvite || processing) return
    setProcessing('accept')
    play('level_up')
    const res = await acceptMatch(activeInvite.id)
    if (res.success) {
      // Manually set activeMatch so App.jsx can redirect immediately with gameId
      setActiveMatch({
        id: activeInvite.id,
        ...activeInvite,
        status: 'active',
        guestProfile: {
          displayName: auth.currentUser?.displayName || 'Pemain',
          photoURL: auth.currentUser?.photoURL || ''
        }
      })
      handleClose()
    }
    setProcessing(null)
  }

  const handleIgnore = async () => {
    if (!activeInvite || processing) return
    setProcessing('ignore')
    await declineMatch(activeInvite.id)
    handleClose()
    setProcessing(null)
  }

  if (!activeInvite) return null

  const dark = tc.dark
  const surface = tc.surface
  const textMain = tc.textMain
  const borderCol = tc.borderCol

  return (
    <>
      <style>{`
        .match-toast {
          position: fixed; top: 80px; left: 50%; transform: translateX(-50%);
          z-index: 1000; width: 90%; max-width: 360px;
          background: ${surface}; border: 2px solid #FDCB6E;
          border-radius: 20px; padding: 16px;
          box-shadow: 0 10px 40px rgba(0,0,0,0.2), 0 0 20px rgba(253,203,110,0.2);
          display: flex; align-items: center; gap: 16px;
          animation: toast-in 0.5s cubic-bezier(0.175, 0.885, 0.32, 1.275) both;
        }
        .match-toast.exit {
          animation: toast-out 0.4s cubic-bezier(0.6, -0.28, 0.735, 0.045) both;
        }
        @keyframes toast-in {
          from { opacity: 0; transform: translate(-50%, -30px) scale(0.9); }
          to { opacity: 1; transform: translate(-50%, 0) scale(1); }
        }
        @keyframes toast-out {
          from { opacity: 1; transform: translate(-50%, 0) scale(1); }
          to { opacity: 0; transform: translate(-50%, -30px) scale(0.9); }
        }
        .toast-icon {
          width: 48px; height: 48px; border-radius: 14px;
          background: linear-gradient(135deg, #FDCB6E, #F39C12);
          display: flex; align-items: center; justify-content: center;
          font-size: 24px; flex-shrink: 0;
          box-shadow: 0 4px 12px rgba(243,156,18,0.3);
        }
        .toast-btn-accept {
          background: #FDCB6E; color: #fff; border: none;
          padding: 8px 16px; border-radius: 10px; font-weight: 800;
          font-family: 'Fredoka One', cursive; cursor: pointer;
          font-size: 13px; transition: transform 0.1s;
        }
        .toast-btn-accept:active { transform: scale(0.95); }
        .toast-btn-ignore {
          background: none; border: none; color: ${tc.textMuted};
          font-size: 11px; font-weight: 700; cursor: pointer; padding: 4px;
        }
      `}</style>

      <div className={`match-toast ${isExiting ? 'exit' : ''}`}>
        <div className="toast-icon">⚔️</div>
        <div style={{ flex: 1 }}>
          <div style={{ color: textMain, fontSize: 14, fontWeight: 800, fontFamily: "'Fredoka One', cursive", marginBottom: 2 }}>
            TANTANGAN BARU!
          </div>
          <div style={{ color: tc.textMuted, fontSize: 11, fontWeight: 700, textTransform: 'uppercase' }}>
             {activeInvite.gameId === 'math-challenge' ? 'Math Challenge' : 'Reaction Test'}
          </div>
        </div>
        <div style={{ display: 'flex', flexDirection: 'column', gap: 4, alignItems: 'center' }}>
          <button className="toast-btn-accept" onClick={handleAccept} disabled={!!processing}>
            {processing === 'accept' ? '...' : 'TERIMA'}
          </button>
          <button className="toast-btn-ignore" onClick={handleIgnore} disabled={!!processing}>
            {processing === 'ignore' ? '...' : 'ABAIKAN'}
          </button>
        </div>
      </div>
    </>
  )
}

