]
// Drop rates (total weight = 200):
// Common: 50% | Uncommon: 28% | Rare: 18% | Epic: 3% | Legendary: 1%

const RARITY_COLORS = {
  common:    '#B0BEC5',
  uncommon:  '#66BB6A',
  rare:      '#42A5F5',
  epic:      '#AB47BC',
  legendary: '#FFD700',
}

const RARITY_LABELS = {
  common:    'Common',
  uncommon:  'Uncommon',
  rare:      'Rare',
  epic:      'Epic',
  legendary: 'Legendary',
}

const EXTRA_SPIN_COST = 150
const FREE_SPINS_PER_WEEK = 5   // 5 spin gratis per minggu, reset Senin 07:00 WIB
const PITY_THRESHOLD = 50
const DUPE_COIN_EPIC = 300
const DUPE_COIN_LEGENDARY = 800
const DUPE_COIN_SHOP = 50

// ─── Helpers ────────────────────────────────────────────────────────────────

// Kembalikan key unik per "pekan wheel" — pekan baru dimulai Senin 07:00 WIB
function getWeekKey() {
  const now  = new Date()
  const day  = now.getDay()   // 0=Min … 6=Sab
  const hour = now.getHours()

  // Hari ke belakang sejak Senin terakhir (0 kalau hari ini Senin)
  const daysBack = day === 0 ? 6 : day - 1
  const monday   = new Date(now)
  monday.setDate(now.getDate() - daysBack)

  // Senin sebelum jam 07:00 masih masuk pekan lalu
  if (daysBack === 0 && hour < 7) monday.setDate(monday.getDate() - 7)

  const yyyy = monday.getFullYear()
  const mm   = String(monday.getMonth() + 1).padStart(2, '0')
  const dd   = String(monday.getDate()).padStart(2, '0')
  return `week-${yyyy}-${mm}-${dd}`
}

// Ekspor: kapan reset berikutnya (Senin 07:00 waktu lokal)
export function getNextResetTime() {
  const now  = new Date()
  const day  = now.getDay()
  const hour = now.getHours()
  const next = new Date(now)

  if (day === 1 && hour < 7) {
    // Hari ini Senin sebelum 07:00 — reset hari ini jam 07:00
    next.setHours(7, 0, 0, 0)
  } else {
    // Senin depan jam 07:00
    const daysUntil = day === 0 ? 1 : (8 - day) % 7 || 7
    next.setDate(now.getDate() + daysUntil)
    next.setHours(7, 0, 0, 0)
  }
  next.setSeconds(0); next.setMilliseconds(0)
  return next
}

function loadWheelState() {
  try { return JSON.parse(localStorage.getItem(WHEEL_KEY)) || {} } catch { return {} }
}

function saveWheelState(state) {
  localStorage.setItem(WHEEL_KEY, JSON.stringify(state))
}

function getDefaultWheelState() {
  return {
    lastSpinDate: null,
    freeSpinsUsed: 0,
    pityCounter: 0,
    wonExclusives: [],
    spinHistory: [],
    totalSpins: 0,
  }
}

// Weighted random selection
function weightedRandom(pool) {
  const totalWeight = pool.reduce((sum, r) => sum + r.weight, 0)
  let rand = Math.random() * totalWeight
  for (const reward of pool) {
    rand -= reward.weight
    if (rand <= 0) return reward
  }
  return pool[pool.length - 1]
}

// ─── Provider ───────────────────────────────────────────────────────────────

export function LuckyWheelProvider({ children }) {
  const [state, setState] = useState(() => {
    const saved = loadWheelState()
    const def = getDefaultWheelState()
    // Reset free spins kalau masuk pekan baru (Senin 07:00)
    if (saved.lastSpinDate !== getWeekKey()) {
      return { ...def, ...saved, freeSpinsUsed: 0, lastSpinDate: getWeekKey() }
    }
    return { ...def, ...saved }
  })

  useEffect(() => {
    saveWheelState(state)
  }, [state])

  const hasFreeSpins       = state.freeSpinsUsed < FREE_SPINS_PER_WEEK
  const freeSpinsRemaining  = Math.max(0, FREE_SPINS_PER_WEEK - state.freeSpinsUsed)

  // Resolve what the player actually gets from a reward type
  const resolveReward = useCallback((rewardSlot, ownedExclusives) => {
    if (rewardSlot.type === 'coin') {
      return { type: 'coin', amount: rewardSlot.amount, label: rewardSlot.label, icon: rewardSlot.icon, rarity: rewardSlot.rarity }
    }
    if (rewardSlot.type === 'xp') {
      return { type: 'xp', amount: rewardSlot.amount, label: rewardSlot.label, icon: rewardSlot.icon, rarity: rewardSlot.rarity }
    }
    if (rewardSlot.type === 'exclusive') {
      const rarity = rewardSlot.rarity
      const weekGames = getCurrentWeekGames()
      // ONLY offer exclusives from this week's featured games — no fallback
      const available = WHEEL_EXCLUSIVES.filter(e =>
        weekGames.includes(e.game) && e.rarity === rarity && !ownedExclusives.includes(e.id)
      )
      if (available.length > 0) {
        const item = available[Math.floor(Math.random() * available.length)]
        return { type: 'exclusive', item, label: item.name, icon: item.icon, rarity: item.rarity, img: item.img, desc: item.desc }
      }
      // All owned — dupe conversion
      const dupeCoins = rarity === 'legendary' ? DUPE_COIN_LEGENDARY : DUPE_COIN_EPIC
      return { type: 'coin', amount: dupeCoins, label: `${dupeCoins} Coin (dupe)`, icon: '🪙', rarity, isDupe: true }
    }
    // Shop item — placeholder coin reward (player already has access to shop)
    return { type: 'coin', amount: DUPE_COIN_SHOP, label: '50 Coin (Shop)', icon: '🎁', rarity: 'rare' }
  }, [])

  const spin = useCallback((isFreeSpin) => {
    const today = getWeekKey()

    // Pity system: guarantee epic+ after threshold
    let pool = [...REWARD_POOL]
    if (state.pityCounter >= PITY_THRESHOLD) {
      pool = pool.filter(r => r.rarity === 'epic' || r.rarity === 'legendary')
    }

    const rewardSlot = weightedRandom(pool)
    const resolved = resolveReward(rewardSlot, state.wonExclusives)

    // Update state
    setState(prev => {
      const isEpicPlus = resolved.rarity === 'epic' || resolved.rarity === 'legendary'
      const newPity = isEpicPlus ? 0 : prev.pityCounter + 1
      const newWon = resolved.type === 'exclusive' && resolved.item
        ? [...prev.wonExclusives, resolved.item.id]
        : prev.wonExclusives

      const historyEntry = {
        date: new Date().toISOString(),
        label: resolved.label,
        rarity: resolved.rarity,
        icon: resolved.icon,
      }

      return {
        ...prev,
        lastSpinDate: today,
        freeSpinsUsed: isFreeSpin ? prev.freeSpinsUsed + 1 : prev.freeSpinsUsed,
        pityCounter: newPity,
        wonExclusives: newWon,
        spinHistory: [historyEntry, ...prev.spinHistory].slice(0, 30),
        totalSpins: prev.totalSpins + 1,
      }
    })

    return resolved
  }, [state, resolveReward])

  const getWheelSlots = useCallback(() => {
    // Return 8 slots for the wheel visual, showing this week's exclusive items
    const weekGames = getCurrentWeekGames()
    return REWARD_POOL.map(r => {
      const slot = {
        id: r.id,
        label: r.label,
        icon: r.icon,
        rarity: r.rarity,
        color: RARITY_COLORS[r.rarity],
        img: null,
      }
      // For exclusive slots, show items from this week's featured games (stable pick)
      if (r.type === 'exclusive') {
        const weekItems = WHEEL_EXCLUSIVES.filter(e => weekGames.includes(e.game) && e.rarity === r.rarity)
        const allItems = weekItems.length > 0 ? weekItems : WHEEL_EXCLUSIVES.filter(e => e.rarity === r.rarity)
        if (allItems.length > 0) {
          // Stable pick: use week number so it only changes on Monday, not during spin
          const pick = allItems[getWeekOfYear() % allItems.length]
          slot.img = pick.img
          slot.label = pick.name
          slot.icon = pick.icon
        }
      }
      return slot
    })
  }, [])

  return (
    <LuckyWheelContext.Provider value={{
      hasFreeSpins,
      freeSpinsUsed: state.freeSpinsUsed,
      freeSpinsRemaining,
      freeSpinsPerWeek: FREE_SPINS_PER_WEEK,
      pityCounter: state.pityCounter,
      wonExclusives: state.wonExclusives,
      spinHistory: state.spinHistory,
      totalSpins: state.totalSpins,
      extraSpinCost: EXTRA_SPIN_COST,
      spin,
      getWheelSlots,
      getCurrentWeekGames,
      getWeeklyExclusives,
      WHEEL_EXCLUSIVES,
      RARITY_COLORS,
      RARITY_LABELS,
      DUPE_COIN_EPIC,
      DUPE_COIN_LEGENDARY,
    }}>
      {children}
    </LuckyWheelContext.Provider>
  )
}

export function useLuckyWheel() { return useContext(LuckyWheelContext) }

import { createContext, useContext, useState, useCallback, useRef } from 'react'
import { useSettings } from '../context/SettingsContext.jsx'

const NotifContext = createContext(null)

let globalId = 0

export function NotifProvider({ children }) {
  const [toasts, setToasts] = useState([])

  const addToast = useCallback((toast) => {
    const id = ++globalId
    const item = {
      id,
      type: toast.type || 'info', // info, success, error, warning, reward, levelup
      message: toast.message || '',
      emoji: toast.emoji || '',
      duration: toast.duration || 3000,
      amount: toast.amount, // for coin/xp rewards
    }
    setToasts(prev => [...prev, item])
    setTimeout(() => {
      setToasts(prev => prev.filter(t => t.id !== id))
    }, item.duration)
    return id
  }, [])

  const success = useCallback((msg, emoji = '✅') =>
    addToast({ type: 'success', message: msg, emoji }), [addToast])

  const error = useCallback((msg, emoji = '❌') =>
    addToast({ type: 'error', message: msg, emoji }), [addToast])

  const reward = useCallback((amount, msg, emoji = '🪙') =>
    addToast({ type: 'reward', message: msg, emoji, amount }), [addToast])

  const levelUp = useCallback((level, title) =>
    addToast({ type: 'levelup', message: title, emoji: '🎉', amount: level, duration: 4000 }), [addToast])

  const info = useCallback((msg, emoji = 'ℹ️') =>
    addToast({ type: 'info', message: msg, emoji }), [addToast])

  return (
    <NotifContext.Provider value={{ toasts, addToast, success, error, reward, levelUp, info }}>
      {children}
      <ToastContainer toasts={toasts} />
    </NotifContext.Provider>
  )
}

export function useNotif() {
  return useContext(NotifContext)
}

// ─── Toast Container ────────────────────────────────────────────────────────
function ToastContainer({ toasts }) {
  const { darkMode } = useSettings()
  const dark = darkMode

  return (
    <div style={{
      position: 'fixed', top: 76, left: '50%', transform: 'translateX(-50%)',
      zIndex: 300, display: 'flex', flexDirection: 'column', gap: 8,
      pointerEvents: 'none', width: '90%', maxWidth: 380,
    }}>
      {toasts.map((t, i) => (
        <Toast key={t.id} toast={t} dark={dark} index={i} />
      ))}
    </div>
  )
}

// ─── Individual Toast ───────────────────────────────────────────────────────
function Toast({ toast, dark, index }) {
  const COLORS = {
    info:    { bg: dark ? 'rgba(162,155,254,0.95)' : '#A29BFE', accent: '#A29BFE' },
    success: { bg: dark ? 'rgba(78,205,196,0.95)' : '#4ECDC4', accent: '#4ECDC4' },
    error:   { bg: dark ? 'rgba(255,107,107,0.95)' : '#FF6B6B', accent: '#FF6B6B' },
    warning: { bg: dark ? 'rgba(253,203,110,0.95)' : '#FDCB6E', accent: '#FDCB6E' },
    reward:  { bg: dark ? 'rgba(249,168,37,0.95)' : '#F9A825', accent: '#F9A825' },
    levelup: { bg: dark ? 'linear-gradient(135deg,rgba(162,155,254,0.95),rgba(253,121,168,0.95))' : 'linear-gradient(135deg,#A29BFE,#FD79A8)', accent: '#A29BFE' },
  }

  const c = COLORS[toast.type] || COLORS.info
  const isGradient = c.bg.includes('gradient')

  return (
    <>
      <style>{`
        @keyframes toastSlideIn { 
          from { opacity:0; transform:translateY(-16px) scale(0.92); } 
          to { opacity:1; transform:translateY(0) scale(1); } 
        }
        @keyframes toastShine {
          0% { left: -100%; }
          100% { left: 200%; }
        }
      `}</style>
      <div style={{
        background: c.bg,
        color: '#fff',
        borderRadius: 16,
        padding: toast.type === 'levelup' ? '14px 20px' : '10px 20px',
        display: 'flex', alignItems: 'center', gap: 10,
        boxShadow: `0 8px 28px ${c.accent}44, 0 2px 8px rgba(0,0,0,0.15)`,
        animation: `toastSlideIn 0.3s ${index * 0.05}s cubic-bezier(0.34,1.56,0.64,1) both`,
        pointerEvents: 'auto',
        position: 'relative', overflow: 'hidden',
        fontFamily: "'Nunito',sans-serif",
      }}>
        {/* Shine effect */}
        <div style={{
          position: 'absolute', top: 0, width: '30%', height: '100%',
          background: 'linear-gradient(90deg, transparent, rgba(255,255,255,0.2), transparent)',
          transform: 'skewX(-20deg)',
          animation: 'toastShine 1s 0.3s ease forwards',
          pointerEvents: 'none',
          left: '-100%',
        }} />

        <span style={{ fontSize: toast.type === 'levelup' ? 28 : 20, flexShrink: 0 }}>{toast.emoji}</span>

        <div style={{ flex: 1, minWidth: 0 }}>
          {toast.type === 'levelup' ? (
            <>
              <div style={{ fontFamily: "'Fredoka One',cursive", fontSize: 16, letterSpacing: 0.5 }}>
                Level Up! Lv.{toast.amount}
              </div>
              <div style={{ fontSize: 12, opacity: 0.85 }}>{toast.message}</div>
            </>
          ) : toast.type === 'reward' ? (
            <div style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
              <span style={{ fontFamily: "'Fredoka One',cursive", fontSize: 16 }}>+{toast.amount}</span>
              {toast.message && <span style={{ fontSize: 13, opacity: 0.9 }}>• {toast.message}</span>}
            </div>
          ) : (
            <span style={{ fontFamily: "'Fredoka One',cursive", fontSize: 14, letterSpacing: 0.3 }}>
              {toast.message}
            </span>
          )}
        </div>
      </div>
    </>
  )
}

