// ─── Default state ───────────────────────────────────────────────────────────
function getDefaultProgress() {
  return {
    totalXP: 0,
    totalGamesPlayed: 0,
    uniqueGamesPlayed: 0,
    gamesPlayedSet: [],    // list of game IDs played
    hardGamesWon: 0,
    currentStreak: 0,
    maxStreak: 0,
    lastPlayDate: null,
    threeStarCount: 0,
    fastestGame: 0,        // seconds, 0 = not set
    gameWins: {},           // { gameId: count }
    gameBests: {},          // { gameId: bestScore }
    totalPlayTime: 0,       // seconds
    unlockedAchievements: [],
    newAchievements: [],    // achievements just unlocked (for notification)
    selectedTitle: null,    // User-selected custom title
    unlockedTitles: [],      // List of unlocked titles (strings)
    seasonXP: 0,             // Battle Pass XP
    claimedBPTiers: [],      // List of claimed tier numbers
    claimedLevelRewards: [], // List of claimed level reward numbers
    selectedBorder: null,    // Custom border ID
    unlockedBorders: [],     // List of unlocked border IDs
    selectedAvatar: null,    // Custom avatar ID (from AVATAR_CATALOG)
    unlockedAvatars: ['raccoon','fox','kiddo','lynx','wolf'], // 5 free avatars unlocked by default
    selectedMascotSkin: 'neon-blue',
    selectedMascotHat: null,
    unlockedMascotSkins: ['neon-blue'],
    unlockedMascotHats: [],
    mascotName: 'Brainy',
  }
}

// ─── Provider ────────────────────────────────────────────────────────────────
export function ProgressProvider({ children }) {
  const { currentMode } = useLimitedMode()
  const { earnCoins } = useCoins()
  const [progress, setProgress] = useState(() => {
    const saved = getJSON(StorageKeys.XP)
    return saved ? { ...getDefaultProgress(), ...saved } : getDefaultProgress()
  })

  // Save on change
  useEffect(() => {
    setJSON(StorageKeys.XP, progress)
  }, [progress])

  // Reload from localStorage when cloud sync completes
  useEffect(() => {
    const handler = () => {
      const saved = getJSON(StorageKeys.XP)
      if (saved) setProgress(p => ({ ...getDefaultProgress(), ...saved }))
    }
    window.addEventListener('bp-cloud-sync', handler)
    return () => window.removeEventListener('bp-cloud-sync', handler)
  }, [])

  // One-time migration to fix the bug where chests weren't saved
  useEffect(() => {
    if (!localStorage.getItem('bp-fixed-trophy-bug')) {
      setProgress(p => ({ ...p, claimedLevelRewards: [] }))
      localStorage.setItem('bp-fixed-trophy-bug', 'true')
    }
  }, [])

  // Update streak on mount
  useEffect(() => {
    setProgress(p => {
      const today = new Date().toDateString()
      const yesterday = new Date(Date.now() - 86400000).toDateString()

      if (p.lastPlayDate === today) return p // already counted today

      let newStreak = p.currentStreak
      if (p.lastPlayDate === yesterday) {
        newStreak = p.currentStreak + 1
      } else if (p.lastPlayDate !== today) {
        newStreak = 1
      }

      return {
        ...p,
        currentStreak: newStreak,
        maxStreak: Math.max(p.maxStreak, newStreak),
        lastPlayDate: today,
      }
    })
  }, [])

  // Report a game result
  const reportGameResult = useCallback(({ gameId, difficultyId, won, score, stars, timeSec }) => {
    // Dispatch event for leaderboard auto-submission
    try {
      window.dispatchEvent(new CustomEvent('bp-game-result', {
        detail: { gameId, difficultyId, won, score, stars, timeSec }
      }))
    } catch(e) {}

    setProgress(p => {
      const next = { ...p }
      const oldLevel = getLevel(p.totalXP || 0)

      // XP calculation with streak combo multiplier
      let xpGain = 20 // base for playing
      if (won) xpGain += 30
      if (score) xpGain += Math.min(Math.floor(score / 10), 50) // cap at 50 bonus
      if (stars === 3) xpGain += 25
      if (difficultyId === 'hard') xpGain += 15
      if (difficultyId === 'medium') xpGain += 5

      // Streak combo multiplier
      const streak = next.currentStreak || 0
      const comboMultiplier = streak >= 14 ? 2.0 : streak >= 7 ? 1.5 : streak >= 3 ? 1.2 : 1.0
      xpGain = Math.round(xpGain * comboMultiplier)

      // Limited Mode Event Multiplier
      if (currentMode) {
        if (currentMode.id === 'speed' && difficultyId === 'easy') {
          xpGain = Math.round(xpGain * currentMode.xpMultiplier)
        } else if (currentMode.id === 'survival' && difficultyId === 'hard') {
          xpGain = Math.round(xpGain * currentMode.xpMultiplier)
        } else if (currentMode.id === 'no_mistakes' && stars === 3) {
          xpGain = Math.round(xpGain * currentMode.xpMultiplier)
        }
      }

      next.totalXP = (next.totalXP || 0) + xpGain

      // Level Up Detection
      const newLevel = getLevel(next.totalXP)
      if (newLevel > oldLevel) {
        next.levelUpData = { oldLevel, newLevel }
      }

      next.totalGamesPlayed = (next.totalGamesPlayed || 0) + 1

      // Track date
      next.lastPlayDate = new Date().toDateString()

      // Unique games
      const gamesSet = new Set(next.gamesPlayedSet || [])
      gamesSet.add(gameId)
      next.gamesPlayedSet = [...gamesSet]
      next.uniqueGamesPlayed = gamesSet.size

      // Hard mode wins
      if (won && difficultyId === 'hard') {
        next.hardGamesWon = (next.hardGamesWon || 0) + 1
      }

      // 3-star count
      if (stars === 3) {
        next.threeStarCount = (next.threeStarCount || 0) + 1
      }

      // Fastest game
      if (won && timeSec && timeSec > 0) {
        if (!next.fastestGame || timeSec < next.fastestGame) {
          next.fastestGame = timeSec
        }
      }

      // Per-game wins
      if (won) {
        next.gameWins = { ...next.gameWins }
        next.gameWins[gameId] = (next.gameWins[gameId] || 0) + 1
      }

      // Per-game best scores
      if (score && score > 0) {
        next.gameBests = { ...next.gameBests }
        if (!next.gameBests[gameId] || score > next.gameBests[gameId]) {
          next.gameBests[gameId] = score
        }
      }

      // Play time
      if (timeSec) {
        next.totalPlayTime = (next.totalPlayTime || 0) + timeSec
      }

      // Check achievements
      const alreadyUnlocked = new Set(next.unlockedAchievements || [])
      const newlyUnlocked = []
      for (const ach of ACHIEVEMENTS) {
        if (alreadyUnlocked.has(ach.id)) continue
        if (ach.check(next)) {
          alreadyUnlocked.add(ach.id)
          newlyUnlocked.push(ach.id)
        }
      }
      next.unlockedAchievements = [...alreadyUnlocked]
      next.newAchievements = newlyUnlocked

      // Grant rewards for new achievements
      if (newlyUnlocked.length > 0) {
        newlyUnlocked.forEach(achId => {
          const ach = ACHIEVEMENTS.find(a => a.id === achId)
          if (ach && ach.reward) {
            // Reward Coins
            if (ach.reward.coins) {
              earnCoins(ach.reward.coins, `Achievement: ${ach.title}`)
            }
            // Reward Title
            if (ach.reward.title) {
              const currentTitles = new Set(next.unlockedTitles || [])
              currentTitles.add(ach.reward.title)
              next.unlockedTitles = [...currentTitles]
            }
          }
        })
      }

      // Automatically unlock Level Titles
      const allLevelTitles = LEVEL_TITLES.slice(0, newLevel + 1)
      const currentTitlesCount = (next.unlockedTitles || []).length
      const updatedTitlesSet = new Set(next.unlockedTitles || [])
      allLevelTitles.forEach(t => updatedTitlesSet.add(t))
      if (updatedTitlesSet.size > currentTitlesCount) {
        next.unlockedTitles = [...updatedTitlesSet]
      }

      next.seasonXP = (next.seasonXP || 0) + xpGain

      return next
    })
  }, [currentMode])

  // Battle Pass & Border Management
  const claimBPTier = useCallback((tier) => {
    const tierData = BP_REWARDS.find(r => r.tier === tier)
    if (!tierData) return { success: false, reason: 'Tier tidak valid' }

    setProgress(p => {
      if (p.claimedBPTiers?.includes(tier)) return p
      if (p.seasonXP < tierData.xp) return p

      const next = { ...p, claimedBPTiers: [...(p.claimedBPTiers || []), tier] }
      const { reward } = tierData

      const grantReward = (rew) => {
        if (rew.type === 'coins') {
          earnCoins(rew.amount, `Battle Pass: ${tierData.label || rew.label}`)
        } else if (rew.type === 'title') {
          const titles = new Set(next.unlockedTitles)
          titles.add(rew.value)
          next.unlockedTitles = [...titles]
        } else if (rew.type === 'border') {
          const borders = new Set(next.unlockedBorders)
          borders.add(rew.value)
          next.unlockedBorders = [...borders]
        } else if (rew.type === 'ship') {
          window.dispatchEvent(new CustomEvent('bp-wheel-unlock', {
            detail: { item: { type: 'ships', id: rew.value } }
          }))
        } else if (rew.type === 'dash-skin') {
          window.dispatchEvent(new CustomEvent('bp-wheel-unlock', {
            detail: { item: { type: 'dash-themes', id: rew.value } }
          }))
        }
      }

      if (reward.type === 'multi') {
        reward.list.forEach(grantReward)
      } else {
        grantReward(reward)
      }

      return next
    })
    return { success: true }
  }, [])

  // ─── Level Road Management ─────────────────────────────────────────────────
  const claimLevelReward = useCallback((level) => {
    const myLevel = getLevel(progress.totalXP || 0)
    if (level > myLevel) return { success: false, reason: 'Level belum dicapai' }
    if (progress.claimedLevelRewards?.includes(level)) return { success: false, reason: 'Sudah diklaim' }

    const reward = getLevelRoadReward(level)

    // Helper to perform side effects cleanly OUTSIDE setState
    const dispatchRewardSideEffects = (rew) => {
      if (rew.type === 'coins') {
        earnCoins(rew.amount, `Trophy Road Lvl ${level}`)
      } else if (rew.type === 'ship') {
        window.dispatchEvent(new CustomEvent('bp-wheel-unlock', {
          detail: { item: { type: 'ships', id: rew.id || rew.value } }
        }))
      } else if (rew.type === 'dash-skin') {
        window.dispatchEvent(new CustomEvent('bp-wheel-unlock', {
          detail: { item: { type: 'dash-themes', id: rew.id || rew.value } }
        }))
      } else if (rew.type === 'chest') {
        window.dispatchEvent(new CustomEvent('bp-add-chest', {
          detail: { chestId: rew.id, amount: rew.amount }
        }))
      }
    }

    // Process side effects explicitly once
    if (reward.type === 'multi') {
      reward.list.forEach(dispatchRewardSideEffects)
    } else {
      dispatchRewardSideEffects(reward)
    }

    // Now update state purely
    setProgress(p => {
      if (p.claimedLevelRewards?.includes(level)) return p

      const next = { ...p, claimedLevelRewards: [...(p.claimedLevelRewards || []), level] }

      const grantStateReward = (rew) => {
        if (rew.type === 'title') {
          const titles = new Set(next.unlockedTitles || [])
          titles.add(rew.value)
          next.unlockedTitles = [...titles]
        } else if (rew.type === 'border') {
          const borders = new Set(next.unlockedBorders || [])
          borders.add(rew.id || rew.value)
          next.unlockedBorders = [...borders]
        }
      }

      if (reward.type === 'multi') {
        reward.list.forEach(grantStateReward)
      } else {
        grantStateReward(reward)
      }

      return next
    })
    return { success: true }
  }, [progress])

  const setSelectedBorder = useCallback((borderId) => {
    setProgress(p => ({ ...p, selectedBorder: borderId }))
  }, [])

  const unlockBorder = useCallback((id) => {
    setProgress(p => {
      const set = new Set(p.unlockedBorders || [])
      if (set.has(id)) return p
      set.add(id)
      return { ...p, unlockedBorders: [...set] }
    })
  }, [])

  // Avatar management
  const setSelectedAvatar = useCallback((avatarId) => {
    setProgress(p => ({ ...p, selectedAvatar: avatarId }))
  }, [])

  const unlockAvatar = useCallback((id) => {
    setProgress(p => {
      const set = new Set(p.unlockedAvatars || ['raccoon','fox','kiddo','lynx','wolf'])
      if (set.has(id)) return p
      set.add(id)
      return { ...p, unlockedAvatars: [...set] }
    })
  }, [])

  // Title management
  const setSelectedTitle = useCallback((title) => {
    setProgress(p => ({ ...p, selectedTitle: title }))
  }, [])

  const unlockTitle = useCallback((title) => {
    setProgress(p => {
      const set = new Set(p.unlockedTitles || [])
      if (set.has(title)) return p
      set.add(title)
      return { ...p, unlockedTitles: [...set] }
    })
  }, [])

  // Mascot management
  const setSelectedMascotSkin = useCallback((skinId) => {
    setProgress(p => ({ ...p, selectedMascotSkin: skinId }))
  }, [])

  const unlockMascotSkin = useCallback((id) => {
    setProgress(p => {
      const set = new Set(p.unlockedMascotSkins || ['neon-blue'])
      if (set.has(id)) return p
      set.add(id)
      return { ...p, unlockedMascotSkins: [...set] }
    })
  }, [])

  const setSelectedMascotHat = useCallback((hatId) => {
    setProgress(p => ({ ...p, selectedMascotHat: hatId }))
  }, [])

  const unlockMascotHat = useCallback((id) => {
    setProgress(p => {
      const set = new Set(p.unlockedMascotHats || [])
      if (set.has(id)) return p
      set.add(id)
      return { ...p, unlockedMascotHats: [...set] }
    })
  }, [])

  const setMascotName = useCallback((name) => {
    setProgress(p => ({ ...p, mascotName: name }))
  }, [])

  const clearNewAchievements = useCallback(() => {
    setProgress(p => ({ ...p, newAchievements: [] }))
  }, [])

  const clearLevelUp = useCallback(() => {
    setProgress(p => ({ ...p, levelUpData: null }))
  }, [])

  return (
    <ProgressContext.Provider value={{ 
      progress, reportGameResult, 
      clearNewAchievements, clearLevelUp, 
      setSelectedTitle, unlockTitle,
      setSelectedAvatar, unlockAvatar,
      claimBPTier, claimLevelReward, setSelectedBorder, selectBorder: setSelectedBorder, unlockBorder,
      setSelectedMascotSkin, unlockMascotSkin, setSelectedMascotHat, unlockMascotHat, setMascotName,
      selectedMascotSkin: progress.selectedMascotSkin || 'neon-blue',
      unlockedMascotSkins: progress.unlockedMascotSkins || ['neon-blue'],
      selectedMascotHat: progress.selectedMascotHat || null,
      unlockedMascotHats: progress.unlockedMascotHats || [],
      mascotName: progress.mascotName || 'Brainy',
      getLevelInfo: () => getLevelInfo(progress.totalXP || 0),
      getTitleRarity: (title) => getTitleRarity(title),
      getSeasonInfo: () => {
        const curXP = progress.seasonXP || 0
        let currentTier = 0
        let xpInTier = curXP
        let xpNeededForNext = BP_REWARDS[0].xp

        for (let i = 0; i < BP_REWARDS.length; i++) {
          const t = BP_REWARDS[i]
          if (curXP >= t.xp) {
            currentTier = t.tier
            if (BP_REWARDS[i + 1]) {
              xpInTier = curXP - t.xp
              xpNeededForNext = BP_REWARDS[i + 1].xp - t.xp
            } else {
              xpInTier = 1; xpNeededForNext = 1 // Maxed
            }
          } else {
            if (i === 0) {
              xpInTier = curXP
              xpNeededForNext = t.xp
            }
            break
          }
        }

        const hasRewardToClaim = BP_REWARDS.some(r => curXP >= r.xp && !progress.claimedBPTiers?.includes(r.tier))
        const maxXP = BP_REWARDS[BP_REWARDS.length - 1].xp

        return { 
          currentTier: currentTier || 0, 
          xpInTier: xpInTier || 0, 
          xpNeededForNext: xpNeededForNext || 1, 
          progress: Math.min(curXP / maxXP, 1) || 0,
          hasRewardToClaim: !!hasRewardToClaim
        }
      }
    }}>
      {children}
    </ProgressContext.Provider>
  )
}

export function useProgress() {
  return useContext(ProgressContext)
}

import { createContext, useContext, useState, useEffect, useCallback, useRef } from 'react'
import { auth, getDb } from '../firebase.js'

const SocialContext = createContext(null)

// Lazy-loaded Firestore helpers
let _firestoreMod = null
async function getFirestoreHelpers() {
  if (!_firestoreMod) {
    _firestoreMod = await import('firebase/firestore')
  }
  return _firestoreMod
}

export function SocialProvider({ children }) {
  const [activities, setActivities] = useState([])
  const [loadingActivities, setLoadingActivities] = useState(false)
  const unsubRef = useRef(null)

  // ─── Profile Interaction ───────────────────────────────────────────────────

  const getProfile = useCallback(async (uid) => {
    if (!uid) return null
    try {
      const db = await getDb()
      const { doc, getDoc } = await getFirestoreHelpers()

      const docRef = doc(db, 'users', uid)
      const snap = await getDoc(docRef)

      if (snap.exists()) {
        return { uid, ...snap.data() }
      }
      return null
    } catch (err) {
      console.error('[Social] ❌ getProfile failed:', err.message)
      return null
    }
  }, [])

  // Push an activity to the cloud
  const logActivity = useCallback(async ({ type, userName, details, icon }) => {
    const user = auth.currentUser
    if (!user && !localStorage.getItem('bp_is_guest')) return // Don't log if completely anonymous

    try {
      const db = await getDb()
      const { collection, addDoc, serverTimestamp } = await getFirestoreHelpers()

      await addDoc(collection(db, 'activity'), {
        type,   // 'level_up', 'high_score', 'achievement', 'chest_open'
        userId: user ? user.uid : 'guest',
        userName: userName || 'Pemain',
        details: details || '',
        icon: icon || '⭐',
        timestamp: serverTimestamp()
      })
    } catch (err) {
      console.error('[Social] ❌ logActivity failed:', err.message)
    }
  }, [])

  // ─── Activity Feed ─────────────────────────────────────────────────────────

  // Real-time listener for global activities
  useEffect(() => {
    let mounted = true
    const startListener = async () => {
      try {
        const db = await getDb()
        const { collection, query, orderBy, limit, onSnapshot } = await getFirestoreHelpers()

        const q = query(
          collection(db, 'activity'),
          orderBy('timestamp', 'desc'),
          limit(30)
        )

        unsubRef.current = onSnapshot(q, (snap) => {
          if (!mounted) return
          const docs = snap.docs.map(doc => ({ id: doc.id, ...doc.data() }))
          setActivities(docs)
        }, (err) => {
          // Handle initial empty collection or permission errors (silently)
          if (err.code === 'permission-denied') {
            console.warn('[Social] ❌ Permission denied on activity feed.')
          }
        })
      } catch (err) {
        console.error('[Social] Error starting listener:', err)
      }
    }

    startListener()
    return () => {
      mounted = false
      if (unsubRef.current) unsubRef.current()
    }
  }, [])

  // Listen for global log-activity events
  useEffect(() => {
    const handler = (e) => {
      const { type, userName, details, icon } = e.detail || {}
      if (type) {
        logActivity({ type, userName, details, icon })
      }
    }
    window.addEventListener('bp-log-activity', handler)
    return () => window.removeEventListener('bp-log-activity', handler)
  }, [logActivity])

  return (
    <SocialContext.Provider value={{
      activities,
      logActivity,
      getProfile,
      loadingActivities
    }}>
      {children}
    </SocialContext.Provider>
  )
}

export function useSocial() { return useContext(SocialContext) }

// useMusic.js — Procedural lo-fi chiptune BGM menggunakan Web Audio API
import { useRef, useEffect } from 'react'

// ─── Notes (Hz) ──────────────────────────────────────────────────────────────
const N = {
  C3:130.81, D3:146.83, E3:164.81, F3:174.61, G3:196.00, A3:220.00, B3:246.94,
  C4:261.63, D4:293.66, E4:329.63, F4:349.23, G4:392.00, A4:440.00, B4:493.88,
  C5:523.25, D5:587.33, E5:659.25, F5:698.46, G5:783.99, A5:880.00,
}

// ─── Themes Configuration ───────────────────────────────────────────────────
const THEMES = {
  ambient: {
    bpm: 94,
    chords: [
      { bass: N.C3, pads: [N.C4, N.E4, N.G4] },
      { bass: N.G3, pads: [N.G4, N.B4, N.D5] },
      { bass: N.A3, pads: [N.A4, N.C5, N.E5] },
      { bass: N.F3, pads: [N.F4, N.A4, N.C5] },
    ],
    melodies: [
      [N.E5,null,N.G5,null, N.A5,N.G5,N.E5,null],
      [N.G5,N.E5,null,N.D5, N.C5,null,N.E5,null],
    ],
    padType: 'sine',
    leadType: 'square'
  },
  intense: {
    bpm: 144,
    chords: [
      { bass: N.A3, pads: [N.A4, N.C5, N.E5] },
      { bass: N.F3, pads: [N.F4, N.A4, N.C5] },
      { bass: N.D3, pads: [N.D4, N.F4, N.A4] },
      { bass: N.E3, pads: [N.E4, N.G4, N.B4] },
    ],
    melodies: [
      [N.A5,N.E5,N.A5,N.E5, N.F5,N.D5,N.F5,N.D5],
      [N.A5,null,N.C5,null, N.B4,null,N.G4,null],
    ],
    padType: 'sawtooth',
    leadType: 'sawtooth'
  }
}

const ARP_SEQ = [0,1,2,1, 2,1,0,1]

class BGMEngine {
  constructor() {
    this.ctx = null
    this.master = null
    this.playing = false
    this.timer = null
    this.beat = 0
    this.nextTime = 0
    this.loopN = 0
    this.themeName = 'ambient'
    this.bpm = 94
  }

  init() {
    if (this.ctx) return true
    try {
      this.ctx = new (window.AudioContext || window.webkitAudioContext)()
      this.master = this.ctx.createGain()
      this.master.gain.value = 0
      this.master.connect(this.ctx.destination)
      return true
    } catch(e) {
      return false
    }
  }

  setTheme(name) {
    if (!THEMES[name] || this.themeName === name) return
    this.themeName = name
    this.bpm = THEMES[name].bpm
    // Reset loop counting if needed for abrupt changes
  }

  tone(freq, time, dur, type, vol, pan = 0) {
    if (!this.ctx || !this.playing) return
    const o = this.ctx.createOscillator()
    const g = this.ctx.createGain()
    const p = this.ctx.createStereoPanner()

    o.type = type
    o.frequency.setValueAtTime(freq, time)
    o.detune.setValueAtTime(Math.random() * 8 - 4, time)

    g.gain.setValueAtTime(0, time)
    g.gain.linearRampToValueAtTime(vol, time + 0.015)
    g.gain.setValueAtTime(vol * 0.8, time + dur * 0.7)
    g.gain.exponentialRampToValueAtTime(0.001, time + dur)

    p.pan.setValueAtTime(pan, time)

    o.connect(g)
    g.connect(p)
    p.connect(this.master)
    o.start(time)
    o.stop(time + dur + 0.05)
  }

  hihat(time, vol) {
    if (!this.ctx || !this.playing) return
    for (let i = 0; i < 2; i++) {
      const o = this.ctx.createOscillator()
      const g = this.ctx.createGain()
      o.type = 'square'
      o.frequency.setValueAtTime(6000 + Math.random() * 6000, time)
      g.gain.setValueAtTime(0, time)
      g.gain.linearRampToValueAtTime(vol, time + 0.002)
      g.gain.exponentialRampToValueAtTime(0.001, time + 0.04)
      o.connect(g)
      g.connect(this.master)
      o.start(time)
      o.stop(time + 0.05)
    }
  }

  kick(time) {
    if (!this.ctx || !this.playing) return
    const o = this.ctx.createOscillator()
    const g = this.ctx.createGain()
    o.type = 'sine'
    o.frequency.setValueAtTime(180, time)
    o.frequency.exponentialRampToValueAtTime(32, time + 0.15)
    g.gain.setValueAtTime(0.45, time)
    g.gain.exponentialRampToValueAtTime(0.001, time + 0.2)
    o.connect(g)
    g.connect(this.master)
    o.start(time)
    o.stop(time + 0.25)
  }

  scheduleBeat(t) {
    const theme = THEMES[this.themeName]
    const bd = 60 / this.bpm
    const ci = Math.floor((this.beat % 8) / 2)
    const ch = theme.chords[ci]
    const sub = this.beat % 2

    // ── BASS ──
    if (sub === 0) {
      this.tone(ch.bass, t, bd * 1.6, 'triangle', 0.25, 0)
      this.tone(ch.bass / 2, t, bd * 1.6, 'sine', 0.18, 0)
    }

    // ── PAD ──
    if (sub === 0) {
      ch.pads.forEach((note, i) => {
        this.tone(note, t, bd * 1.9, theme.padType, 0.06, (i - 1) * 0.4)
      })
    }

    // ── ARPEGGIO ──
    for (let i = 0; i < 4; i++) {
      const aIdx = ARP_SEQ[(sub * 4 + i) % ARP_SEQ.length]
      const note = ch.pads[aIdx]
      if (note) this.tone(note, t + i * bd / 4, bd / 4 * 0.7, 'triangle', 0.08, ((i % 2) * 2 - 1) * 0.25)
    }

    // ── MELODY ──
    const melodies = theme.melodies
    const mel = melodies[this.loopN % melodies.length]
    const melNote = mel[this.beat % 8]
    if (melNote) {
      this.tone(melNote, t + 0.01, bd * 0.7, theme.leadType, 0.09, 0.2)
      this.tone(melNote * 1.5, t + 0.01, bd * 0.5, 'sine', 0.04, -0.2)
    }

    // ── DRUMS ──
    if (this.beat % 4 === 0) this.kick(t)
    if (this.beat % 4 === 2) {
      this.hihat(t, 0.07)
      this.tone(200, t, 0.08, 'sawtooth', 0.10, 0)
    }
    for (let i = 0; i < 4; i++) {
        this.hihat(t + i * bd / 4, i === 0 ? 0.05 : 0.02)
    }
  }

  scheduler() {
    if (!this.ctx) return
    const look = 0.2
    while (this.nextTime < this.ctx.currentTime + look) {
      this.scheduleBeat(this.nextTime)
      this.nextTime += 60 / this.bpm
      this.beat++
      if (this.beat >= 8) { this.beat = 0; this.loopN++ }
    }
  }

  start() {
    if (!this.init()) return
    if (this.playing) return
    if (this.ctx.state === 'suspended') this.ctx.resume()

    this.playing = true
    this.beat = 0
    this.nextTime = this.ctx.currentTime + 0.05

    const now = this.ctx.currentTime
    this.master.gain.cancelScheduledValues(now)
    this.master.gain.setValueAtTime(this.master.gain.value, now)
    this.master.gain.linearRampToValueAtTime(0.8, now + 1.5)

    if (this.timer) clearInterval(this.timer)
    this.timer = setInterval(() => this.scheduler(), 40)
  }

  stop() {
    if (!this.playing || !this.ctx) return
    const now = this.ctx.currentTime
    this.master.gain.cancelScheduledValues(now)
    this.master.gain.setValueAtTime(this.master.gain.value, now)
    this.master.gain.linearRampToValueAtTime(0, now + 1.2)

    const timer = this.timer
    this.timer = null
    setTimeout(() => {
      this.playing = false
      if (timer) { clearInterval(timer) }
    }, 1300)
  }

  destroy() {
    this.playing = false
    if (this.timer) { clearInterval(this.timer); this.timer = null }
    if (this.ctx) { this.ctx.close().catch(() => {}); this.ctx = null }
  }
}

let _engine = null
const getEngine = () => { if (!_engine) _engine = new BGMEngine(); return _engine }

// ─── Hook ────────────────────────────────────────────────────────────────────
export function useMusic(shouldPlay, isMuted, themeName = 'ambient') {
  const gestureRef = useRef(false)

  useEffect(() => {
    const engine = getEngine()
    engine.setTheme(themeName)

    if (shouldPlay && !isMuted) {
      const tryStart = () => {
        engine.start()
        gestureRef.current = true
      }

      if (gestureRef.current) {
        engine.start()
      } else {
        const handler = () => {
          tryStart()
          document.removeEventListener('click', handler)
          document.removeEventListener('touchstart', handler)
          document.removeEventListener('keydown', handler)
        }
        document.addEventListener('click', handler)
        document.addEventListener('touchstart', handler)
        document.addEventListener('keydown', handler)

        return () => {
          document.removeEventListener('click', handler)
          document.removeEventListener('touchstart', handler)
          document.removeEventListener('keydown', handler)
        }
      }
    } else {
      engine.stop()
    }
  }, [shouldPlay, isMuted, themeName])

  useEffect(() => {
    return () => {
      // Don't destroy global engine on every unmount of a component using the hook
      // only if it's really intended. For now we keep it singleton.
    }
  }, [])
}

// useSound.js — Sound effects menggunakan Web Audio API (tanpa library external)
import { useCallback, useRef, useEffect } from 'react'

function createAudioContext() {
  if (typeof window === 'undefined') return null
  return new (window.AudioContext || window.webkitAudioContext)()
}

// Buat beep/tone programatically
function playTone(ctx, { frequency = 440, type = 'sine', duration = 0.1, gain = 0.3, delay = 0 } = {}) {
  if (!ctx) return
  const oscillator = ctx.createOscillator()
  const gainNode   = ctx.createGain()

  oscillator.connect(gainNode)
  gainNode.connect(ctx.destination)

  oscillator.type      = type
  oscillator.frequency.setValueAtTime(frequency, ctx.currentTime + delay)
  gainNode.gain.setValueAtTime(0, ctx.currentTime + delay)
  gainNode.gain.linearRampToValueAtTime(gain, ctx.currentTime + delay + 0.01)
  gainNode.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + delay + duration)

  oscillator.start(ctx.currentTime + delay)
  oscillator.stop(ctx.currentTime + delay + duration + 0.05)
}

// Kumpulan sound presets
const SOUNDS = {
  flip: (ctx) => {
    playTone(ctx, { frequency: 600, type: 'sine', duration: 0.08, gain: 0.2 })
  },
  match: (ctx) => {
    // Chord naik — nada sukses
    playTone(ctx, { frequency: 523, type: 'sine', duration: 0.15, gain: 0.25, delay: 0 })
    playTone(ctx, { frequency: 659, type: 'sine', duration: 0.15, gain: 0.25, delay: 0.05 })
    playTone(ctx, { frequency: 784, type: 'sine', duration: 0.2,  gain: 0.3,  delay: 0.1 })
  },
  mismatch: (ctx) => {
    // Nada turun — error
    playTone(ctx, { frequency: 300, type: 'sawtooth', duration: 0.12, gain: 0.15, delay: 0 })
    playTone(ctx, { frequency: 220, type: 'sawtooth', duration: 0.15, gain: 0.12, delay: 0.08 })
  },
  win: (ctx) => {
    // Fanfare kemenangan
    const melody = [523, 659, 784, 1047]
    melody.forEach((f, i) => {
      playTone(ctx, { frequency: f, type: 'sine', duration: 0.2, gain: 0.3, delay: i * 0.12 })
    })
    // Tambah harmoni
    playTone(ctx, { frequency: 1047, type: 'sine', duration: 0.5, gain: 0.2, delay: 0.5 })
  },
  click: (ctx) => {
    playTone(ctx, { frequency: 800, type: 'sine', duration: 0.05, gain: 0.15 })
  },
  pop: (ctx) => {
    playTone(ctx, { frequency: 700, type: 'sine', duration: 0.04, gain: 0.3 })
    playTone(ctx, { frequency: 1200, type: 'sine', duration: 0.05, gain: 0.1, delay: 0.04 })
  },
  hover: (ctx) => {
    playTone(ctx, { frequency: 1000, type: 'sine', duration: 0.04, gain: 0.08 })
  },
  // Snake game sounds
  eat: (ctx) => {
    playTone(ctx, { frequency: 880, type: 'square', duration: 0.08, gain: 0.2 })
    playTone(ctx, { frequency: 1100, type: 'square', duration: 0.06, gain: 0.15, delay: 0.06 })
  },
  gameOver: (ctx) => {
    playTone(ctx, { frequency: 400, type: 'sawtooth', duration: 0.2, gain: 0.25, delay: 0 })
    playTone(ctx, { frequency: 300, type: 'sawtooth', duration: 0.2, gain: 0.22, delay: 0.15 })
    playTone(ctx, { frequency: 200, type: 'sawtooth', duration: 0.4, gain: 0.2,  delay: 0.3 })
  },
  levelUp: (ctx) => {
    [392, 523, 659, 784].forEach((f, i) => {
      playTone(ctx, { frequency: f, type: 'triangle', duration: 0.12, gain: 0.25, delay: i * 0.08 })
    })
  },
  toggle: (ctx) => {
    playTone(ctx, { frequency: 700, type: 'sine', duration: 0.07, gain: 0.15 })
  },
  trophy: (ctx) => {
    // Grand celebratory sound
    [523, 659, 784, 1047, 1318].forEach((f, i) => {
      playTone(ctx, { frequency: f, type: 'triangle', duration: 0.3, gain: 0.2, delay: i * 0.05 })
    });
    // Lower support notes for fullness
    [261, 329, 392].forEach((f, i) => {
      playTone(ctx, { frequency: f, type: 'sine', duration: 0.4, gain: 0.15, delay: 0.1 + i * 0.05 })
    });
  },
}

export function useSound() {
  const ctxRef    = useRef(null)
  const mutedRef  = useRef(false)

  // Lazy init AudioContext (harus dipicu user gesture)
  const getCtx = useCallback(() => {
    if (!ctxRef.current) {
      ctxRef.current = createAudioContext()
    }
    if (ctxRef.current?.state === 'suspended') {
      ctxRef.current.resume()
    }
    return ctxRef.current
  }, [])

  const play = useCallback((soundName) => {
    if (mutedRef.current) return
    const fn = SOUNDS[soundName]
    if (fn) fn(getCtx())
  }, [getCtx])

  const setMuted = useCallback((val) => {
    mutedRef.current = val
  }, [])

  return { play, setMuted }
}

import { useState, useMemo } from 'react'
import { useLocalAnalytics } from '../context/LocalAnalyticsContext.jsx'
import { useProgress } from '../context/ProgressContext.jsx'
