                    <div style={{ fontSize: 13, color: textMuted, marginTop: 8, fontWeight: 600 }}>KETUK UNTUK MENYALIN 📋</div>
                  </div>
                </BorderGlow>

                <h3 style={{ fontFamily: "'Fredoka One',cursive", color: textMain, fontSize: 16, marginBottom: 12 }}>
