                    <div className="mc-emoji-bg">{game.emoji}</div>
                    <div className="mc-top">
                      <div
                        className="mc-icon"
                        style={{ background: `${game.color}18`, border: `1.5px solid ${game.color}33`, position: 'relative', zIndex: 10 }}
