          margin-bottom: 24px;
          text-shadow: 0 4px 20px rgba(0,0,0,0.3);
        }
        .hero-subtitle {
          font-family: var(--font-mono);
          font-size: 10px;
          letter-spacing: 4px;
          color: #FFD700;
