                 <div style={{ display: 'flex', gap: 16, flexWrap: 'wrap', justifyContent: 'center' }}>
                   {rewards.map((r, i) => {
                     const mat = MATERIALS[r.id]
                     return (
                       <div key={i} style={{
                         background: '#1A1F35',
                         border: `2px solid ${mat.color}`, textAlign: 'center', width: 130, padding: "24px", borderRadius: 24,
