              ) : (
                <div style={{ fontSize: isFirst ? 36 : 28 }}>👤</div>
              )}
            </div>

            {/* Custom Border Overlay — from profile/shop */}
            {borderData ? (
              <BorderOverlay borderData={borderData} borderRadius={24} />
            ) : (
              <div 
                className="legacy-border-glow"
                style={{
                  position: 'absolute', inset: 0,
                  borderRadius: 24, border: `3.5px solid ${accent}`,
                  zIndex: 2, pointerEvents: 'none',
                  '--glow-color': accent
                }} 
              />
            )}
          </div>
          <div style={{
            position: 'absolute', bottom: -12, left: '50%', transform: 'translateX(-50%)',
            width: 32, height: 32, borderRadius: '50%', background: accent,
            display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 18,
            boxShadow: `0 4px 15px rgba(0,0,0,0.5), 0 0 10px ${accent}`, 
            border: '2.5px solid rgba(255,255,255,0.3)', zIndex: 4,
            fontWeight: 800
          }}>
            {medal}
          </div>
        </div>

        <div style={{ 
          fontFamily: "'Fredoka One',cursive", fontSize: isFirst ? 15 : 13, color: '#fff', 
          textAlign: 'center', width: '100%', overflow: 'hidden', textOverflow: 'ellipsis', 
          whiteSpace: 'nowrap', marginBottom: 2, 
          textShadow: isFirst ? `0 0 8px ${accent}44` : 'none'
        }}>
          {entry.name || 'Anon'}
        </div>

        {entry.selectedTitle && (
          <div style={{ 
            fontSize: isFirst ? 9 : 8, fontWeight: 900, color: isFirst ? '#FDCB6E' : '#A29BFE', 
            background: isFirst ? 'rgba(253, 203, 110, 0.15)' : 'rgba(162, 155, 254, 0.15)', 
            padding: '2px 8px', borderRadius: 6,
            textTransform: 'uppercase', marginBottom: 6, letterSpacing: '0.8px',
            border: `1px solid ${isFirst ? 'rgba(253, 203, 110, 0.2)' : 'rgba(162, 155, 254, 0.2)'}`
          }}>
            {entry.selectedTitle}
          </div>
        )}

        <div style={{ 
          fontFamily: "'Fredoka One',cursive", fontSize: isFirst ? 18 : 15, 
          color: accent, textShadow: `0 0 12px ${accent}33`
        }}>
          {(entry.score || 0).toLocaleString()}
        </div>

        {entry.name === nickname && (
          <div style={{ 
            fontSize: 9, color: '#00F5FF', fontWeight: 900, marginTop: 4,
            background: 'rgba(0,245,255,0.1)', padding: '1px 8px', borderRadius: 100
          }}>KAMU</div>
        )}
      </div>
    </div>
  )
}

// ─── Main Leaderboard Page ───────────────────────────────────────────────────

export default function Leaderboard({ onBack, games, onInspect }) {
  const { darkMode } = useSettings()
  const { play } = useSound()
  const { nickname, setNickname, getOnlineScores, getLocalBoard, clearCache, loading, lastError, firebaseStatus } = useLeaderboard()
  const { playerName, photoURL, isLoggedIn, userId } = useAuth()
  const { progress } = useProgress()
  const { friends } = useFriends()
  const tc = useThemeColors()
  const localBorder = progress.selectedBorder || null
  const localAvatar = progress.selectedAvatar || null

  const [gameTab, setGameTab] = useState('space-shooter')
  const [diffTab, setDiffTab] = useState(null)
  const [mode, setMode] = useState('online')
  const [scores, setScores] = useState([])
  const [showNickname, setShowNickname] = useState(!nickname)
  const [nameInput, setNameInput] = useState(nickname || '')
  const [refreshKey, setRefreshKey] = useState(0)

  const dark = tc.dark
  const bg = tc.bg
  const surface = tc.surface
  const textMain = tc.textMain
  const textMuted = tc.textMuted
  const borderCol = tc.borderCol

  useEffect(() => {
    let cancelled = false
    async function load() {
      let data
      if (mode === 'online') {
        const fetchDiff = diffTab === 'friends' ? null : diffTab
        data = await getOnlineScores(gameTab, fetchDiff)
        if (data && diffTab === 'friends') {
          // Filter out scores that are not from actual friends (and include current user)
          const friendUids = new Set(friends.map(f => f.uid))
          if (userId) friendUids.add(userId) // Add self
          const filtered = data.filter(r => friendUids.has(r.uid))
          // Re-rank them
          data = filtered.map((r, i) => ({ ...r, rank: i + 1 }))
        }
      } else {
        const fetchDiff = diffTab === 'friends' ? null : diffTab
        data = getLocalBoard(gameTab, fetchDiff)
      }
      if (!cancelled) setScores(data || [])
    }
    load()
    return () => { cancelled = true }
  }, [gameTab, diffTab, mode, refreshKey, getOnlineScores, getLocalBoard, friends, userId])

  const saveNickname = () => {
    const n = nameInput.trim()
    if (n.length >= 2) {
      setNickname(n)
      setShowNickname(false)
      play('click')
    }
  }

