                            }}>
                              {entry.selectedTitle}
                            </div>
                          )}
                        </div>
                        {entry.name === nickname && (
                          <span style={{ fontSize:10, color: 'var(--accent-vivid)', marginLeft:4 }}>← Kamu</span>
                        )}
                      </div>
                      <div style={{ fontSize:10, color:'rgba(255,255,255,0.4)', marginTop:1 }}>
                        {formatDate(entry.updatedAt || entry.createdAt || entry.date)}
                        {entry.level ? ` • Lv${entry.level}` : ''}
                        {entry.time ? ` • ${formatTime(entry.time)}` : ''}
                      </div>
                    </div>
                    {/* Score */}
                    <div style={{
                      fontFamily:"'Fredoka One',cursive", fontSize:16, color: '#4ECDC4', flexShrink:0,
                    }}>
                      {(entry.score || 0).toLocaleString()}
                    </div>
                  </div>
                )
              })}
            </div>
          )}

        </div>
      </div>
    </>
  )
}

import { useState, useEffect, useRef, useLayoutEffect } from 'react'
import { useSettings } from '../context/SettingsContext.jsx'
import { useSound } from '../hooks/useSound.js'
import { useProgress, ACHIEVEMENTS, getLevelInfo, getBorderForLevel, getTitleColorForLevel, CUSTOM_BORDERS, AVATAR_CATALOG } from '../context/ProgressContext.jsx'
import { useAuth } from '../context/AuthContext.jsx'
import { useCloudSave } from '../context/CloudSaveContext.jsx'
import { useThemeColors } from '../hooks/useThemeColors.js'
import { ADMIN_IDS } from '../config/admin.js'
import TitleSelector from '../components/TitleSelector.jsx'
import BorderSelector from '../components/BorderSelector.jsx'
import LevelRoad from '../components/LevelRoad.jsx'
import PremiumTitleBadge from '../components/PremiumTitleBadge.jsx'
import gsap from 'gsap'

const CATEGORY_META = {
  milestone: { label: 'Milestone',  icon: '🎮', color: '#4ECDC4' },
  variety:   { label: 'Variasi',    icon: '🧭', color: '#A29BFE' },
  skill:     { label: 'Skill',      icon: '⚔️', color: '#FF6B6B' },
  streak:    { label: 'Streak',     icon: '🔥', color: '#FD79A8' },
  score:     { label: 'Skor',       icon: '💰', color: '#FDCB6E' },
  perfect:   { label: 'Sempurna',   icon: '⭐', color: '#FFE66D' },
  speed:     { label: 'Kecepatan',  icon: '⚡', color: '#45B7D1' },
  game:      { label: 'Per-Game',   icon: '🎯', color: '#55EFC4' },
}

function formatPlayTime(seconds) {
  if (!seconds || seconds <= 0) return '0m'
  const h = Math.floor(seconds / 3600)
  const m = Math.floor((seconds % 3600) / 60)
  if (h > 0) return `${h}j ${m}m`
  return `${m}m`
}

export default function Profile({ onBack, games, onAnalytics, onAdmin, onFriends }) {
  const { darkMode } = useSettings()
  const { play } = useSound()
  const { progress } = useProgress()
  const { isLoggedIn, isGuest, playerName, photoURL, email, loginWithGoogle, logout, userId } = useAuth()
  const { syncStatus, lastSync, forceSync } = useCloudSave()
  const tc = useThemeColors()
  const [achFilter, setAchFilter] = useState('all')
  const [showTitleSelector, setShowTitleSelector] = useState(false)
  const dark = tc.dark

  const isAdmin = userId && ADMIN_IDS.includes(userId)

  const levelInfo = getLevelInfo(progress.totalXP || 0)
  const borderData = progress.selectedBorder ? CUSTOM_BORDERS[progress.selectedBorder] : getBorderForLevel(levelInfo.level)
  const titleStyle = getTitleColorForLevel(levelInfo.level)

  const [showBorderSelector, setShowBorderSelector] = useState(false)
  const [showLevelRoad, setShowLevelRoad] = useState(false)

  const claimedLevelRewards = progress.claimedLevelRewards || []
  const unclaimedCount = Array.from({ length: Math.max(0, levelInfo.level - 1) }, (_, i) => i + 2).filter(lvl => !claimedLevelRewards.includes(lvl)).length

  const unlockedSet = new Set(progress.unlockedAchievements || [])
  const unlockedCount = unlockedSet.size
  const totalAchievements = ACHIEVEMENTS.length

  // ── GSAP Refs ──
  const heroRef = useRef(null)
  const statsRef = useRef(null)
  const achRef = useRef(null)
  const gameStatsRef = useRef(null)
  const xpBarRef = useRef(null)
  const hasAnimated = useRef(false)

  const categories = ['all', ...Object.keys(CATEGORY_META)]
  const filteredAchievements = achFilter === 'all'
    ? ACHIEVEMENTS
    : ACHIEVEMENTS.filter(a => a.category === achFilter)

  const bg       = tc.bg
  const surface  = tc.surface
  const textMain = tc.textMain
  const textMuted= tc.textMuted
  const borderCol= tc.borderCol

  // ── GSAP Entrance Animations ──
  useLayoutEffect(() => {
    if (hasAnimated.current) return
    hasAnimated.current = true

    const tl = gsap.timeline({ defaults: { ease: 'power3.out' } })

    // Hero card entrance
    if (heroRef.current) {
      tl.fromTo(heroRef.current, { opacity: 0, y: 30, scale: 0.95 }, { opacity: 1, y: 0, scale: 1, duration: 0.6 })
    }

    // Stats grid stagger
    if (statsRef.current) {
      const statCards = statsRef.current.querySelectorAll('.prof-stat')
      tl.fromTo(statCards,
        { opacity: 0, y: 20, scale: 0.9 },
        { opacity: 1, y: 0, scale: 1, duration: 0.4, stagger: 0.07 },
        '-=0.3'
      )
    }

    // XP bar fill from 0
    if (xpBarRef.current) {
      gsap.fromTo(xpBarRef.current,
        { width: '0%' },
        { width: `${Math.round(levelInfo.progress * 100)}%`, duration: 1.2, ease: 'power2.out', delay: 0.5 }
      )
    }

    // Game stats section
    if (gameStatsRef.current) {
      const rows = gameStatsRef.current.querySelectorAll('.game-stat-row')
      tl.fromTo(rows,
        { opacity: 0, x: -20 },
        { opacity: 1, x: 0, duration: 0.35, stagger: 0.04 },
        '-=0.2'
      )
    }

    // Achievement section
    if (achRef.current) {
      tl.fromTo(achRef.current,
        { opacity: 0, y: 30 },
        { opacity: 1, y: 0, duration: 0.5 },
        '-=0.2'
      )
    }
  }, [])

  // ── Achievement filter change animation ──
  useEffect(() => {
    if (!achRef.current) return
    const items = achRef.current.querySelectorAll('.ach-item')
    if (!items.length) return
    gsap.fromTo(items,
      { opacity: 0, y: 12 },
      { opacity: 1, y: 0, duration: 0.3, stagger: 0.03, ease: 'power2.out', clearProps: 'all' }
    )
  }, [achFilter])

  return (
    <>
      <style>{`
        .prof-root {
          min-height: 100vh; padding: 32px 20px 80px;
          transition: background 0.4s;
        }
        .prof-inner { max-width: 600px; margin: 0 auto; }
        .prof-back {
          display: inline-flex; align-items: center; gap: 8px;
          background: ${surface}; border: 2px solid ${borderCol};
          border-radius: 12px; padding: 9px 18px;
          font-size: 14px; font-weight: 700; color: ${textMuted};
          cursor: pointer; margin-bottom: 28px; font-family: 'Nunito',sans-serif;
          transition: all 0.18s ease;
        }
        .prof-back:hover { border-color: #A29BFE; color: #A29BFE; transform: translateX(-3px); }

        /* Level card */
        .prof-level-card {
          background: ${surface}; border: 2px solid ${borderCol};
          border-radius: 24px; padding: 28px; margin-bottom: 20px;
          position: relative; overflow: hidden;
        }
        .prof-level-card::before {
          content: ''; position: absolute; top: 0; left: 0; right: 0; height: 4px;
          background: linear-gradient(90deg, #FF6B6B, #A29BFE, #4ECDC4, #FDCB6E);
        }

        /* Stats grid */
        .prof-stats {
          display: grid; grid-template-columns: repeat(2, 1fr); gap: 12px;
          margin-bottom: 20px;
        }
        .prof-stat {
          background: ${surface}; border: 2px solid ${borderCol};
          border-radius: 18px; padding: 18px 16px; text-align: center;
          transition: all 0.2s;
        }
        .prof-stat:hover { transform: translateY(-2px); border-color: #A29BFE44; }

        /* Achievement section */
        .prof-ach-section {
          background: ${surface}; border: 2px solid ${borderCol};
          border-radius: 24px; padding: 24px; margin-bottom: 20px;
        }

        /* Achievement filter */
        .ach-filter-row {
          display: flex; gap: 6px; flex-wrap: wrap; margin-bottom: 18px;
          padding-bottom: 16px; border-bottom: 1px solid ${dark ? 'rgba(255,255,255,0.06)' : 'rgba(0,0,0,0.06)'};
        }
        .ach-filter-btn {
          padding: 5px 12px; border-radius: 100px; border: 1.5px solid ${borderCol};
          background: transparent; font-size: 12px; font-weight: 700;
          cursor: pointer; transition: all 0.2s;
          font-family: 'Nunito',sans-serif; color: ${textMuted};
          white-space: nowrap;
        }
        .ach-filter-btn.active {
          border-color: #A29BFE; background: #A29BFE22; color: #A29BFE;
        }
        .ach-filter-btn:hover { border-color: #A29BFE; }

        /* Border Animations */
        @keyframes bp-border-pulse {
          from { filter: brightness(1) drop-shadow(0 0 10px gold); }
          to { filter: brightness(1.3) drop-shadow(0 0 25px gold); }
        }
        @keyframes bp-border-glitch {
          0% { border-color: #6c5ce7; box-shadow: 0 0 30px #6c5ce7; }
          45% { border-color: #6c5ce7; box-shadow: 0 0 30px #6c5ce7; }
          50% { border-color: #ff0064; box-shadow: 0 0 40px #ff0064; }
          55% { border-color: #6c5ce7; box-shadow: 0 0 30px #6c5ce7; }
          100% { border-color: #6c5ce7; box-shadow: 0 0 30px #6c5ce7; }
        }

        @media (max-width: 500px) {
          .ach-filter-row { flex-wrap: nowrap; overflow-x: auto; -webkit-overflow-scrolling: touch; scrollbar-width: none; }
          .ach-filter-row::-webkit-scrollbar { display: none; }
          .ach-filter-btn { flex-shrink: 0; }
        }

        /* Achievement item */
        .ach-item {
          display: flex; align-items: center; gap: 14px;
          padding: 14px; border-radius: 16px;
          margin-bottom: 8px; transition: all 0.2s;
          border: 1.5px solid transparent;
        }
        .ach-item.unlocked { background: ${dark ? 'rgba(253,203,110,0.06)' : 'rgba(253,203,110,0.08)'}; border-color: ${dark ? 'rgba(253,203,110,0.15)' : 'rgba(253,203,110,0.2)'}; }
        .ach-item.locked   { opacity: 0.5; }
        .ach-item:hover    { transform: translateX(4px); }
        .ach-icon-wrap {
          width: 48px; height: 48px; border-radius: 14px;
          display: flex; align-items: center; justify-content: center;
          font-size: 24px; flex-shrink: 0;
        }

        /* Leaderboard */
        .prof-leader {
          background: ${surface}; border: 2px solid ${borderCol};
          border-radius: 24px; padding: 24px;
        }

        @media (max-width: 480px) {
          .prof-stats { grid-template-columns: repeat(2, 1fr); gap: 8px; }
          .prof-stat { padding: 14px 10px; }
        }
      `}</style>

      <div className="prof-root" style={{ background: bg }}>
        <div className="prof-inner">

          {/* Back */}
          <button className="prof-back" onClick={() => { play('click'); onBack() }}>
            ← Kembali
          </button>

          {/* ── Level Card ── */}
          <div className="prof-level-card" ref={heroRef}>
            <div style={{ display: 'flex', alignItems: 'center', gap: 18, marginBottom: 20 }}>
              <div style={{ position: 'relative', width: 90, height: 90, flexShrink: 0 }}>
                {/* Avatar Content */}
                <div style={{
                  position: 'absolute', inset: 8, borderRadius: '50%',
                  background: progress.selectedAvatar ? (AVATAR_CATALOG.find(a=>a.id===progress.selectedAvatar)?.color || 'transparent') : photoURL ? 'transparent' : (borderData.bgColor || 'rgba(0,0,0,0.1)'),
                  display: 'flex', alignItems: 'center', justifyContent: 'center',
                  fontSize: 36, overflow: 'hidden', zIndex: 1,
                  boxShadow: progress.selectedAvatar ? `inset 0 0 15px rgba(0,0,0,0.5)` : 'none'
                }}>
                  {progress.selectedAvatar ? (
                    <img src={AVATAR_CATALOG.find(a=>a.id===progress.selectedAvatar)?.img} alt="Avatar" style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
                  ) : photoURL ? (
                    <img src={photoURL} alt="" style={{ width: '100%', height: '100%', objectFit: 'cover' }} referrerPolicy="no-referrer" />
                  ) : (
                    levelInfo.level < 5 ? '🌱' : levelInfo.level < 10 ? '⚔️' : levelInfo.level < 15 ? '👑' : '🌟'
                  )}
                </div>

                {/* Border Layer */}
                {borderData.url ? (
                  <div 
                    className="premium-border-glow"
                    style={{
                      position: 'absolute', inset: 0,
                      backgroundImage: `url(${borderData.url})`,
                      backgroundSize: '100% 100%',
                      backgroundPosition: 'center',
                      backgroundRepeat: 'no-repeat',
                      zIndex: 2, pointerEvents: 'none',
