                  />
                ) : (
                  <div 
                    className="legacy-border-glow"
                    style={{
                      position: 'absolute', inset: 6,
                      borderRadius: '50%', border: borderData.border,
                      boxShadow: borderData.boxShadow,
                      animation: borderData.animation || 'none',
                      zIndex: 2, pointerEvents: 'none',
                      '--glow-color': borderData.glowColor || '#7C6FE8'
                    }} 
                  />
                )}
              </div>
              <div style={{ flex: 1 }}>
                <div style={{ fontFamily: "'Fredoka One',cursive", fontSize: 13, color: borderData.color, letterSpacing: '0.5px', marginBottom: 2 }}>
                  LEVEL {levelInfo.level}
                </div>
                <div style={{ display: 'flex', alignItems: 'center', gap: 6, marginBottom: 2 }}>
                  <PremiumTitleBadge 
                    title={progress.selectedTitle || levelInfo.title}
                    rarity={progress.getTitleRarity?.(progress.selectedTitle || levelInfo.title) || 'common'}
                    size="normal"
                  />
                  <button 
                    onClick={() => { play('click'); setShowTitleSelector(true) }}
                    style={{ 
                      fontSize: 10, background: 'transparent', border: 'none', 
                      color: tc.textMuted, cursor: 'pointer', textDecoration: 'underline',
                      fontWeight: 700
                    }}
                  >
                    Ganti Gelar
                  </button>
                  <span style={{ color: tc.borderCol }}>•</span>
                  <button 
                    onClick={() => { play('click'); setShowBorderSelector(true) }}
                    style={{ 
                      fontSize: 10, background: 'transparent', border: 'none', 
                      color: tc.textMuted, cursor: 'pointer', textDecoration: 'underline',
                      fontWeight: 700
                    }}
                  >
                    Ganti Bingkai
                  </button>
                </div>
                <div style={{ 
                  fontFamily: "'Fredoka One',cursive", fontSize: 24, lineHeight: 1.1,
                  background: titleStyle.bg !== 'transparent' ? titleStyle.bg : 'none',
                  WebkitBackgroundClip: titleStyle.bg !== 'transparent' ? 'text' : 'border-box',
                  WebkitTextFillColor: titleStyle.bg !== 'transparent' ? 'transparent' : textMain,
                  color: textMain,
                  marginBottom: 4
                }}>
                  {playerName || 'Player'}
                </div>
                <div style={{ fontSize: 12, color: textMuted, marginTop: 4 }}>
                  {isLoggedIn ? `${email}` : isGuest ? 'Mode Tamu' : ''} • <strong style={{color: borderData.color}}>{(progress.totalXP || 0).toLocaleString()} XP</strong>
                </div>
