                  background: 'linear-gradient(135deg,#4285F4,#356AC3)',
                  border: 'none', borderRadius: 8,
                  padding: '6px 14px', fontSize: 11, color: '#fff', cursor: 'pointer', fontWeight: 700,
                  boxShadow: '0 2px 8px rgba(66,133,244,0.3)',
