  const ADMIN_HASH = '6cee52' // hashed admin email
  const hashEmail = (e) => {
    if (!e) return ''
    let h = 0
    for (let i = 0; i < e.length; i++) { h = ((h << 5) - h) + e.charCodeAt(i); h |= 0 }
    return Math.abs(h).toString(16).slice(0, 6)
  }
