  const setPhase = (p) => { phaseRef.current = p; _setPhase(p) }

  // Resize handler
  useEffect(() => {
    let t = null
    const onRz = () => { clearTimeout(t); t = setTimeout(() => setRzKey(k => k + 1), 250) }
    window.addEventListener('resize', onRz)
    const onOr = () => setTimeout(onRz, 200)
    window.addEventListener('orientationchange', onOr)
    return () => { clearTimeout(t); window.removeEventListener('resize', onRz); window.removeEventListener('orientationchange', onOr) }
  }, [])

  // ── Generate bricks for a level ──
  function generateBricks(W, H, lvl) {
    const rows = Math.min(cfg.brickRows + Math.floor(lvl / 3), 8)
    const cols = Math.min(cfg.brickCols + Math.floor(lvl / 4), 11)
    const brickW = (W - 20) / cols - 4
    const brickH = 18
    const bricks = []
    const startY = 50

    for (let r = 0; r < rows; r++) {
      for (let c = 0; c < cols; c++) {
        const isGold = Math.random() < 0.08 + lvl * 0.005
        const isSteel = Math.random() < 0.05 + lvl * 0.01 && !isGold
        bricks.push({
          x: 12 + c * (brickW + 4),
          y: startY + r * (brickH + 4),
          w: brickW,
          h: brickH,
          color: isGold ? '#FFD700' : isSteel ? '#95A5A6' : BRICK_COLORS[(r + lvl) % BRICK_COLORS.length],
          hp: isSteel ? 2 : 1,
          maxHp: isSteel ? 2 : 1,
          gold: isGold,
          steel: isSteel,
          points: isGold ? 30 : isSteel ? 20 : 10,
          alive: true,
          shakeT: 0,
          breakAnimation: 0,
        })
      }
    }
    return bricks
  }

  // ── Generate boss ──
  function generateBoss(W, lvl) {
    const hp = cfg.bossHP + Math.floor(lvl / 5) * 10
    return {
      x: W / 2 - 60,
      y: 30,
      w: 120,
      h: 40,
      hp,
      maxHP: hp,
      color: '#FF4757',
      dir: 1,
      speed: 1 + lvl * 0.1,
      alive: true,
      shootTimer: 0,
      projectiles: [],
    }
  }

  // ── Init game state ──
  function initGame(W, H, lvl = 1) {
    const isBoss = lvl % 5 === 0
    const paddleW = cfg.paddleW
    const g = {
      W, H,
      paddle: { x: W / 2 - paddleW / 2, y: H - 40, w: paddleW, h: 12, baseW: paddleW },
      balls: [{
        x: W / 2, y: H - 55,
        dx: cfg.ballSpeed * (Math.random() > 0.5 ? 1 : -1) * 0.7,
        dy: -cfg.ballSpeed,
        r: 7,
        fireball: false,
        stuck: true,
      }],
      bricks: isBoss ? [] : generateBricks(W, H, lvl),
      boss: isBoss ? generateBoss(W, lvl) : null,
      powerups: [],
      lasers: [],
      particles: [],
      effects: { wide: 0, fireball: 0, magnet: 0, laser: 0 },
      score: gameRef.current ? gameRef.current.score : 0,
      lives: gameRef.current ? gameRef.current.lives : cfg.lives,
      level: lvl,
      combo: 0,
      comboTimer: 0,
      stars: [],
    }
    return g
  }

  // ── Canvas setup ──
  useEffect(() => {
    const canvas = canvasRef.current
    if (!canvas) return
    const parent = canvas.parentElement
    if (!parent) return
    const rect = parent.getBoundingClientRect()
    const dpr = Math.min(window.devicePixelRatio || 1, 2)
    const W = Math.floor(rect.width) || window.innerWidth
    const H = Math.floor(rect.height) || window.innerHeight
    canvas.width = W * dpr
    canvas.height = H * dpr
    canvas.style.width = W + 'px'
    canvas.style.height = H + 'px'
    const ctx = canvas.getContext('2d')
    ctx.setTransform(dpr, 0, 0, dpr, 0, 0)

    gameRef.current = initGame(W, H, 1)
    setScore(0)
    setLives(cfg.lives)
    setLevel(1)
    setCombo(0)

    // ── Input handlers ──
    const onMouseMove = (e) => {
      const r = canvas.getBoundingClientRect()
      inputRef.current.mouseX = e.clientX - r.left
    }
    const onTouchStart = (e) => {
      if (e.cancelable) e.preventDefault()
      const t = e.touches[0]
      const r = canvas.getBoundingClientRect()
      inputRef.current.touchActive = true
      inputRef.current.touchX = t.clientX - r.left
      onClick()
    }
    const onTouchMove = (e) => {
      if (e.cancelable) e.preventDefault()
      const t = e.touches[0]
      const r = canvas.getBoundingClientRect()
      inputRef.current.touchX = t.clientX - r.left
    }
    const onTouchEnd = () => {
      inputRef.current.touchActive = false
    }
    const onClick = () => {
      const g = gameRef.current
      if (!g) return
      if (phaseRef.current === 'idle') {
        setPhase('playing')
        g.balls.forEach(b => { b.stuck = false })
      }
      // Release stuck balls (magnet)
      g.balls.forEach(b => { if (b.stuck) b.stuck = false })
    }

    canvas.addEventListener('mousemove', onMouseMove)
    canvas.addEventListener('touchstart', onTouchStart, { passive: false })
    canvas.addEventListener('touchmove', onTouchMove, { passive: false })
    canvas.addEventListener('touchend', onTouchEnd)
    canvas.addEventListener('click', onClick)

    // ── Game loop ──
    let lastTime = 0
    function loop(timestamp) {
      const dt = Math.min((timestamp - lastTime) / 16.667, 2)
      lastTime = timestamp

      const g = gameRef.current
      if (!g) { animRef.current = requestAnimationFrame(loop); return }
      const p = phaseRef.current

      // Move paddle
      let targetX = null
      if (inputRef.current.touchActive && inputRef.current.touchX !== null) {
        targetX = inputRef.current.touchX
      } else if (inputRef.current.mouseX !== null) {
        targetX = inputRef.current.mouseX
      }
      if (targetX !== null) {
        const pw = g.effects.wide > 0 ? g.paddle.baseW * 1.5 : g.paddle.baseW
        g.paddle.w = pw
        g.paddle.x = clamp(targetX - pw / 2, 0, W - pw)
      }

      if (p !== 'playing') {
        draw(ctx, g, W, H)
        animRef.current = requestAnimationFrame(loop)
        return
      }

      // Update effects timers
      const now = Date.now()
      for (const key of ['wide', 'fireball', 'magnet', 'laser']) {
        if (g.effects[key] > 0 && now > g.effects[key]) {
          g.effects[key] = 0
        }
      }

      // Fire lasers
      if (g.effects.laser > 0) {
        if (!g.lastLaserTime) g.lastLaserTime = 0
        if (now - g.lastLaserTime > 500) { // Fire every 0.5s
          g.lastLaserTime = now
          g.lasers.push({ x: g.paddle.x + 10, y: g.paddle.y, dy: -6, w: 4, h: 12 })
          g.lasers.push({ x: g.paddle.x + g.paddle.w - 14, y: g.paddle.y, dy: -6, w: 4, h: 12 })
          try { play('flip') } catch(e) {}
        }
      }

      // Update balls
      for (let bi = g.balls.length - 1; bi >= 0; bi--) {
        const ball = g.balls[bi]
        if (ball.stuck) {
          ball.x = g.paddle.x + g.paddle.w / 2
          ball.y = g.paddle.y - ball.r - 2
          continue
        }

        ball.fireball = g.effects.fireball > 0

        // Trail Update
        ball.trail = ball.trail || []
        if (p === 'playing' && !ball.stuck) {
           ball.trail.push({x: ball.x, y: ball.y})
           if (ball.trail.length > (ball.fireball ? 15 : 8)) ball.trail.shift()
        } else if (ball.stuck || p !== 'playing') {
           ball.trail = []
        }

        ball.x += ball.dx * dt
        ball.y += ball.dy * dt

        // Wall bounce
        if (ball.x - ball.r < 0) { ball.x = ball.r; ball.dx = Math.abs(ball.dx); }
        if (ball.x + ball.r > W) { ball.x = W - ball.r; ball.dx = -Math.abs(ball.dx); }
        if (ball.y - ball.r < 0) { ball.y = ball.r; ball.dy = Math.abs(ball.dy); }

        // Paddle bounce (CCD - Continuous Collision Detection for mobile stability)
        const prevY = ball.y - ball.dy * dt
        const paddleHit = ball.dy > 0 && 
                         prevY + ball.r <= g.paddle.y && 
                         ball.y + ball.r >= g.paddle.y &&
                         ball.x >= g.paddle.x - 6 &&
                         ball.x <= g.paddle.x + g.paddle.w + 6

        if (paddleHit) {
          const hitPos = (ball.x - g.paddle.x) / g.paddle.w
          const angle = (hitPos - 0.5) * Math.PI * 0.75
          const speed = Math.sqrt(ball.dx * ball.dx + ball.dy * ball.dy)

          ball.dx = speed * Math.sin(angle)
          ball.dy = -Math.abs(speed * Math.cos(angle))

          // Anti-sticking: Snap ball above paddle
          ball.y = g.paddle.y - ball.r - 2

          if (g.effects.magnet > 0) {
            ball.stuck = true
          }
          g.combo = 0
          try { play('flip'); vibrateLight() } catch(e) {}
        }

        // Brick collision
        for (const brick of g.bricks) {
          if (!brick.alive && brick.breakAnimation <= 0) continue
          if (ball.x + ball.r > brick.x && ball.x - ball.r < brick.x + brick.w &&
              ball.y + ball.r > brick.y && ball.y - ball.r < brick.y + brick.h) {
            brick.hp--
            if (brick.hp <= 0) {
              brick.alive = false
              brick.breakAnimation = 15
              g.combo++
              const comboBonus = Math.min(g.combo, 10)
              const pts = brick.points * (1 + comboBonus * 0.1) * (1 + (g.level - 1) * 0.1)
              g.score += Math.round(pts)

              // Spawn particles
              for (let i = 0; i < 6; i++) {
                g.particles.push({
                  x: brick.x + brick.w / 2, y: brick.y + brick.h / 2,
                  dx: rand(-3, 3), dy: rand(-3, 1),
                  life: 30, color: brick.color, r: rand(2, 5),
                })
              }

              // Maybe spawn powerup (12% chance)
              if (Math.random() < 0.12) {
                const type = POWERUP_TYPES[Math.floor(Math.random() * POWERUP_TYPES.length)]
                g.powerups.push({
                  ...type, x: brick.x + brick.w / 2, y: brick.y + brick.h / 2,
                  dy: 1.5, r: 10,
                })
              }
            } else {
              brick.color = '#BDC3C7' // steel hit visual
              brick.shakeT = 10 // shake animation
              // Spark particles on non-lethal hit
              for (let i = 0; i < 4; i++) {
                g.particles.push({
                  x: brick.x + brick.w / 2, y: brick.y + brick.h / 2,
                  dx: rand(-2, 2), dy: rand(-2, 1),
                  life: 15, color: '#fff', r: rand(1, 3),
                })
              }
            }

            if (!ball.fireball) {
              // Determine bounce direction
              const overlapL = (ball.x + ball.r) - brick.x
              const overlapR = (brick.x + brick.w) - (ball.x - ball.r)
              const overlapT = (ball.y + ball.r) - brick.y
              const overlapB = (brick.y + brick.h) - (ball.y - ball.r)
              const minOverlap = Math.min(overlapL, overlapR, overlapT, overlapB)
              if (minOverlap === overlapT || minOverlap === overlapB) ball.dy = -ball.dy
              else ball.dx = -ball.dx
            }
            try { play('match'); vibrateLight() } catch(e) {}
            break
          }
        }

        // Boss collision
        if (g.boss && g.boss.alive) {
          const b = g.boss
          if (ball.x + ball.r > b.x && ball.x - ball.r < b.x + b.w &&
              ball.y + ball.r > b.y && ball.y - ball.r < b.y + b.h) {
            b.hp--
            g.score += 5
            ball.dy = Math.abs(ball.dy)
            for (let i = 0; i < 4; i++) {
              g.particles.push({
                x: ball.x, y: ball.y,
                dx: rand(-2, 2), dy: rand(-2, 2),
                life: 20, color: '#FF4757', r: rand(2, 4),
              })
            }
            try { play('match'); vibrateLight() } catch(e) {}
            if (b.hp <= 0) {
              b.alive = false
              g.score += 200 + g.level * 50
              for (let i = 0; i < 20; i++) {
                g.particles.push({
                  x: b.x + b.w / 2, y: b.y + b.h / 2,
                  dx: rand(-5, 5), dy: rand(-5, 3),
                  life: 50, color: ['#FF4757','#FFD700','#FF6B6B','#FDCB6E'][i%4], r: rand(3, 7),
                })
              }
            }
          }
        }

        // Ball fell below
        if (ball.y - ball.r > H) {
          g.balls.splice(bi, 1)
        }
      }

      // Boss movement & shooting
      if (g.boss && g.boss.alive) {
        const b = g.boss
        b.x += b.dir * b.speed * dt
        if (b.x <= 10 || b.x + b.w >= W - 10) b.dir *= -1
        b.shootTimer++
        if (b.shootTimer > 90 - g.level * 2) {
          b.shootTimer = 0
          b.projectiles.push({
            x: b.x + b.w / 2, y: b.y + b.h,
            dy: 3 + g.level * 0.15, r: 5, color: '#FF4757',
          })
        }
        // Update projectiles
        for (let i = b.projectiles.length - 1; i >= 0; i--) {
          const proj = b.projectiles[i]
          proj.y += proj.dy * dt
          // Hit paddle = lose life
          if (proj.y + proj.r >= g.paddle.y && proj.y - proj.r <= g.paddle.y + g.paddle.h &&
              proj.x >= g.paddle.x && proj.x <= g.paddle.x + g.paddle.w) {
            b.projectiles.splice(i, 1)
            g.lives--
            try { play('mismatch'); vibrateHeavy() } catch(e) {}
            continue
          }
          if (proj.y > H + 20) b.projectiles.splice(i, 1)
        }
      }

      // Update lasers
      for (let i = g.lasers.length - 1; i >= 0; i--) {
        const l = g.lasers[i]
        l.y += l.dy * dt
        if (l.y < -20) { g.lasers.splice(i, 1); continue }

        // Hit brick
        let hit = false
        for (const brick of g.bricks) {
          if (!brick.alive) continue
          if (l.x < brick.x + brick.w && l.x + l.w > brick.x && l.y < brick.y + brick.h && l.y + l.h > brick.y) {
            brick.hp--
            if (brick.hp <= 0) {
              brick.alive = false; brick.breakAnimation = 15; g.score += brick.points
              for (let pi = 0; pi < 4; pi++) g.particles.push({ x: l.x, y: l.y, dx: rand(-2, 2), dy: rand(-2, 2), life: 20, color: brick.color, r: 2 })
            }
            hit = true; break
          }
        }
        // Hit boss
        if (!hit && g.boss && g.boss.alive) {
          const b = g.boss
          if (l.x < b.x + b.w && l.x + l.w > b.x && l.y < b.y + b.h && l.y + l.h > b.y) {
            b.hp--; g.score += 5; hit = true
            for (let pi = 0; pi < 4; pi++) g.particles.push({ x: l.x, y: l.y, dx: rand(-2, 2), dy: rand(-2, 2), life: 20, color: '#FF4757', r: 2 })
          }
        }
        if (hit) g.lasers.splice(i, 1)
      }

      // Powerup movement & collection
      for (let i = g.powerups.length - 1; i >= 0; i--) {
        const pu = g.powerups[i]
        pu.y += pu.dy * dt
        // Collect
        if (pu.y + pu.r >= g.paddle.y && pu.y - pu.r <= g.paddle.y + g.paddle.h &&
            pu.x >= g.paddle.x && pu.x <= g.paddle.x + g.paddle.w) {
          g.powerups.splice(i, 1)
          applyPowerup(g, pu, W, H)
          try { play('win'); vibrateMedium() } catch(e) {}
          continue
        }
        if (pu.y > H + 20) g.powerups.splice(i, 1)
      }

      // Particles
      for (let i = g.particles.length - 1; i >= 0; i--) {
        const pt = g.particles[i]
        pt.x += pt.dx * dt
        pt.y += pt.dy * dt
        pt.dy += 0.1
        pt.life--
        if (pt.life <= 0) g.particles.splice(i, 1)
      }

      // Combo timer
      g.comboTimer++
      if (g.comboTimer > 120) g.combo = 0

      // Brick shake decay
      for (const brick of g.bricks) {
        if (brick.shakeT > 0) brick.shakeT -= dt
        if (brick.breakAnimation > 0) brick.breakAnimation -= dt
      }

      // All balls lost
      if (g.balls.length === 0) {
        g.lives--
        if (g.lives <= 0) {
          // Game Over
          setPhase('lost')
          setScore(g.score)
          setLives(0)
          try { play('mismatch'); vibrateError() } catch(e) {}
          const coinAmt = Math.max(5, Math.floor(g.score / 100))
          earnCoins(coinAmt, `Brick Breaker Lv${g.level} (${difficulty.id})`)
          reportGameResult({
            gameId: 'brick-breaker', difficultyId: difficulty.id,
            won: false, score: g.score, stars: 0, timeSec: 0,
          })
        } else {
          // Respawn ball
          g.balls.push({
            x: g.paddle.x + g.paddle.w / 2, y: g.paddle.y - 10,
            dx: cfg.ballSpeed * (Math.random() > 0.5 ? 1 : -1) * 0.7,
            dy: -cfg.ballSpeed,
            r: 7, fireball: false, stuck: true,
          })
          setLives(g.lives)
          try { play('mismatch'); vibrateError() } catch(e) {}
        }
      }

      // Level complete
      const bricksCleared = g.bricks.length > 0 && g.bricks.every(b => !b.alive)
      const bossDefeated = g.boss && !g.boss.alive
      if (bricksCleared || bossDefeated) {
        const nextLvl = g.level + 1
        if (nextLvl > cfg.maxLevel) {
          // WIN!
          setPhase('won')
          setScore(g.score)
          setShowConfetti(true)
          try { play('win'); vibrateSuccess() } catch(e) {}
          let stars = g.lives >= cfg.lives ? 3 : g.lives >= cfg.lives - 1 ? 2 : 1
          const coinReward = { easy: 30, medium: 50, hard: 80 }
          let coinAmt = (coinReward[difficulty.id] || 30) + Math.floor(g.score / 200)
          if (stars === 3) coinAmt += 30
          earnCoins(coinAmt, `Menang Brick Breaker (${difficulty.id})`)
          reportGameResult({
            gameId: 'brick-breaker', difficultyId: difficulty.id,
            won: true, score: g.score, stars, timeSec: 0,
          })
          // Save best
          const bestKey = `brick-breaker-best-${difficulty.id}`
          const prev = parseInt(localStorage.getItem(bestKey) || '0')
          if (g.score > prev) localStorage.setItem(bestKey, g.score)
        } else {
          // Next level
          setLevel(nextLvl)
          setScore(g.score)
          const ng = initGame(W, H, nextLvl)
          ng.score = g.score
          ng.lives = g.lives
          gameRef.current = ng
          // Auto start
          ng.balls.forEach(b => { b.stuck = false })
          // Slight delay before auto-start next level
          setPhase('playing')
        }
      }

      // Update UI
      setScore(g.score)
      setCombo(g.combo)
      if (g.boss) {
        setBossHP(g.boss.hp)
        setBossMaxHP(g.boss.maxHP)
      } else {
        setBossHP(0)
      }

      draw(ctx, g, W, H)
      animRef.current = requestAnimationFrame(loop)
    }

    function applyPowerup(g, pu, W, H) {
      switch (pu.id) {
        case 'fireball':
          g.effects.fireball = Date.now() + pu.duration
          break
        case 'wide':
          g.effects.wide = Date.now() + pu.duration
          break
        case 'magnet':
          g.effects.magnet = Date.now() + pu.duration
          break
        case 'multi': {
          // Add 2 extra balls
          const mainBall = g.balls[0]
          if (mainBall) {
            for (let i = 0; i < 2; i++) {
              g.balls.push({
                x: mainBall.x, y: mainBall.y,
                dx: cfg.ballSpeed * Math.cos(Math.PI * 0.3 * (i === 0 ? 1 : -1)),
                dy: -cfg.ballSpeed * Math.abs(Math.sin(Math.PI * 0.3)),
                r: 7, fireball: mainBall.fireball, stuck: false,
              })
            }
          }
          break
        }
        case 'life':
          g.lives = Math.min(g.lives + 1, cfg.lives + 2)
          setLives(g.lives)
          break
        case 'laser':
          g.effects.laser = Date.now() + pu.duration
          break
      }
    }

    function draw(ctx, g, W, H) {
      // Background
      ctx.fillStyle = '#0a0a2e'
      ctx.fillRect(0, 0, W, H)

      // Grid lines (subtle)
      ctx.strokeStyle = 'rgba(162,155,254,0.04)'
      ctx.lineWidth = 1
      for (let x = 0; x < W; x += 30) { ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, H); ctx.stroke() }
      for (let y = 0; y < H; y += 30) { ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(W, y); ctx.stroke() }

      // Bricks
      for (const brick of g.bricks) {
        if (!brick.alive && brick.breakAnimation <= 0) continue
        const shakeOff = brick.shakeT > 0 ? (Math.sin(brick.shakeT * 8) * brick.shakeT * 0.4) : 0
        const bx = brick.x + shakeOff
        const breakProg = 1 - (brick.breakAnimation / 15)
        const opacity = brick.breakAnimation > 0 ? 1 - breakProg : 1
        ctx.globalAlpha = opacity
        ctx.fillStyle = brick.color
        ctx.shadowColor = brick.color
        ctx.shadowBlur = brick.gold ? 12 : 4
        const r = 4
        ctx.beginPath()
        drawRoundRect(ctx, bx, brick.y, brick.w, brick.h, r)
        ctx.fill()
        ctx.shadowBlur = 0

        if (brick.gold) {
          ctx.fillStyle = 'rgba(255,255,255,0.3)'
          ctx.beginPath()
          drawRoundRect(ctx, bx + 2, brick.y + 2, brick.w - 4, brick.h / 2 - 2, [r, r, 0, 0])
          ctx.fill()
        }
        // Crack lines on damaged steel bricks
        if (brick.steel && brick.hp < brick.maxHp) {
          ctx.strokeStyle = 'rgba(0,0,0,0.5)'
          ctx.lineWidth = 1.5
          ctx.beginPath()
          ctx.moveTo(bx + brick.w * 0.3, brick.y + 2)
          ctx.lineTo(bx + brick.w * 0.5, brick.y + brick.h * 0.6)
          ctx.lineTo(bx + brick.w * 0.65, brick.y + brick.h - 2)
          ctx.stroke()
          ctx.beginPath()
          ctx.moveTo(bx + brick.w * 0.5, brick.y + brick.h * 0.6)
          ctx.lineTo(bx + brick.w * 0.75, brick.y + brick.h * 0.4)
          ctx.stroke()
        }
        ctx.globalAlpha = 1
        if (brick.steel && brick.hp > 1) {
          ctx.strokeStyle = 'rgba(255,255,255,0.4)'
          ctx.lineWidth = 1.5
          ctx.beginPath()
          drawRoundRect(ctx, bx + 1, brick.y + 1, brick.w - 2, brick.h - 2, r)
          ctx.stroke()
        }
      }

      // Boss
      if (g.boss && g.boss.alive) {
        const b = g.boss
        const hpRatio = b.hp / b.maxHP
        ctx.fillStyle = hpRatio > 0.5 ? '#FF4757' : hpRatio > 0.25 ? '#FF6348' : '#EA2027'
        ctx.shadowColor = '#FF4757'
        ctx.shadowBlur = 15 + Math.sin(Date.now() / 200) * 5
        ctx.beginPath()
        drawRoundRect(ctx, b.x, b.y, b.w, b.h, 8)
        ctx.fill()
        ctx.shadowBlur = 0

        // Boss face
        ctx.fillStyle = '#fff'
        ctx.font = 'bold 20px monospace'
        ctx.textAlign = 'center'
        ctx.fillText('👾', b.x + b.w / 2, b.y + b.h / 2 + 7)

        // HP bar
        ctx.fillStyle = 'rgba(0,0,0,0.5)'
        ctx.fillRect(b.x, b.y - 10, b.w, 6)
        ctx.fillStyle = hpRatio > 0.5 ? '#00B894' : hpRatio > 0.25 ? '#FDCB6E' : '#FF4757'
        ctx.fillRect(b.x, b.y - 10, b.w * hpRatio, 6)

        // Boss projectiles
        for (const proj of b.projectiles) {
          ctx.fillStyle = proj.color
          ctx.shadowColor = proj.color
          ctx.shadowBlur = 8
          ctx.beginPath()
          ctx.arc(proj.x, proj.y, proj.r, 0, Math.PI * 2)
          ctx.fill()
          ctx.shadowBlur = 0
        }
      }

      // Powerups
      for (const pu of g.powerups) {
        ctx.fillStyle = pu.color
        ctx.shadowColor = pu.color
        ctx.shadowBlur = 10
        ctx.beginPath()
        ctx.arc(pu.x, pu.y, pu.r, 0, Math.PI * 2)
        ctx.fill()
        ctx.shadowBlur = 0
        ctx.font = '12px serif'
        ctx.textAlign = 'center'
        ctx.fillText(pu.emoji, pu.x, pu.y + 4)
      }

      // Tap to launch hint
      if (g.balls.some(b => b.stuck) && phase === 'playing') {
        ctx.fillStyle = 'rgba(255,255,255,0.6)'
        ctx.font = "italic 700 14px 'Fredoka One',cursive"
        ctx.textAlign = 'center'
        ctx.fillText('TAP TO LAUNCH 🚀', W / 2, g.paddle.y - 40)
      }

      // Lasers
      for (const l of g.lasers) {
        ctx.fillStyle = '#FF4757'; ctx.shadowColor = '#FF4757'; ctx.shadowBlur = 8
        ctx.fillRect(l.x, l.y, l.w, l.h)
        ctx.shadowBlur = 0
      }

      // Paddle
      const pw = g.paddle.w
      const px = g.paddle.x
      const py = g.paddle.y
      const grad = ctx.createLinearGradient(px, py, px, py + g.paddle.h)
      if (g.effects.wide > 0) {
        grad.addColorStop(0, '#00CEC9')
        grad.addColorStop(1, '#00B894')
      } else if (g.effects.magnet > 0) {
        grad.addColorStop(0, '#FDCB6E')
        grad.addColorStop(1, '#F39C12')
      } else {
        grad.addColorStop(0, '#A29BFE')
        grad.addColorStop(1, '#6C5CE7')
      }
      ctx.fillStyle = grad
      ctx.shadowColor = '#A29BFE'
      ctx.shadowBlur = 10
      ctx.beginPath()
      drawRoundRect(ctx, px, py, pw, g.paddle.h, 6)
      ctx.fill()
      ctx.shadowBlur = 0

      // Balls
      for (const ball of g.balls) {
        // Draw Trail
        if (ball.trail && ball.trail.length > 1) {
           ctx.beginPath()
           ctx.moveTo(ball.trail[0].x, ball.trail[0].y)
           for (let i = 1; i < ball.trail.length; i++) {
             ctx.lineTo(ball.trail[i].x, ball.trail[i].y)
           }
           ctx.lineTo(ball.x, ball.y)
           ctx.strokeStyle = ball.fireball ? 'rgba(255, 69, 0, 0.45)' : 'rgba(162, 155, 254, 0.35)'
           ctx.lineWidth = ball.fireball ? ball.r * 1.8 : ball.r * 1.2
           ctx.lineCap = 'round'
           ctx.stroke()
        }

        ctx.fillStyle = ball.fireball ? '#FF4500' : '#fff'
        ctx.shadowColor = ball.fireball ? '#FF4500' : '#A29BFE'
        ctx.shadowBlur = ball.fireball ? 15 : 8
        ctx.beginPath()
        ctx.arc(ball.x, ball.y, ball.r, 0, Math.PI * 2)
        ctx.fill()
        ctx.shadowBlur = 0
        if (ball.fireball) {
          ctx.fillStyle = 'rgba(255,69,0,0.3)'
          ctx.beginPath()
          ctx.arc(ball.x, ball.y, ball.r + 4, 0, Math.PI * 2)
          ctx.fill()
        }
      }

      // Particles
      for (const pt of g.particles) {
        ctx.globalAlpha = pt.life / 30
        ctx.fillStyle = pt.color
        ctx.beginPath()
        ctx.arc(pt.x, pt.y, pt.r, 0, Math.PI * 2)
        ctx.fill()
      }
      ctx.globalAlpha = 1

      // HUD
      ctx.fillStyle = '#fff'
      ctx.font = "bold 14px 'Fredoka One', cursive"
      ctx.textAlign = 'left'
      ctx.fillText(`Lv ${g.level}`, 10, H - 10)
      ctx.textAlign = 'right'
      ctx.fillText(`${g.score}`, W - 10, H - 10)

      // Power-up timer bars
      const now = Date.now()
      const activeEffects = []
      if (g.effects.fireball > now) activeEffects.push({ emoji: '🔥', color: '#FF4500', pct: (g.effects.fireball - now) / 8000 })
      if (g.effects.wide > now) activeEffects.push({ emoji: '📏', color: '#00CEC9', pct: (g.effects.wide - now) / 10000 })
      if (g.effects.magnet > now) activeEffects.push({ emoji: '🧲', color: '#FDCB6E', pct: (g.effects.magnet - now) / 8000 })
      if (g.effects.laser > now) activeEffects.push({ emoji: '🔫', color: '#FF4757', pct: (g.effects.laser - now) / 8000 })
      if (activeEffects.length > 0) {
        const barW = 60, barH = 6, barY = H - 28
        const startX = (W - activeEffects.length * (barW + 24)) / 2
        for (let i = 0; i < activeEffects.length; i++) {
          const eff = activeEffects[i]
          const x = startX + i * (barW + 24)
          ctx.font = '11px serif'
          ctx.textAlign = 'left'
          ctx.fillText(eff.emoji, x, barY + 5)
          ctx.fillStyle = 'rgba(255,255,255,0.15)'
          ctx.fillRect(x + 16, barY, barW, barH)
          ctx.fillStyle = eff.color
          ctx.shadowColor = eff.color
          ctx.shadowBlur = 4
          ctx.fillRect(x + 16, barY, barW * Math.min(eff.pct, 1), barH)
          ctx.shadowBlur = 0
          ctx.fillStyle = '#fff'
        }
      }

      // Idle text
      if (phaseRef.current === 'idle') {
        ctx.fillStyle = 'rgba(0,0,0,0.4)'
        ctx.fillRect(0, H / 2 - 30, W, 60)
        ctx.fillStyle = '#fff'
        ctx.font = "bold 18px 'Fredoka One', cursive"
        ctx.textAlign = 'center'
        ctx.fillText('TAP UNTUK MULAI', W / 2, H / 2 + 6)
      }
    }

    animRef.current = requestAnimationFrame(loop)

    return () => {
      cancelAnimationFrame(animRef.current)
      canvas.removeEventListener('mousemove', onMouseMove)
      canvas.removeEventListener('touchstart', onTouchStart)
      canvas.removeEventListener('touchmove', onTouchMove)
      canvas.removeEventListener('touchend', onTouchEnd)
      canvas.removeEventListener('click', onClick)
    }
  }, [difficulty.id, rzKey])

  const restart = () => {
    const canvas = canvasRef.current
    if (!canvas) return
    const parent = canvas.parentElement
    const rect = parent ? parent.getBoundingClientRect() : canvas.getBoundingClientRect()
    const W = Math.floor(rect.width) || window.innerWidth
    const H = Math.floor(rect.height) || window.innerHeight
    gameRef.current = initGame(W, H, 1)
    gameRef.current.lives = cfg.lives
    gameRef.current.score = 0
    setPhase('idle')
    setScore(0)
    setLives(cfg.lives)
    setLevel(1)
    setCombo(0)
    setShowConfetti(false)
  }

  // Stars calc
  const getStars = () => {
    if (phase !== 'won') return 0
    const g = gameRef.current
    if (!g) return 1
    return g.lives >= cfg.lives ? 3 : g.lives >= cfg.lives - 1 ? 2 : 1
  }

  const stars = getStars()
  const coinReward = phase === 'won'
    ? ({ easy: 30, medium: 50, hard: 80 }[difficulty.id] || 30) + Math.floor(score / 200) + (stars === 3 ? 30 : 0)
    : Math.max(5, Math.floor(score / 100))

  const DIFF_LABEL = { easy: '🟢 Mudah', medium: '🟡 Sedang', hard: '🔴 Sulit' }

  return (
    <div style={{
      width: '100%', height: typeof CSS !== 'undefined' && CSS.supports('height','100dvh') ? '100dvh' : '100vh',
      background: '#0a0a2e', position: 'relative', overflow: 'hidden', userSelect: 'none',
      fontFamily: "'Fredoka One', cursive",
    }}>
      {showTutorial && (
        <TutorialModal steps={TUTORIAL_STEPS} storageKey="bp_tut_brick-breaker"
          onClose={() => setShowTutorial(false)} />
      )}
      {showConfetti && <Confetti />}

      {/* Top HUD */}
      <div style={{
        position: 'absolute', top: 0, left: 0, right: 0, zIndex: 10,
        display: 'flex', justifyContent: 'space-between', alignItems: 'center',
        padding: '8px 14px', background: 'rgba(0,0,0,0.4)',
      }}>
        <button onClick={onBack} style={{
          background: 'rgba(255,255,255,0.1)', border: '1px solid rgba(255,255,255,0.2)',
          color: '#fff', borderRadius: 8, padding: '6px 12px', fontSize: 14, cursor: 'pointer',
        }}>←</button>
        <div style={{ display: 'flex', gap: 14, alignItems: 'center', color: '#fff', fontSize: 13 }}>
          <span>🧱 Lv {level}</span>
          <span>💯 {score.toLocaleString()}</span>
          <span>{'❤️'.repeat(Math.max(0, lives))}</span>
          {combo > 2 && <span style={{ color: '#FDCB6E' }}>🔥 x{combo}</span>}
        </div>
      </div>

      {/* Boss HP bar */}
      {bossHP > 0 && (
        <div style={{
          position: 'absolute', top: 44, left: 20, right: 20, zIndex: 10,
          height: 8, background: 'rgba(0,0,0,0.5)', borderRadius: 4,
        }}>
          <div style={{
            height: '100%', borderRadius: 4,
            width: `${(bossHP / bossMaxHP) * 100}%`,
            background: bossHP / bossMaxHP > 0.5 ? '#00B894' : bossHP / bossMaxHP > 0.25 ? '#FDCB6E' : '#FF4757',
            transition: 'width 0.2s',
          }} />
          <div style={{
            position: 'absolute', top: -2, left: '50%', transform: 'translateX(-50%)',
            color: '#fff', fontSize: 10, fontWeight: 800,
          }}>
            👾 BOSS — HP {bossHP}/{bossMaxHP}
          </div>
        </div>
      )}

      <div style={{ position: 'absolute', inset: 0, zIndex: 1 }}>
        <canvas ref={canvasRef} style={{ width: '100%', height: '100%', display: 'block', touchAction: 'none' }} />
      </div>

      {phase === 'won' && (
        <WinModal
          emoji="🏆"
          title="Level Clear!"
          subtitle={`${cfg.maxLevel} level terselesaikan!`}
          diffLabel={DIFF_LABEL[difficulty.id]}
          stats={[
            { label: 'Skor', value: score.toLocaleString(), color: '#A29BFE' },
            { label: 'Level', value: `Lv ${level}`, color: '#00B894' },
            { label: 'Nyawa', value: String(lives), color: '#FF6B6B' },
          ]}
          stars={stars}
          coinReward={coinReward}
          onRestart={restart}
          onBack={onBack}
          onHome={onHome}
          dark={tc.dark}
          gameColor="#FF6B6B"
        />
      )}
      {phase === 'lost' && (
        <LoseModal
          emoji="💥"
          title="Game Over"
          subtitle={`Sampai Level ${level}`}
          diffLabel={DIFF_LABEL[difficulty.id]}
          stats={[
            { label: 'Skor', value: score.toLocaleString(), color: '#A29BFE' },
            { label: 'Level', value: `Lv ${level}`, color: '#00B894' },
            { label: 'Nyawa', value: String(lives), color: '#FF6B6B' },
          ]}
          coinReward={coinReward}
          onRestart={restart}
          onBack={onBack}
          onHome={onHome}
          dark={tc.dark}
          gameColor="#FF6B6B"
        />
      )}
    </div>
  )
}

import TutorialModal from '../../components/TutorialModal.jsx'
import Confetti from '../../components/Confetti.jsx'
import { useState, useEffect, useCallback, useRef, useMemo } from 'react'
import { useSettings } from '../../context/SettingsContext.jsx'
import { useThemeColors } from '../../hooks/useThemeColors.js'
import { useSound } from '../../hooks/useSound.js'
import { useProgress } from '../../context/ProgressContext.jsx'
import { useCoins } from '../../context/CoinContext.jsx'
import { WinModal } from '../../components/GameLayout.jsx'

const TUTORIAL_STEPS = [
  { emoji:'🧪', title:'Color Sort', desc:'Urutkan bola warna ke dalam tabung yang tepat! Setiap tabung harus berisi satu warna saja.', tip:'Gunakan tabung kosong sebagai tempat transit sementara.' },
  { emoji:'👆', title:'Cara Main', desc:'Klik tabung sumber untuk mengambil bola paling atas, lalu klik tabung tujuan untuk meletakkannya.', tip:'Bola hanya bisa diletakkan di tabung yang kosong atau yang warna paling atasnya sama.' },
  { emoji:'⭐', title:'Sistem Bintang', desc:'Semakin sedikit langkah yang kamu pakai, semakin banyak bintang! Minimalisir perpindahan untuk 3 bintang.', tip:'Easy ≤20 langkah, Medium ≤30, Hard ≤45 untuk 3 bintang.' },
]

const COLORS = [
  { id: 'red',    hex: '#FF6B6B', name: 'Merah'   },
  { id: 'blue',   hex: '#74B9FF', name: 'Biru'     },
  { id: 'green',  hex: '#00B894', name: 'Hijau'    },
  { id: 'yellow', hex: '#FDCB6E', name: 'Kuning'   },
  { id: 'purple', hex: '#A29BFE', name: 'Ungu'     },
  { id: 'orange', hex: '#E17055', name: 'Oranye'   },
  { id: 'pink',   hex: '#FD79A8', name: 'Pink'     },
  { id: 'cyan',   hex: '#00CEC9', name: 'Cyan'     },
  { id: 'brown',  hex: '#B47B56', name: 'Cokelat'  },
  { id: 'lime',   hex: '#BADC58', name: 'Hijau Muda' },
]

const TUBE_CAPACITY = 4
const DIFF_CONFIG = {
  easy:   { colorCount: 4, emptyTubes: 2 },
  medium: { colorCount: 6, emptyTubes: 2 },
  hard:   { colorCount: 8, emptyTubes: 2 },
}

function shuffle(arr) {
  const a = [...arr]
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]]
  }
  return a
}

function generatePuzzle(diffId) {
  const config = DIFF_CONFIG[diffId] || DIFF_CONFIG.easy
  const { colorCount, emptyTubes } = config
  const colors = COLORS.slice(0, colorCount)

  // Create balls: 4 of each color
  let balls = []
  for (const color of colors) {
    for (let i = 0; i < TUBE_CAPACITY; i++) {
      balls.push(color.id)
    }
  }
  balls = shuffle(balls)

  // Distribute into tubes
  const tubes = []
  for (let i = 0; i < colorCount; i++) {
    tubes.push(balls.slice(i * TUBE_CAPACITY, (i + 1) * TUBE_CAPACITY))
  }
  // Add empty tubes
  for (let i = 0; i < emptyTubes; i++) {
    tubes.push([])
  }

  return tubes
}

function isSorted(tube) {
  if (tube.length !== TUBE_CAPACITY) return false
  return tube.every(b => b === tube[0])
}

function isPuzzleSolved(tubes) {
  return tubes.every(t => t.length === 0 || isSorted(t))
}

function canPour(from, to) {
  if (from.length === 0) return false
  if (to.length >= TUBE_CAPACITY) return false
  if (to.length === 0) return true
  return from[from.length - 1] === to[to.length - 1]
}

function getColorHex(colorId) {
  const c = COLORS.find(c => c.id === colorId)
  return c ? c.hex : '#888'
}

function useTimer(running, resetKey) {
  const [time, setTime] = useState(0)
  useEffect(() => { setTime(0) }, [resetKey])
  useEffect(() => {
    if (!running) return
    const id = setInterval(() => setTime(t => t + 1), 1000)
    return () => clearInterval(id)
  }, [running])
  return time
}

const formatTime = (s) =>
  `${Math.floor(s/60).toString().padStart(2,'0')}:${(s%60).toString().padStart(2,'0')}`

const DIFF_LABEL = { easy: '🟢 Mudah', medium: '🟡 Sedang', hard: '🔴 Sulit' }

export default function ColorSortGame({ onBack, onHome, game, difficulty }) {
  const tc = useThemeColors()
  const dark = tc.dark
  const { play } = useSound()
  const { reportGameResult } = useProgress()
  const { earnCoins, getActiveTubeTheme } = useCoins()
  const tubeTheme = getActiveTubeTheme ? getActiveTubeTheme() : null

  const [tubes, setTubes] = useState(() => generatePuzzle(difficulty.id))
  const [selectedTube, setSelectedTube] = useState(null)
  const [moves, setMoves] = useState(0)
  const [won, setWon] = useState(false)
  const [showTutorial, setShowTutorial] = useState(() => !localStorage.getItem('bp_tut_color-sort'))
  const [showConfetti, setShowConfetti] = useState(false)
  const [resetKey, setResetKey] = useState(0)
  const [history, setHistory] = useState([]) // for undo
  const [animatingTube, setAnimatingTube] = useState(null)

  const isGameActive = !won
  const timerRunning = isGameActive && moves > 0
  const time = useTimer(timerRunning, resetKey)

  const bestKey = `colorsort-best-${difficulty.id}`
  const [bestMoves, setBestMoves] = useState(() => parseInt(localStorage.getItem(bestKey) || '0'))

  // Check win
  useEffect(() => {
    if (won || moves === 0) return
    if (isPuzzleSolved(tubes)) {
      setWon(true)
      setShowConfetti(true)
      play('win')

      if (bestMoves === 0 || moves < bestMoves) {
        localStorage.setItem(bestKey, moves)
        setBestMoves(moves)
      }

      const starThresholds = { easy: 20, medium: 30, hard: 45 }
      const threshold = starThresholds[difficulty.id] || 20
      const stars = moves <= threshold ? 3 : moves <= threshold * 1.5 ? 2 : 1
      reportGameResult({
        gameId: 'color-sort',
        difficultyId: difficulty.id,
        won: true,
        score: Math.max(0, 500 - moves * 5),
        stars,
        timeSec: time,
      })
      const coinReward = { easy: 15, medium: 25, hard: 40 }
      let coinAmount = coinReward[difficulty.id] || 15
      if (stars === 3) coinAmount += 20
      earnCoins(coinAmount, `Menang Color Sort (${difficulty.id})`)
    }
  }, [tubes, moves])

  const { winStars, winCoinAmount } = useMemo(() => {
    if (!won) return { winStars: 0, winCoinAmount: 0 }
    const starThresholds = { easy: 20, medium: 30, hard: 45 }
    const threshold = starThresholds[difficulty.id] || 20
    const stars = moves <= threshold ? 3 : moves <= threshold * 1.5 ? 2 : 1
    const coinReward = { easy: 15, medium: 25, hard: 40 }
    let coinAmount = coinReward[difficulty.id] || 15
    if (stars === 3) coinAmount += 20
    return { winStars: stars, winCoinAmount: coinAmount }
  }, [won, moves, difficulty.id])

  const handleTubeClick = useCallback((tubeIndex) => {
    if (won) return

    if (selectedTube === null) {
      // Select source tube
      if (tubes[tubeIndex].length === 0) return
      if (isSorted(tubes[tubeIndex])) return // already sorted, skip
      play('click')
      setSelectedTube(tubeIndex)
    } else if (selectedTube === tubeIndex) {
      // Deselect
      play('click')
      setSelectedTube(null)
    } else {
      // Try to pour
      if (canPour(tubes[selectedTube], tubes[tubeIndex])) {
        play('match')
        setHistory(h => [...h, tubes.map(t => [...t])])
        setAnimatingTube(tubeIndex)

        const newTubes = tubes.map(t => [...t])
        const ball = newTubes[selectedTube].pop()
        newTubes[tubeIndex].push(ball)
        setTubes(newTubes)
        setMoves(m => m + 1)
        setSelectedTube(null)
        setTimeout(() => setAnimatingTube(null), 300)
      } else {
        play('mismatch')
        setSelectedTube(null)
      }
    }
  }, [selectedTube, tubes, won, play])

  const undo = () => {
    if (history.length === 0 || won) return
    play('click')
    const prev = history[history.length - 1]
    setTubes(prev)
    setHistory(h => h.slice(0, -1))
    setMoves(m => m - 1)
    setSelectedTube(null)
  }

  const restart = () => {
    play('click')
    setTubes(generatePuzzle(difficulty.id))
    setSelectedTube(null)
    setMoves(0)
    setWon(false)
    setShowConfetti(false)
    setHistory([])
    setAnimatingTube(null)
    setResetKey(k => k + 1)
  }

  // Theme
  const bg        = tc.bg
  const surface   = tc.surface
  const textMain  = tc.textMain
  const textMuted = tc.textMuted
  const borderCol = tc.borderCol
  const accent    = '#6C5CE7'

  const config = DIFF_CONFIG[difficulty.id] || DIFF_CONFIG.easy

  return (
    <div style={{ maxWidth: 700, margin: '0 auto', padding: '32px 20px 60px', background: bg, minHeight: '100dvh', transition: 'background 0.3s' }}>
      <style>{`
        @keyframes tubeCompletePulse {
          0% { transform: scale(1); filter: brightness(1); }
          50% { transform: scale(1.1); filter: brightness(1.4) drop-shadow(0 0 15px #FFD93D); }
          100% { transform: scale(1); filter: brightness(1.1); }
        }
      `}</style>
      {showTutorial && <TutorialModal steps={TUTORIAL_STEPS} color={accent} onClose={() => { setShowTutorial(false); localStorage.setItem("bp_tut_color-sort","1") }} />}
      <Confetti active={showConfetti} onDone={() => setShowConfetti(false)} />

      {/* Header */}
      <div style={{ display: 'flex', alignItems: 'center', gap: 12, marginBottom: 24 }}>
        <button onClick={() => { play('click'); onBack() }}
          style={{ background: surface, border: `2px solid ${borderCol}`, borderRadius: 12, padding: '8px 14px', fontSize: 18, cursor: 'pointer', color: textMain }}>
          ←
        </button>
        <div style={{ flex: 1 }}>
          <h1 style={{ fontFamily: "'Fredoka One',cursive", fontSize: 26, color: textMain, lineHeight: 1 }}>
            🧪 Color Sort
          </h1>
          <p style={{ fontSize: 13, color: textMuted, marginTop: 2 }}>
            Urutkan {config.colorCount} warna ke tabung yang tepat!
          </p>
        </div>
        <span style={{ background: difficulty.id === 'easy' ? '#E8F8F0' : difficulty.id === 'medium' ? '#FFFBF0' : '#FFF0F0', color: difficulty.id === 'easy' ? '#00b894' : difficulty.id === 'medium' ? '#f9a825' : '#FF6B6B', border: `2px solid ${difficulty.id === 'easy' ? '#00b89444' : difficulty.id === 'medium' ? '#f9a82544' : '#FF6B6B44'}`, borderRadius: 100, padding: '6px 14px', fontFamily: "'Fredoka One',cursive", fontSize: 13, whiteSpace: 'nowrap' }}>
          {DIFF_LABEL[difficulty.id]}
        </span>
      </div>

      {/* Stats */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3,1fr)', gap: 12, marginBottom: 24 }}>
        {[
          { label: '🎯 Langkah', value: moves, color: '#6C5CE7' },
          { label: '⏱ Waktu', value: formatTime(time), color: '#4ECDC4' },
          { label: '🧪 Tabung', value: `${tubes.filter(t => isSorted(t)).length}/${config.colorCount}`, color: '#FF6B6B' },
        ].map(s => (
          <div key={s.label} style={{ background: surface, border: `2px solid ${s.color}33`, borderRadius: 16, padding: '12px 16px', textAlign: 'center' }}>
            <div style={{ fontFamily: "'Fredoka One',cursive", fontSize: 26, color: s.color, lineHeight: 1 }}>{s.value}</div>
            <div style={{ fontSize: 12, color: textMuted, marginTop: 3, fontWeight: 600 }}>{s.label}</div>
          </div>
        ))}
      </div>

      {/* Tubes */}
      <div style={{
        display: 'flex', justifyContent: 'center', gap: config.colorCount > 6 ? 8 : 12,
        flexWrap: 'wrap', marginBottom: 28, padding: '0 8px',
      }}>
        {tubes.map((tube, ti) => {
          const isSelected = selectedTube === ti
          const isFull = isSorted(tube)
          const isAnimating = animatingTube === ti

          return (
            <div key={ti} onClick={() => handleTubeClick(ti)}
              style={{
                cursor: won ? 'default' : 'pointer',
                transform: isSelected ? 'translateY(-12px) scale(1.05)' : isAnimating ? 'scale(1.03)' : 'scale(1)',
                transition: 'all 0.25s cubic-bezier(0.4,0,0.2,1)',
                filter: isFull ? 'brightness(1.1)' : 'none',
                animation: isFull ? 'tubeCompletePulse 0.5s ease-out' : 'none',
              }}>
              {/* Tube container */}
              <div style={{
                width: config.colorCount > 6 ? 44 : 52,
                height: config.colorCount > 6 ? 160 : 180,
                borderRadius: tubeTheme?.shape === 'bubble' ? '12px 12px 26px 26px' : tubeTheme?.shape === 'flask' ? '4px 4px 22px 22px' : tubeTheme?.shape === 'bamboo' ? '4px 4px 12px 12px' : tubeTheme?.shape === 'crystal' ? '8px 8px 16px 16px' : '0 0 20px 20px',
                borderLeft: `3px solid ${isSelected ? accent : tubeTheme?.border || (dark ? '#3d3561' : '#B2BEC3')}`,
                borderRight: `3px solid ${isSelected ? accent : tubeTheme?.border || (dark ? '#3d3561' : '#B2BEC3')}`,
                borderBottom: `3px solid ${isSelected ? accent : tubeTheme?.border || (dark ? '#3d3561' : '#B2BEC3')}`,
                background: tubeTheme?.tube || (dark ? '#0f0f23' : '#F8F9FA'),
                display: 'flex', flexDirection: 'column-reverse',
                padding: 3,
                gap: 2,
                position: 'relative',
                boxShadow: isSelected ? `0 8px 20px ${accent}44` : isFull ? `0 4px 12px ${getColorHex(tube[0])}44` : '0 2px 8px rgba(0,0,0,0.08)',
              }}>
                {/* Balls */}
                {tube.map((ball, bi) => (
                  <div key={bi} style={{
                    width: '100%',
                    flex: 1,
                    borderRadius: 12,
                    background: `linear-gradient(145deg, ${getColorHex(ball)}, ${getColorHex(ball)}dd)`,
                    boxShadow: `inset 0 -2px 4px rgba(0,0,0,0.15), inset 0 2px 4px rgba(255,255,255,0.25)`,
                    transition: 'all 0.3s',
                  }} />
                ))}
                {/* Empty slots */}
                {Array(TUBE_CAPACITY - tube.length).fill(null).map((_, i) => (
                  <div key={`empty-${i}`} style={{
                    width: '100%', flex: 1,
                    borderRadius: 12,
                    background: 'transparent',
                  }} />
                ))}
                {/* Completed check */}
                {isFull && (
                  <div style={{
                    position: 'absolute', top: -14, left: '50%', transform: 'translateX(-50%)',
                    fontSize: 16, filter: 'drop-shadow(0 2px 4px rgba(0,0,0,0.2))',
                  }}>✅</div>
                )}
              </div>
            </div>
          )
        })}
      </div>

      {/* Buttons */}
      <div style={{ display: 'flex', justifyContent: 'center', gap: 10, flexWrap: 'wrap' }}>
        <button onClick={restart}
          style={{ background: accent, color: '#fff', border: 'none', borderRadius: 100, padding: '12px 28px', fontSize: 15, fontWeight: 800, fontFamily: "'Fredoka One',cursive", cursor: 'pointer', boxShadow: `0 4px 14px ${accent}44` }}>
          🔄 Main Lagi
        </button>
        <button onClick={undo} disabled={history.length === 0 || won}
          style={{ background: history.length === 0 || won ? 'rgba(255,255,255,0.05)' : 'rgba(255,211,61,0.15)', color: history.length === 0 || won ? textMuted : '#FFD93D', border: `2px solid ${history.length === 0 || won ? borderCol : '#FFD93D44'}`, borderRadius: 100, padding: '12px 18px', fontSize: 14, fontWeight: 800, fontFamily: "'Fredoka One',cursive", cursor: history.length === 0 || won ? 'default' : 'pointer' }}>
          ↩️ Undo
        </button>
        <button onClick={() => { play('click'); onBack() }}
          style={{ background: surface, color: textMuted, border: `2px solid ${borderCol}`, borderRadius: 100, padding: '12px 18px', fontSize: 14, fontWeight: 700, fontFamily: "'Fredoka One',cursive", cursor: 'pointer' }}>
          🎯 Level
        </button>
      </div>

      {/* Best record */}
      {bestMoves > 0 && (
        <div style={{ marginTop: 20, background: dark ? '#1f1f3e' : '#FFF9F0', border: `2px solid ${dark ? '#3d3561' : '#FFE66D'}`, borderRadius: 16, padding: '12px 20px', textAlign: 'center', fontSize: 14, color: textMuted, fontWeight: 600 }}>
          🏆 Rekor {DIFF_LABEL[difficulty.id]}: <span style={{ color: accent, fontFamily: "'Fredoka One',cursive", fontSize: 16 }}>{bestMoves} langkah</span>
        </div>
      )}

      {won && (
        <WinModal
          title="Selamat!"
          subtitle="Semua warna berhasil diurutkan!"
          diffLabel={DIFF_LABEL[difficulty.id]}
          stats={[
            { label: 'Langkah', value: String(moves), color: '#6C5CE7' },
            { label: 'Waktu', value: formatTime(time), color: '#4ECDC4' },
          ]}
          stars={winStars}
          coinReward={winCoinAmount}
          onRestart={restart}
          onBack={() => { play('click'); onBack() }}
          onHome={() => { play('click'); onHome?.() }}
          dark={dark}
          gameColor={game?.color || accent}
        />
      )}
    </div>
  )
}

