// ═══════════════════════════════════════════════
// TILE DEFINITIONS — source rects from tileset.png (256×752, 16px tiles)
// [col, row] → pixel position = [col*16, row*16]
// ═══════════════════════════════════════════════
const TS = 16 // tile pixel size in tileset
const t = (c, r) => [c * TS, r * TS, TS, TS] // helper

const MAP_W = 50
const MAP_H = 40
const TILE_SIZE = 16
const SCALE = 3

// Tile type IDs for map
const _ = 0  // grass
