// Fence
const T_FENCE_V   = t(5, 7)   // fence vertical
const T_FENCE_H   = t(6, 7)   // fence horizontal
const T_FENCE_TL  = t(5, 8)   // fence corner TL
const T_FENCE_TR  = t(7, 8)   // fence corner TR
