  'MASA','NAGA','PETA','SENI','TARI','BESI','DESA','HARI','KAIN','RODA',
]
const WORDS_5 = [
  'BUNGA','POHON','MURID','LAPAR','DUDUK','LEMBU','ORGAN','HUJAN','ANGIN',
  'PANAS','BADAI','SALJU','MERAH','KULIT','BULAN','SURAT','RUMAH','MOBIL',
