  'LAWAN','JALUR','PESTA','ZAKAT','KURSI','SAWAH','TANAH','ASPAL','TIMUR',
]
const WORDS_6 = [
  'BERAPA','DATANG','GLOBAL','JANGAN','KARENA','LASKAR','PALING','RAHMAT',
  'SAMPAI','TAMBAH','ZIARAH','BANGSA','CAHAYA','DAMPAK','FAKTOR','GALANG',
