].filter(w => w.length === 6) // safety filter
const WORDS_7 = [
  'BELAJAR','MEMBACA','MENULIS','BERMAIN','BERLARI','BERTAMU','DATARAN',
  'EDUKASI','FANTASI','GERAKAN','HARAPAN','ILMUWAN','JUTAWAN','LAMARAN',
