// ─── Configuration ──────────────────────────────────────────────────────────
const CFG = {
  easy:   { timePerQ: 15, lives: 5, startLevel: 1, correctToLevel: 5, targetLevel: 8 },
  medium: { timePerQ: 10, lives: 4, startLevel: 1, correctToLevel: 5, targetLevel: 10 },
  hard:   { timePerQ: 7,  lives: 3, startLevel: 2, correctToLevel: 5, targetLevel: 12 },
}

// ─── Question Generator ──────────────────────────────────────────────────────
function randInt(min, max) { return Math.floor(Math.random() * (max - min + 1)) + min }

function generateQuestion(level) {
  let a, b, c, op, answer, display

  if (level <= 2) {
    a = level === 1 ? randInt(1, 9) : randInt(10, 50)
    b = level === 1 ? randInt(1, 9) : randInt(1, 30)
    if (Math.random() < 0.5) { op = '+'; answer = a + b; display = `${a} + ${b}` }
    else { if (a < b) [a, b] = [b, a]; op = '−'; answer = a - b; display = `${a} − ${b}` }
  } else if (level <= 4) {
    const r = Math.random()
    if (r < 0.3) {
      a = randInt(10, 99); b = randInt(1, 50)
      if (Math.random() < 0.5) { answer = a + b; display = `${a} + ${b}` }
      else { if (a < b) [a, b] = [b, a]; answer = a - b; display = `${a} − ${b}` }
    } else if (r < 0.7 || level < 4) {
      a = randInt(2, 12); b = randInt(2, 12); answer = a * b; display = `${a} × ${b}`
    } else {
      b = randInt(2, 12); answer = randInt(2, 12); a = b * answer; display = `${a} ÷ ${b}`
    }
  } else if (level <= 6) {
    const r = Math.random()
    if (r < 0.25) {
      a = randInt(11, 25); b = randInt(2, 9); answer = a * b; display = `${a} × ${b}`
    } else if (r < 0.5) {
      b = randInt(3, 15); answer = randInt(2, 15); a = b * answer; display = `${a} ÷ ${b}`
    } else if (r < 0.75) {
      a = randInt(50, 200); b = randInt(20, 99)
      if (Math.random() < 0.5) { answer = a + b; display = `${a} + ${b}` }
      else { if (a < b) [a, b] = [b, a]; answer = a - b; display = `${a} − ${b}` }
    } else {
      a = randInt(2, 9); b = randInt(2, 9); c = randInt(1, 20)
      if (Math.random() < 0.5) { answer = a * b + c; display = `${a} × ${b} + ${c}` }
      else { answer = a * b - c; if (answer < 0) { c = randInt(1, a*b-1); answer = a*b-c }; display = `${a} × ${b} − ${c}` }
    }
  } else {
    const r = Math.random()
    if (r < 0.3) {
      a = randInt(10, 30); b = randInt(2, 9); c = randInt(10, 50); answer = a * b + c; display = `${a} × ${b} + ${c}`
    } else if (r < 0.5) {
      a = randInt(10, 30); b = randInt(2, 9); c = randInt(1, 30)
      const product = a * b
      if (product > c) { answer = product - c; display = `${a} × ${b} − ${c}` }
      else { answer = product + c; display = `${a} × ${b} + ${c}` }
    } else if (r < 0.7) {
      a = randInt(5, 15); b = randInt(1, 30); answer = a * a + b; display = `${a}² + ${b}`
    } else if (r < 0.85) {
      a = randInt(5, 20); b = randInt(3, 15); c = randInt(2, 6); answer = (a + b) * c; display = `(${a} + ${b}) × ${c}`
    } else {
      b = randInt(5, 25); answer = randInt(3, 20); a = b * answer; display = `${a} ÷ ${b}`
    }
  }

  const wrongAnswers = new Set()
  while (wrongAnswers.size < 3) {
    const deviation = Math.max(3, Math.floor(Math.abs(answer) * 0.3))
    let wrong = answer + randInt(-deviation, deviation)
    if (wrong === answer) wrong = answer + (Math.random() < 0.5 ? 1 : -1) * randInt(1, deviation)
    if (wrong !== answer && !wrongAnswers.has(wrong)) wrongAnswers.add(wrong)
  }
  const options = [answer, ...wrongAnswers].sort(() => Math.random() - 0.5)
  return { display, answer, options }
}

function getComboMultiplier(streak) {
  if (streak >= 10) return 3
  if (streak >= 5)  return 2
  if (streak >= 3)  return 1.5
  return 1
}
function getComboLabel(streak) {
  if (streak >= 10) return '🔥 UNSTOPPABLE ×3'
  if (streak >= 5)  return '⚡ ON FIRE ×2'
  if (streak >= 3)  return '✨ COMBO ×1.5'
  return ''
}
function getComboColor(streak) {
  if (streak >= 10) return '#FF3838'
  if (streak >= 5)  return '#E17055'
  if (streak >= 3)  return '#FDCB6E'
  return '#888'
}

const LEVEL_NAMES = ['', 'Pemula', 'Dasar', 'Terampil', 'Mahir', 'Ahli', 'Master', 'Grandmaster', 'Genius', 'Legenda', 'Mythic', 'Transcendent', 'Infinity']

export default function MathChallenge({ onBack, onHome, game, difficulty, multiplayerMatch }) {
  // 1. Hooks & Basic Identity
  const { darkMode } = useSettings()
  const { play } = useSound()
  const { reportGameResult } = useProgress()
  const { earnCoins } = useCoins()
  const matchCtx = useMatch() || {}
  const { updateMatchState, finishMatch, setActiveMatch } = matchCtx
  const { uid: userId, photoURL } = useAuth()
  const tc = useThemeColors()
  const diff = CFG[difficulty?.id] || CFG.easy

  // 2. Theme Colors (Define early so all returns & callbacks can use them)
  const bg = tc.bg
  const surface = tc.surface
  const textMain = tc.textMain
  const textMuted = tc.textMuted
  const accent = '#6C5CE7'
  const accentLight = '#A29BFE'

  // 3. State
  const [phase, setPhase] = useState('tutorial')
  const [level, setLevel] = useState(diff.startLevel)
  const [lives, setLives] = useState(diff.lives)
  const [score, setScore] = useState(0)
  const [totalCorrect, setTotalCorrect] = useState(0)
  const [totalWrong, setTotalWrong] = useState(0)
  const [totalAnswered, setTotalAnswered] = useState(0)
  const [streak, setStreak] = useState(0)
  const [bestStreak, setBestStreak] = useState(0)
  const [correctInLevel, setCorrectInLevel] = useState(0)
  const [question, setQuestion] = useState(null)
  const [timeLeft, setTimeLeft] = useState(diff.timePerQ)
  const [feedback, setFeedback] = useState(null)
  const [selectedAnswer, setSelectedAnswer] = useState(null)
  const [showLevelUp, setShowLevelUp] = useState(false)
  const [showConfetti, setShowConfetti] = useState(false)
  const [gameOverReason, setGameOverReason] = useState('')

  // 4. Multiplayer Status
  const isMultiplayer = !!multiplayerMatch
  const myUid = userId || auth.currentUser?.uid
  const opponentUid = isMultiplayer ? (multiplayerMatch.hostUid === myUid ? multiplayerMatch.guestUid : multiplayerMatch.hostUid) : null
  const opponentData = isMultiplayer ? (multiplayerMatch.state?.[opponentUid] || { score: 0, level: 1, finished: false }) : null
  const opponentProfile = isMultiplayer ? (multiplayerMatch.hostUid === myUid ? multiplayerMatch.guestProfile : multiplayerMatch.hostProfile) : null
  const opponentEmote = isMultiplayer ? opponentData?.emote : null
  const myEmoteData = isMultiplayer ? (multiplayerMatch.state?.[myUid]?.emote || null) : null

  // Send emote to opponent via match state
  const sendEmote = useCallback((emoji) => {
    if (!isMultiplayer || !multiplayerMatch?.id || !myUid) return
    const newState = {
      ...multiplayerMatch.state,
      [myUid]: { ...multiplayerMatch.state?.[myUid], emote: { emoji, ts: Date.now() } }
    }
    updateMatchState?.(multiplayerMatch.id, newState)
  }, [isMultiplayer, multiplayerMatch?.id, multiplayerMatch?.state, myUid, updateMatchState])

  // 5. Refs
  const timerRef = useRef(null)
  const feedbackTimerRef = useRef(null)
  const levelUpTimerRef = useRef(null)
  const scoreRef = useRef(0)
  const levelRef = useRef(diff.startLevel)
  const livesRef = useRef(diff.lives)

  // 6. Ref Syncing
  useEffect(() => { scoreRef.current = score }, [score])
  useEffect(() => { levelRef.current = level }, [level])
  useEffect(() => { livesRef.current = lives }, [lives])

  // 7. Storage / Best Score
  const bestKey = `math-challenge-best-${difficulty?.id || 'easy'}`
  const [bestScore, setBestScore] = useState(() => {
    try { return parseInt(localStorage.getItem(bestKey)) || 0 } catch { return 0 }
  })
  const [bestLevel, setBestLevel] = useState(() => {
    try { return parseInt(localStorage.getItem(`${bestKey}-level`)) || 0 } catch { return 0 }
  })

  // 8. Callbacks (Ordered by dependency)
  const endGame = useCallback((reason) => {
    clearInterval(timerRef.current)
    clearTimeout(feedbackTimerRef.current)
    setGameOverReason(reason)
    setPhase('result')

    if (isMultiplayer && multiplayerMatch?.id && myUid) {
      const curScore = scoreRef.current
      const curLevel = levelRef.current
      const curLives = livesRef.current

      const newState = { 
        ...multiplayerMatch.state, 
        [myUid]: { 
          score: curScore, 
          level: curLevel, 
          finished: true, 
          lives: curLives,
          correct: totalCorrect,
          wrong: totalWrong
        } 
      }
      updateMatchState?.(multiplayerMatch.id, newState)

      // If opponent also finished, determine winner
      if (opponentData?.finished) {
        const winner = curScore > (opponentData?.score || 0) ? myUid
          : curScore < (opponentData?.score || 0) ? opponentUid : 'draw'
        finishMatch?.(multiplayerMatch.id, winner)
      }
    }

    if (reason === 'target') { setShowConfetti(true); play('win') }
    else { play('gameOver') }
  }, [play, isMultiplayer, multiplayerMatch?.id, multiplayerMatch?.state, opponentData, myUid, updateMatchState, finishMatch])

  const handleTimeout = useCallback((q) => {
    clearInterval(timerRef.current)
    play('error')
    setFeedback({ type: 'timeout', points: 0, answer: q.answer })
    setStreak(0)
    setTotalWrong(prev => prev + 1)
    setTotalAnswered(ta => ta + 1)

    if (isMultiplayer) {
      feedbackTimerRef.current = setTimeout(() => nextQuestion(), 1200)
    } else {
      setLives(prev => {
        const next = prev - 1
        if (next <= 0) {
          clearTimeout(feedbackTimerRef.current)
          feedbackTimerRef.current = setTimeout(() => endGame('lives'), 1200)
        } else {
          feedbackTimerRef.current = setTimeout(() => nextQuestion(), 1200)
        }
        return next
      })
    }
  }, [play, endGame, isMultiplayer])

  const nextQuestion = useCallback((lvl) => {
    const q = generateQuestion(lvl ?? level)
    setQuestion(q)
    setTimeLeft(diff.timePerQ)
    setSelectedAnswer(null)
    setFeedback(null)

    clearInterval(timerRef.current)
    const start = Date.now()
    timerRef.current = setInterval(() => {
      const elapsed = (Date.now() - start) / 1000
      const remaining = diff.timePerQ - elapsed
      if (remaining <= 0) {
        clearInterval(timerRef.current)
        setTimeLeft(0)
        handleTimeout(q)
      } else {
        setTimeLeft(remaining)
      }
    }, 50)
  }, [level, diff.timePerQ, handleTimeout])

  const handleAnswer = useCallback((selected) => {
    if (feedback || selectedAnswer !== null) return
    clearInterval(timerRef.current)
    setSelectedAnswer(selected)

    const isCorrect = selected === question.answer
    const timeBonus = Math.round(timeLeft * 10)

    if (isCorrect) {
      play('success')
      const newStreak = streak + 1
      const multi = getComboMultiplier(newStreak)
      const basePoints = 100 * level
      const points = Math.round((basePoints + timeBonus) * multi)

      setStreak(newStreak)
      setBestStreak(prev => Math.max(prev, newStreak))
      setScore(prev => prev + points)
      setTotalCorrect(prev => prev + 1)
      setTotalAnswered(prev => prev + 1)
      setTimeLeft(prev => Math.min(prev + 1.5, diff.timePerQ))
      setFeedback({ type: 'correct', points, timeBonus, multi })

      const newCorrectInLevel = correctInLevel + 1
      setCorrectInLevel(newCorrectInLevel)

      if (newCorrectInLevel >= diff.correctToLevel) {
        const newLevel = level + 1
        if (newLevel > diff.targetLevel) {
          feedbackTimerRef.current = setTimeout(() => endGame('target'), 1000)
        } else {
          feedbackTimerRef.current = setTimeout(() => {
            setLevel(newLevel); setCorrectInLevel(0); setShowLevelUp(true); play('levelUp')
            levelUpTimerRef.current = setTimeout(() => {
              setShowLevelUp(false); nextQuestion(newLevel)
            }, 1500)
          }, 800)
        }
      } else {
        feedbackTimerRef.current = setTimeout(() => nextQuestion(), 800)
      }
    } else {
      play('error')
      setStreak(0)
      setTotalWrong(prev => prev + 1)
      setTotalAnswered(prev => prev + 1)
      setFeedback({ type: 'wrong', points: 0, answer: question.answer })

      if (isMultiplayer) {
        feedbackTimerRef.current = setTimeout(() => nextQuestion(), 1200)
      } else {
        setLives(prev => {
          const next = prev - 1
          if (next <= 0) {
            feedbackTimerRef.current = setTimeout(() => endGame('lives'), 1200)
          } else {
            feedbackTimerRef.current = setTimeout(() => nextQuestion(), 1200)
          }
          return next
        })
      }
    }
  }, [feedback, selectedAnswer, question, streak, level, correctInLevel, timeLeft, play, diff, nextQuestion, endGame, isMultiplayer])

  const startGame = useCallback(() => {
    setPhase('playing')
    setLevel(diff.startLevel); setLives(diff.lives); setScore(0); setStreak(0)
    setBestStreak(0); setTotalCorrect(0); setTotalAnswered(0); setCorrectInLevel(0)
    setFeedback(null); setSelectedAnswer(null); setShowConfetti(false); setShowLevelUp(false); setGameOverReason('')
    nextQuestion(diff.startLevel)
  }, [diff, nextQuestion])

  const restart = useCallback(() => {
    if (isMultiplayer) { setActiveMatch?.(null); onBack() }
    else { setPhase('ready') }
  }, [isMultiplayer, setActiveMatch, onBack])

  // 9. Side Effects
  useEffect(() => {
    return () => {
      clearInterval(timerRef.current)
      clearTimeout(feedbackTimerRef.current)
      clearTimeout(levelUpTimerRef.current)
    }
  }, [])

  useEffect(() => {
    if (isMultiplayer && phase === 'ready') startGame()
  }, [isMultiplayer, phase, startGame])

  useEffect(() => {
    if (isMultiplayer && multiplayerMatch?.id && myUid) {
      const curScore = scoreRef.current
      const curCorrect = totalCorrect
      const newState = { 
        ...multiplayerMatch.state, 
        [myUid]: { score: curScore, totalCorrect: curCorrect, level, finished: false } 
      }
      updateMatchState?.(multiplayerMatch.id, newState)
    }
  }, [score, totalCorrect, level, isMultiplayer, myUid, multiplayerMatch?.id, updateMatchState])

  useEffect(() => {
    if (isMultiplayer && phase === 'playing') {
      if (multiplayerMatch?.status === 'cancelled') endGame('opponent_quit')
    }
  }, [multiplayerMatch?.status, isMultiplayer, phase, endGame])

  // PvP: if opponent finishes after us, determine winner
  useEffect(() => {
    if (phase !== 'result' || !isMultiplayer) return
    if (opponentData?.finished && multiplayerMatch?.status === 'active') {
      const winner = score > opponentData.score ? myUid
        : score < opponentData.score ? opponentUid : 'draw'
      finishMatch?.(multiplayerMatch.id, winner)
    }
  }, [opponentData?.finished, isMultiplayer, phase, score, myUid, opponentUid, multiplayerMatch?.id, multiplayerMatch?.status, finishMatch])

  useEffect(() => {
    if (phase !== 'result') return
    if (score > bestScore) { localStorage.setItem(bestKey, score.toString()); setBestScore(score) }
    if (level > bestLevel) { localStorage.setItem(`${bestKey}-level`, level.toString()); setBestLevel(level) }
    const coinReward = won ? Math.floor(score / 50) + stars * 5 : Math.floor(score / 100)
    if (coinReward > 0) earnCoins(coinReward, 'Math Challenge')
    reportGameResult({
      gameId: 'math-challenge', difficultyId: difficulty?.id || 'easy',
      score, stars, won: gameOverReason === 'target', timeSec: 0,
    })
  }, [phase])

  // 10. Styles & Computed
  const timerPct = (timeLeft / diff.timePerQ) * 100
  const timerColor = timerPct > 50 ? '#00B894' : timerPct > 25 ? '#FDCB6E' : '#FF6B6B'
  const won = gameOverReason === 'target'
  const stars = won ? (lives >= diff.lives ? 3 : lives >= Math.ceil(diff.lives / 2) ? 2 : 1) : 0

  // 11. Render logic
  if (phase === 'tutorial') return (
    <TutorialModal steps={TUTORIAL_STEPS} gameName="Math Challenge" onClose={() => setPhase('ready')} />
  )

  if (phase === 'ready') return (
    <div style={{ minHeight:'100dvh', background:bg, display:'flex', flexDirection:'column', alignItems:'center', justifyContent:'center', padding:20 }}>
      <div style={{ textAlign:'center', maxWidth:400 }}>
        <div style={{ fontSize:72, marginBottom:12 }}>🧮</div>
        <h1 style={{ fontFamily:"'Fredoka One',cursive", color:accent, fontSize:28, margin:'0 0 8px' }}>Math Challenge</h1>
        <p style={{ color:textMuted, fontSize:14, marginBottom:24, lineHeight:1.5 }}>
          Jawab soal matematika secepat mungkin!<br/>Capai Level {diff.targetLevel} untuk menang.
        </p>
        <div style={{ display:'flex', gap:16, justifyContent:'center', marginBottom:24, flexWrap:'wrap' }}>
          <div style={{ background:surface, borderRadius:12, padding:'12px 20px', textAlign:'center' }}>
            <div style={{ fontSize:20, fontWeight:700, color:accent }}>{diff.timePerQ}s</div>
            <div style={{ fontSize:11, color:textMuted }}>per soal</div>
          </div>
          <div style={{ background:surface, borderRadius:12, padding:'12px 20px', textAlign:'center' }}>
            <div style={{ fontSize:20, fontWeight:700, color:'#FF6B6B' }}>
              {isMultiplayer ? '✨' : '❤️'.repeat(diff.lives)}
            </div>
            <div style={{ fontSize:11, color:textMuted }}>{isMultiplayer ? 'Mode Kuis' : `${diff.lives} nyawa`}</div>
          </div>
          <div style={{ background:surface, borderRadius:12, padding:'12px 20px', textAlign:'center' }}>
            <div style={{ fontSize:20, fontWeight:700, color:'#00B894' }}>Lv{diff.targetLevel}</div>
            <div style={{ fontSize:11, color:textMuted }}>target</div>
          </div>
        </div>
        <button onClick={startGame} style={{
          fontFamily:"'Fredoka One',cursive", fontSize:18, padding:'14px 48px',
          background:`linear-gradient(135deg, ${accent}, ${accentLight})`, color:'#fff',
          border:'none', borderRadius:14, cursor:'pointer', boxShadow:`0 4px 20px ${accent}44`,
        }}>MULAI! 🚀</button>
        <div style={{ marginTop:16 }}>
          <button onClick={onBack} style={{ background:'none', border:'none', color:textMuted, cursor:'pointer', fontSize:14 }}>← Kembali</button>
        </div>
      </div>
    </div>
  )

  if (phase === 'result') {
    const accuracy = totalAnswered > 0 ? Math.round(totalCorrect / totalAnswered * 100) : 0
    const coinReward = won ? Math.floor(score / 50) + stars * 5 : Math.floor(score / 100)

    const duelStats = isMultiplayer ? [
      { label: 'Skor', myValue: score, oppValue: opponentData?.score || 0, color: '#6C5CE7' },
      { label: 'Benar', myValue: totalCorrect, oppValue: opponentData?.totalCorrect || 0, color: '#00B894' },
      { label: 'Level', myValue: level, oppValue: opponentData?.level || 1, color: '#A29BFE' },
    ] : null

    return (
      <div style={{ minHeight:'100dvh', background:bg }}>
        {showConfetti && <Confetti />}
        <WinModal
          emoji={won ? '🎉' : '💔'} title={won ? 'Luar biasa!' : 'Game over'}
          subtitle={won ? `Kamu mencapai level ${diff.targetLevel}!` : `Berhenti di level ${level} — ${LEVEL_NAMES[level] || 'Level ' + level}`}
          diffLabel={{ easy: '🟢 Mudah', medium: '🟡 Sedang', hard: '🔴 Sulit' }[difficulty?.id] || '🟢 Mudah'}
          stats={[
            { label: 'Skor', value: score.toLocaleString(), color: '#6C5CE7' },
            { label: 'Level', value: `${level} — ${LEVEL_NAMES[level] || ''}`, color: '#A29BFE' },
            { label: 'Benar', value: `${totalCorrect}/${totalAnswered}`, color: '#00B894' },
            { label: 'Akurasi', value: `${accuracy}%`, color: '#FDCB6E' },
            { label: 'Best streak', value: String(bestStreak), color: '#FD79A8' },
          ]}
          stars={won ? stars : 0} coinReward={coinReward}
          highlight={isMultiplayer ? (multiplayerMatch.winner === myUid ? '⚔️ KAMU MENANG!' : multiplayerMatch.winner === 'draw' ? '🤝 HASIL SERI!' : '💀 KAMU KALAH!') : ''}
          onRestart={restart} onBack={onBack} onHome={onHome} dark={darkMode} gameColor={accent}
          duelStats={duelStats}
          onRematch={isMultiplayer && multiplayerMatch?.winner ? () => matchCtx.requestRematch?.(multiplayerMatch) : null}
        />
        {isMultiplayer && (
          <div style={{ position:'fixed', top:20, width:'100%', textAlign:'center', zIndex:2000, pointerEvents:'none' }}>
             <div style={{ background: surface, padding:'8px 16px', borderRadius:20, display:'inline-flex', gap:20, border:`2px solid ${accent}`, boxShadow:'0 4px 20px rgba(0,0,0,0.2)' }}>
                <div><div style={{ fontSize:9, color:textMuted, fontWeight:800 }}>KAMU</div><div style={{ fontFamily:"'Fredoka One',cursive", color:accent, fontSize:14 }}>{score}</div></div>
                <div style={{ fontSize:16, opacity:0.3, alignSelf:'center' }}>VS</div>
                <div><div style={{ fontSize:9, color:textMuted, fontWeight:800 }}>{opponentProfile?.displayName?.toUpperCase() || 'LAWAN'}</div><div style={{ fontFamily:"'Fredoka One',cursive", color:'#FF6B6B', fontSize:14 }}>{opponentData?.score || 0}</div></div>
             </div>
          </div>
        )}
      </div>
    )
  }

  // Playing Phase
  const comboLabel = getComboLabel(streak)
  const comboColor = getComboColor(streak)
  const progressInLevel = (correctInLevel / diff.correctToLevel) * 100

  return (
    <div style={{ minHeight:'100dvh', background:bg, display:'flex', flexDirection:'column' }}>
      {isMultiplayer && (
        <PvpScoreBar
          opponentProfile={opponentProfile}
          opponentScore={opponentData?.score || 0}
          opponentProgress={Math.min(100, Math.round(((opponentData?.level - 1 || 0) * diff.correctToLevel + (opponentData?.totalCorrect % diff.correctToLevel || 0)) / (diff.targetLevel * diff.correctToLevel) * 100))}
          opponentExtra={`Lv.${opponentData?.level || 1}`}
          opponentFinished={opponentData?.finished}
          myScore={score}
          myProgress={Math.min(100, Math.round(((level - 1) * diff.correctToLevel + correctInLevel) / (diff.targetLevel * diff.correctToLevel) * 100))}
          opponentEmote={opponentEmote}
          myEmote={myEmoteData}
          onQuit={() => { matchCtx.quitMatch?.(multiplayerMatch?.id); setActiveMatch?.(null); onBack() }}
        />
      )}

      <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', padding:'12px 16px', gap:8 }}>
        <button onClick={onBack} style={{ background:'none', border:'none', color:textMuted, fontSize:20, cursor:'pointer', padding:4 }}>←</button>
        <div style={{ display:'flex', gap:isMultiplayer ? 8 : 4, alignItems:'center' }}>
          {isMultiplayer ? (
            <>
              <span style={{ fontSize:13, fontWeight:700, color:'#00B894' }}>✓ {totalCorrect}</span>
              <span style={{ fontSize:12, color:textMuted }}>|</span>
              <span style={{ fontSize:13, fontWeight:700, color:'#FF6B6B' }}>✗ {totalWrong}</span>
            </>
          ) : (
            Array.from({ length: diff.lives }, (_, i) => (
              <span key={i} style={{ fontSize:18, opacity: i < lives ? 1 : 0.2, transition:'opacity 0.3s' }}>❤️</span>
            ))
          )}
        </div>
        <div style={{ fontFamily:"'Fredoka One',cursive", color:accent, fontSize:16 }}>{score.toLocaleString()}</div>
      </div>

      <div style={{ height:6, background:surface, margin:'0 16px', borderRadius:3, overflow:'hidden' }}>
        <div style={{ height:'100%', width:`${timerPct}%`, background:timerColor, transition: feedback ? 'none' : 'width 0.1s linear' }} />
      </div>

      <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', padding:'8px 16px 4px', gap:8 }}>
        <div style={{ fontSize:13, color:textMuted }}><span style={{ fontWeight:700, color:accent }}>Level {level}</span><span style={{ marginLeft:4 }}>{LEVEL_NAMES[level] || ''}</span></div>
        <div style={{ fontSize:12, color:textMuted }}>{correctInLevel}/{diff.correctToLevel} → Lv{level+1}</div>
      </div>
      <div style={{ height:4, background:surface, margin:'0 16px 8px', borderRadius:2, overflow:'hidden' }}>
        <div style={{ height:'100%', width:`${progressInLevel}%`, background:accentLight, transition:'width 0.3s ease' }} />
      </div>

      <div style={{ textAlign:'center', height:28, display:'flex', alignItems:'center', justifyContent:'center' }}>
        {comboLabel && <div style={{ fontFamily:"'Fredoka One',cursive", fontSize:16, color:comboColor, animation:'comboPulse 0.6s ease infinite alternate' }}>{comboLabel}</div>}
        {streak > 0 && streak < 3 && <div style={{ fontSize:13, color:textMuted }}>🔥 Streak: {streak}</div>}
      </div>

      {/* Remove previous inline VS bar as PvpScoreBar is now at the top */}

      <div style={{ flex:1, display:'flex', flexDirection:'column', alignItems:'center', justifyContent:'center', padding:'0 20px', gap:24 }}>
        {showLevelUp && (
          <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,0.7)', zIndex:100, display:'flex', alignItems:'center', justifyContent:'center' }}>
            <div style={{ textAlign:'center', animation:'levelUpBounce 0.5s ease' }}>
              <div style={{ fontSize:64 }}>📈</div>
              <div style={{ fontFamily:"'Fredoka One',cursive", fontSize:32, color:'#FDCB6E', marginTop:8 }}>LEVEL UP!</div>
              <div style={{ fontSize:18, color:'#fff', marginTop:4 }}>Level {level} — {LEVEL_NAMES[level] || ''}</div>
            </div>
          </div>
        )}

        {question && (
          <>
            <div style={{
              background:surface, borderRadius:20, padding:'28px 36px', width:'100%', maxWidth:380, textAlign:'center', position:'relative',
              boxShadow: feedback?.type === 'correct' ? '0 0 30px #00B89444' : feedback?.type === 'wrong' || feedback?.type === 'timeout' ? '0 0 30px #FF6B6B44' : 'none',
              animation: feedback?.type === 'wrong' || feedback?.type === 'timeout' ? 'shakeX 0.4s ease' : feedback?.type === 'correct' ? 'popCorrect 0.3s ease' : 'none',
              border: feedback?.type === 'correct' ? '2px solid #00B894' : feedback?.type === 'wrong' || feedback?.type === 'timeout' ? '2px solid #FF6B6B' : `2px solid ${tc.borderCol || '#ccc'}`,
            }}>
              <div style={{ fontFamily:"'Fredoka One',cursive", fontSize: question.display.length > 12 ? 32 : 42, color:textMain, letterSpacing:2 }}>{question.display}</div>
              <div style={{ fontSize:14, color:textMuted, marginTop:4 }}>= ?</div>
            </div>

            {feedback && (
              <div style={{ textAlign:'center', animation:'fadeInUp 0.3s ease' }}>
                {feedback.type === 'correct' && <div style={{ color:'#00B894', fontWeight:700, fontSize:16 }}>✓ Benar! +{feedback.points} {feedback.multi > 1 ? `(×${feedback.multi})` : ''}</div>}
                {(feedback.type === 'wrong' || feedback.type === 'timeout') && <div style={{ color:'#FF6B6B', fontWeight:700, fontSize:16 }}>{feedback.type === 'wrong' ? '✗ Salah!' : '⏰ Waktu habis!'} Jawaban: {feedback.answer}</div>}
              </div>
            )}

            <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:10, width:'100%', maxWidth:380 }}>
              {question.options.map((opt, i) => {
                const isSelected = selectedAnswer === opt; const isCorrectAnswer = opt === question.answer;
                let btnBg = '#6C5CE7'; let btnColor = '#FFFFFF'; let btnBorder = '#5A4BDB';
                let opacity = 1
                if (feedback) {
                  if (isSelected || isCorrectAnswer) { btnBg = isCorrectAnswer ? '#00B894' : '#FF6B6B'; btnBorder = isCorrectAnswer ? '#00B894' : '#FF6B6B' }
                  else { opacity = 0.5 }
                }
                return (
                  <button key={i} onClick={() => handleAnswer(opt)} disabled={!!feedback} style={{
                    fontFamily:"'Fredoka One',cursive", fontSize:22, padding:'16px 8px', background:btnBg, color:btnColor, border:`2px solid ${btnBorder}`,
                    borderRadius:14, cursor: feedback ? 'default' : 'pointer', transform: isSelected ? 'scale(0.95)' : 'scale(1)', transition: 'all 0.1s',
                    opacity
                  }}>{opt}</button>
                )
              })}
            </div>
          </>
        )}
      </div>

      {/* Battle Emotes */}
      {isMultiplayer && phase === 'playing' && (
        <BattleEmotes
          onSendEmote={sendEmote}
          incomingEmote={opponentEmote}
          senderName={opponentProfile?.displayName || 'Lawan'}
          disabled={!!feedback}
        />
      )}

      <style>{`
        @keyframes shakeX { 0%, 100% { transform: translateX(0); } 20% { transform: translateX(-8px); } 40% { transform: translateX(8px); } 60% { transform: translateX(-6px); } 80% { transform: translateX(6px); } }
        @keyframes popCorrect { 0% { transform: scale(1); } 50% { transform: scale(1.04); } 100% { transform: scale(1); } }
        @keyframes comboPulse { from { transform: scale(1); } to { transform: scale(1.08); } }
        @keyframes fadeInUp { from { opacity:0; transform:translateY(8px); } to { opacity:1; transform:translateY(0); } }
        @keyframes levelUpBounce { 0% { opacity:0; transform: scale(0.5); } 60% { transform: scale(1.1); } 100% { opacity:1; transform: scale(1); } }
      `}</style>
    </div>
  )
}

import TutorialModal from '../../components/TutorialModal.jsx'
import Confetti from '../../components/Confetti.jsx'
import { useState, useEffect, useCallback, useRef, useMemo } from 'react'
import { useSettings } from '../../context/SettingsContext.jsx'
import { useSound } from '../../hooks/useSound.js'
import { useProgress } from '../../context/ProgressContext.jsx'
import { useCoins } from '../../context/CoinContext.jsx'
import { useThemeColors } from '../../hooks/useThemeColors.js'
import { useHaptics } from '../../hooks/useHaptics.js'
import { useLeaderboard } from '../../context/LeaderboardContext.jsx'
import { useMatch } from '../../context/MatchContext.jsx'
import { useAuth } from '../../context/AuthContext.jsx'
import { auth } from '../../firebase.js'
import { useMascot } from '../../context/MascotContext.jsx'
import { WinModal } from '../../components/GameLayout.jsx'
import PvpScoreBar from '../../components/PvpScoreBar.jsx'
import BattleEmotes from '../../components/BattleEmotes.jsx'

const TUTORIAL_STEPS = [
  { emoji:'🃏', title:'Memory Card Match', desc:'Temukan semua pasangan kartu yang tersembunyi di balik kartu terbalik!', tip:'Ingat posisi kartu yang sudah pernah kamu buka.' },
  { emoji:'👆', title:'Cara Main', desc:'Klik satu kartu untuk membukanya, lalu cari pasangan yang sama. Kalau cocok, kartu tetap terbuka!', tip:'Kalau tidak cocok, kartu akan tertutup lagi — ingat posisinya!' },
  { emoji:'⭐', title:'Sistem Bintang', desc:'Semakin sedikit gerakan yang kamu pakai, semakin banyak bintang yang kamu dapat. Targetkan 3 bintang!', tip:'Easy ≤10 gerakan, Medium ≤14, Hard ≤20 untuk 3 bintang.' },
]

const DEFAULT_POOL = ['🐶','🐱','🦊','🐻','🦁','🐯','🐸','🐧','🦄','🐼','🦋','🐙']

function shuffle(arr) {
  const a = [...arr]
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]]
  }
  return a
}

function createDeck(pairs, pool) {
  const icons = (pool || DEFAULT_POOL).slice(0, pairs)
  return shuffle(
    [...icons, ...icons].map((emoji, idx) => ({
      id: idx, emoji, flipped: false, matched: false,
    }))
  )
}

function useTimer(running, resetKey, initialTime = 0, isCountdown = false, onTimeOut = null) {
  const [time, setTime] = useState(initialTime)
  useEffect(() => { setTime(initialTime) }, [resetKey, initialTime])
  useEffect(() => {
    if (!running) return
    const id = setInterval(() => {
      setTime(t => {
        if (isCountdown) {
          if (t <= 1) {
            clearInterval(id)
            onTimeOut?.()
            return 0
          }
          return t - 1
        }
        return t + 1
      })
    }, 1000)
    return () => clearInterval(id)
  }, [running, isCountdown, onTimeOut])
  return time
}

const formatTime = (s) =>
  `${Math.floor(s/60).toString().padStart(2,'0')}:${((s%60) || 0).toString().padStart(2,'0')}`

const DIFF_LABEL = { easy: '🟢 Mudah', medium: '🟡 Sedang', hard: '🔴 Sulit' }

export default function MemoryCardMatch({ onBack, onHome, game, difficulty, multiplayerMatch }) {
  const tc = useThemeColors()
  const { play } = useSound()
  const { reportGameResult } = useProgress()
  const { getActiveCardPack, earnCoins, spendCoins, coins } = useCoins()
  const { vibrateLight, vibrateMedium, vibrateSuccess, vibrateError } = useHaptics()
  const { startScoreSession } = useLeaderboard()
  const matchCtx = useMatch() || {}
  const { updateMatchState, finishMatch, setActiveMatch } = matchCtx
  const { uid: userId } = useAuth()
  const { triggerMascot } = useMascot()

  // PvP state
  const isMultiplayer = !!multiplayerMatch
  const myUid = userId || auth.currentUser?.uid
  const opponentUid = isMultiplayer ? (multiplayerMatch.hostUid === myUid ? multiplayerMatch.guestUid : multiplayerMatch.hostUid) : null
  const opponentData = isMultiplayer ? (multiplayerMatch.state?.[opponentUid] || { moves: 0, matched: 0, finished: false }) : null
  const opponentProfile = isMultiplayer ? (multiplayerMatch.hostUid === myUid ? multiplayerMatch.guestProfile : multiplayerMatch.hostProfile) : null
  const opponentEmote = isMultiplayer ? opponentData?.emote : null
  const myEmoteData = isMultiplayer ? (multiplayerMatch.state?.[myUid]?.emote || null) : null

  const sendEmote = useCallback((emoji) => {
    if (!isMultiplayer || !multiplayerMatch?.id || !myUid) return
    const newState = {
      ...multiplayerMatch.state,
      [myUid]: { ...multiplayerMatch.state?.[myUid], emote: { emoji, ts: Date.now() } }
    }
    updateMatchState?.(multiplayerMatch.id, newState)
  }, [isMultiplayer, multiplayerMatch?.id, multiplayerMatch?.state, myUid, updateMatchState])

  const { pairs, cols } = difficulty
  const activePack = getActiveCardPack()
  const iconPool = activePack.icons
  const cardBack = activePack.cardBack || null
  const timersRef = useRef([])

  const safeTimeout = useCallback((fn, ms) => {
    const id = setTimeout(fn, ms)
    timersRef.current.push(id)
    return id
  }, [])

  useEffect(() => {
    return () => { timersRef.current.forEach(id => clearTimeout(id)); timersRef.current = [] }
  }, [])

  const [deck, setDeck]         = useState(() => createDeck(pairs, iconPool))
  const [selected, setSelected] = useState([])
  const [moves, setMoves]       = useState(0)
  const [combo, setCombo]       = useState(0)
  const lastMatchTimeRef        = useRef(0)
  const [locked, setLocked]     = useState(false)
  const [won, setWon]           = useState(false)
  const [failed, setFailed]     = useState(false)
  const [showTutorial, setShowTutorial] = useState(() => !localStorage.getItem('bp_tut_memory-card'))
  const [showConfetti, setShowConfetti] = useState(false)
  const [resetKey, setResetKey] = useState(0)
  const [gameMode, setGameMode] = useState('standard') // standard, timeAttack, mirror

  const bestKey = `${game.id}-best-${difficulty.id}`
  const [bestMoves, setBestMoves] = useState(() => parseInt(localStorage.getItem(bestKey) || '0'))

  const initialTime = useMemo(() => {
    if (gameMode !== 'timeAttack') return 0
    return difficulty.id === 'easy' ? 60 : difficulty.id === 'medium' ? 45 : 30
  }, [gameMode, difficulty.id])

  const timerRunning = !won && !failed && moves > 0
  const time = useTimer(timerRunning, resetKey, initialTime, gameMode === 'timeAttack', () => {
    setFailed(true)
    play('mismatch')
    vibrateError()
  })

  useEffect(() => {
    if (deck.length > 0 && deck.every(c => c.matched)) {
      setWon(true)
      setShowConfetti(true)
      play('win')
      vibrateSuccess()
      if (bestMoves === 0 || moves < bestMoves) {
        localStorage.setItem(bestKey, moves)
        setBestMoves(moves)
      }
      let stars = moves <= (pairs * 1.5) ? 3 : moves <= (pairs * 2.5) ? 2 : 1
      if (paidHints > 0 && stars > 2) stars = 2
      if (!isMultiplayer) {
        reportGameResult({
          gameId: 'memory-card',
          difficultyId: difficulty.id,
          won: true,
          score: Math.max(0, pairs * 100 - moves * 10),
          stars,
          timeSec: gameMode === 'timeAttack' ? initialTime - time : time,
        })
        const coinReward = { easy: 15, medium: 25, hard: 40 }
        let coinAmount = coinReward[difficulty.id] || 15
        if (stars === 3) coinAmount += 20
        earnCoins(coinAmount, `Menang Memory Card (${difficulty.id})`)
      }
      // PvP: mark finished
      if (isMultiplayer && multiplayerMatch?.id) {
        const myScore = Math.max(0, pairs * 100 - moves * 10)
        const newState = {
          ...multiplayerMatch.state,
          [myUid]: { moves, matched: pairs, score: myScore, finished: true }
        }
        updateMatchState?.(multiplayerMatch.id, newState)
        // If opponent already finished, determine winner
        if (opponentData?.finished) {
          const oppScore = opponentData.score || 0
          const winner = myScore > oppScore ? myUid : myScore < oppScore ? opponentUid : 'draw'
          finishMatch?.(multiplayerMatch.id, winner)
        }
      }
    }
  }, [deck])

  // PvP: sync moves in real-time
  useEffect(() => {
    if (!isMultiplayer || !multiplayerMatch?.id || !myUid || won || failed) return
    const matchedPairs = deck.filter(c => c.matched).length / 2
    const myScore = Math.max(0, pairs * 100 - moves * 10)
    const newState = {
      ...multiplayerMatch.state,
      [myUid]: { ...multiplayerMatch.state?.[myUid], moves, matched: matchedPairs, score: myScore, finished: false }
    }
    updateMatchState?.(multiplayerMatch.id, newState)
  }, [moves, isMultiplayer, myUid, multiplayerMatch?.id])

  // PvP: if opponent finishes while we're still playing
  useEffect(() => {
    if (!isMultiplayer || !won) return
    if (opponentData?.finished && multiplayerMatch?.status === 'active') {
      const myScore = Math.max(0, pairs * 100 - moves * 10)
      const oppScore = opponentData.score || 0
      const winner = myScore > oppScore ? myUid : myScore < oppScore ? opponentUid : 'draw'
      finishMatch?.(multiplayerMatch.id, winner)
    }
  }, [opponentData?.finished, won])

  // PvP: if match cancelled
  useEffect(() => {
    if (isMultiplayer && multiplayerMatch?.status === 'cancelled' && !won && !failed) {
      setWon(true) // end the game
    }
  }, [multiplayerMatch?.status])

  const handleRestart = () => {
    setDeck(createDeck(pairs, iconPool))
    setSelected([])
    setMoves(0)
    setWon(false)
    setFailed(false)
    setLocked(false)
    setHintUsed(0)
    setPaidHints(0)
    setHintCells([])
    setResetKey(k => k + 1)
  }

  const flipCard = useCallback((id) => {
    if (locked || failed || won) return
    const card = deck.find(c => c.id === id)
    if (!card || card.flipped || card.matched) return
    if (selected.length === 1 && selected[0].id === id) return

    play('flip')
    vibrateLight()
    const newDeck     = deck.map(c => c.id === id ? { ...c, flipped: true } : c)
    const newSelected = [...selected, { ...card }]
    setDeck(newDeck)
    setSelected(newSelected)

    if (newSelected.length === 2) {
      if (moves === 0 && startScoreSession) startScoreSession(game.id)
      setMoves(m => m + 1)
      setLocked(true)
      if (newSelected[0].emoji === newSelected[1].emoji) {
        play('match')
        vibrateMedium()

        // Combo logic (within 4 seconds)
        const now = Date.now()
        let newCombo = 1
        if (now - lastMatchTimeRef.current < 4000) {
          newCombo = combo + 1
        }
        setCombo(newCombo)
        lastMatchTimeRef.current = now

        if (newCombo === 2) triggerMascot("Wow! Combo ×2! 🔥", "excited")
        else if (newCombo === 3) triggerMascot("Luar biasa!! Triple Combo! 🤯", "surprised")
        else if (newCombo >= 4) triggerMascot(`OMGG!! Combo ×${newCombo}!! Otakmu dewa! 😱`, "excited")

        safeTimeout(() => {
          setDeck(d => d.map(c =>
            c.id === newSelected[0].id || c.id === newSelected[1].id
              ? { ...c, matched: true } : c
          ))
          setSelected([])
          setLocked(false)
        }, 500)
      } else {
        setCombo(0)
        safeTimeout(() => { play('mismatch'); vibrateError() }, 200)
        safeTimeout(() => {
          setDeck(d => d.map(c =>
            c.id === newSelected[0].id || c.id === newSelected[1].id
              ? { ...c, flipped: false } : c
          ))
          setSelected([])
          setLocked(false)
        }, 1000)
      }
    }
  }, [deck, selected, locked, failed, won, play])

  const FREE_HINTS = 3
  const HINT_COST = 100
  const [hintUsed, setHintUsed] = useState(0)
  const [paidHints, setPaidHints] = useState(0)
  const [hintCells, setHintCells] = useState([])

  const useHint = async () => {
    if (locked || won || failed) return
    const isFree = hintUsed < FREE_HINTS
    if (!isFree) {
      if (coins < HINT_COST) { play('mismatch'); vibrateError(); return }
      const ok = await spendCoins(HINT_COST, 'Hint Memory Card')
      if (!ok) return
      setPaidHints(p => p + 1)
    }
    play('click')
    vibrateMedium()
    const unmatched = deck.filter(c => !c.matched && !c.flipped)
    if (unmatched.length < 2) return
    const found = []
    const seen = {}
    for (const c of unmatched) {
      if (seen[c.emoji]) { found.push(seen[c.emoji]); found.push(c); break }
      seen[c.emoji] = c
    }
    if (found.length < 2) return
    const foundIds = found.map(c => c.id)
    setHintCells(foundIds)
    setLocked(true)
    setDeck(d => d.map(c => foundIds.includes(c.id) ? {...c, flipped:true} : c))
    safeTimeout(() => {
      setDeck(d => d.map(c => foundIds.includes(c.id) ? {...c, flipped:false} : c))
      setHintCells([])
      setLocked(false)
    }, 1500)
    setHintUsed(h => h+1)
  }

  const matchedCount = deck.filter(c => c.matched).length / 2

  const winStars = useMemo(() => {
    let stars = moves <= pairs * 1.5 ? 3 : moves <= pairs * 2.5 ? 2 : 1
    if (paidHints > 0 && stars > 2) stars = 2
    return stars
  }, [moves, pairs, paidHints])

  const winCoinAmount = useMemo(() => {
    const coinReward = { easy: 15, medium: 25, hard: 40 }
    let coinAmount = coinReward[difficulty.id] || 15
    if (winStars === 3) coinAmount += 20
    return coinAmount
  }, [winStars, difficulty.id])

  return (
    <div style={{ maxWidth: 700, margin: '0 auto', padding: '32px 20px 60px', background: tc.bg, minHeight: '100vh', transition: 'background 0.3s', position: 'relative', overflowX: 'hidden', display: 'flex', flexDirection: 'column' }}>
      {showTutorial && !isMultiplayer && <TutorialModal steps={TUTORIAL_STEPS} color="#FF6B6B" onClose={() => { setShowTutorial(false); localStorage.setItem("bp_tut_memory-card","1") }} />}
      {showConfetti && <Confetti onComplete={() => setShowConfetti(false)} />}

      {/* PvP Score Bar */}
      {isMultiplayer && (
        <PvpScoreBar
          opponentProfile={opponentProfile}
          opponentScore={opponentData?.score || 0}
          opponentProgress={Math.min(100, Math.round(((opponentData?.matched || 0) / pairs) * 100))}
          opponentExtra={`${opponentData?.moves || 0} moves`}
          opponentFinished={opponentData?.finished}
          myScore={Math.max(0, pairs * 100 - moves * 10)}
          myProgress={Math.min(100, Math.round((matchedCount / pairs) * 100))}
          opponentEmote={opponentEmote}
          myEmote={myEmoteData}
          onQuit={() => { matchCtx.quitMatch?.(multiplayerMatch?.id); setActiveMatch?.(null); onBack() }}
        />
      )}

      {/* Mode Selector Container - Fixed height to prevent layout jump */}
      <div style={{ height: (moves === 0 && !won && !failed) ? 70 : 0, overflow: 'hidden', transition: 'height 0.3s ease', marginBottom: (moves === 0 && !won && !failed) ? 24 : 0 }}>
        <div style={{
          display: 'flex', justifyContent: 'center', gap: 10, padding: '12px',
          background: tc.surface, borderRadius: 20, border: `2px solid ${tc.borderCol}`,
          boxShadow: '0 4px 15px rgba(0,0,0,0.05)',
          touchAction: 'manipulation'
        }}>
          {['standard', 'timeAttack', 'mirror'].map(m => (
            <button key={m} onClick={() => { play('click'); setGameMode(m); }} style={{
              padding: '10px 16px', borderRadius: 14, border: 'none',
              background: gameMode === m ? 'linear-gradient(135deg, #A29BFE, #6C5CE7)' : (tc.dark ? '#2d3436' : '#f0f0f0'),
              color: gameMode === m ? '#fff' : tc.textMain,
              fontSize: 12, fontWeight: 800, cursor: 'pointer', fontFamily: "'Fredoka One', cursive",
              transition: 'all 0.2s', transform: gameMode === m ? 'scale(1.05)' : 'none',
              touchAction: 'manipulation'
            }}>
              {m === 'standard' ? '🎯 Std' : m === 'timeAttack' ? '⏳ T.A' : '🪞 Mir'}
            </button>
          ))}
        </div>
      </div>

      {/* Header */}
      <div style={{ display: 'flex', alignItems: 'center', gap: 12, marginBottom: 16 }}>
        <button onClick={() => { play('click'); onBack() }}
          style={{ background: tc.surface, border: `2px solid ${tc.borderCol}`, borderRadius: 12, padding: '8px 14px', fontSize: 18, cursor: 'pointer', color: tc.textMain }}>
          ←
        </button>
        <div style={{ flex: 1 }}>
          <h1 style={{ fontFamily: "'Fredoka One',cursive", fontSize: 26, color: tc.textMain, lineHeight: 1 }}>
            🃏 Memory Match
          </h1>
          <div style={{ fontSize: 11, color: tc.textMuted, marginTop: 4, fontWeight: 700, textTransform: 'uppercase', letterSpacing: 0.5 }}>
            {DIFF_LABEL[difficulty.id]} {gameMode !== 'standard' && <span style={{ color: '#6C5CE7' }}>• {gameMode.toUpperCase()}</span>}
          </div>
        </div>
      </div>

      {/* Stats */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3,1fr)', gap: 10, marginBottom: 20 }}>
        {[
          { label: 'Gerakan', value: moves, color: '#FF6B6B' },
          { label: 'Timer', value: formatTime(time), color: (gameMode === 'timeAttack' && time < 10) ? '#FF4757' : '#4ECDC4' },
          { label: 'Skor', value: `${matchedCount}/${pairs}`, color: '#A29BFE' },
        ].map(s => (
          <div key={s.label} style={{ background: tc.surface, border: `2px solid ${s.color}33`, borderRadius: 16, padding: '10px 8px', textAlign: 'center' }}>
            <div style={{ fontFamily: "'Fredoka One',cursive", fontSize: 22, color: s.color, lineHeight: 1 }}>{s.value}</div>
            <div style={{ fontSize: 10, color: tc.textMuted, marginTop: 3, fontWeight: 700, textTransform: 'uppercase' }}>{s.label}</div>
          </div>
        ))}
      </div>

      {/* Board */}
      <div style={{
        display: 'grid',
        gridTemplateColumns: `repeat(${cols}, 1fr)`,
        gap: cols >= 5 ? 8 : 12,
        marginBottom: 24,
        perspective: 1000,
        transform: gameMode === 'mirror' ? 'scaleX(-1)' : 'none',
        filter: gameMode === 'mirror' ? 'drop-shadow(0 0 10px rgba(162, 155, 254, 0.3)) contrast(1.1)' : 'none',
        touchAction: 'manipulation',
        userSelect: 'none'
      }}>
        {deck.map(card => (
          <CardTile
            key={card.id}
            card={card}
            onClick={() => flipCard(card.id)}
            darkMode={tc.dark}
            small={cols >= 5}
            cardBack={cardBack}
            isMirror={gameMode === 'mirror'}
          />
        ))}
      </div>

      {/* Combo Floating Text */}
      {combo > 1 && !won && !failed && (
        <div style={{
          position: 'fixed', top: '25%', left: '50%', transform: 'translate(-50%, -50%)',
          pointerEvents: 'none', zIndex: 10, animation: 'combo-pop 1s ease-out forwards',
          fontFamily: "'Fredoka One',cursive", fontSize: 36, color: '#FFD700',
          textShadow: '0 4px 15px rgba(255,215,0,0.5), 0 2px 4px rgba(0,0,0,0.3)',
          letterSpacing: 2
        }}>
          COMBO ×{combo}!
        </div>
      )}
      <style>{`
        @keyframes combo-pop {
          0% { transform: translate(-50%, -40%) scale(0.5); opacity: 0; }
          20% { transform: translate(-50%, -50%) scale(1.2); opacity: 1; }
          80% { transform: translate(-50%, -55%) scale(1); opacity: 1; }
          100% { transform: translate(-50%, -60%) scale(0.8); opacity: 0; }
        }
      `}</style>

      {/* Buttons */}
      <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
        <button
          onClick={useHint}
          disabled={locked || won || failed}
          style={{
            width: '100%', padding: '16px', borderRadius: 16, border: 'none',
            background: 'linear-gradient(135deg, #6C5CE7, #A29BFE)', color: '#fff',
            fontFamily: "'Fredoka One', cursive", fontSize: 16, cursor: 'pointer',
            display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 10,
            opacity: (locked || won || failed) ? 0.5 : 1, transition: 'all 0.3s',
            boxShadow: '0 4px 15px rgba(108, 92, 231, 0.3)'
          }}
        >
          <span>💡</span> Hint {hintUsed < FREE_HINTS ? `(Gratis: ${FREE_HINTS - hintUsed})` : `(🪙 ${HINT_COST})`}
        </button>

        <div style={{ display: 'flex', gap: 10 }}>
          <button onClick={handleRestart}
