// Seeded PRNG for deterministic PvP questions
function seededRng(seed) {
  let s = seed
  return () => { s = (s * 16807 + 0) % 2147483647; return (s - 1) / 2147483646 }
}

function shuffleWithSeed(arr, rng) {
  const a = [...arr]
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(rng() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]]
  }
  return a
}

function shuffleArray(arr) {
  const a = [...arr]; for (let i = a.length - 1; i > 0; i--) { const j = Math.floor(Math.random() * (i + 1));[a[i], a[j]] = [a[j], a[i]] }; return a
}

function prepareQuestions(count, seed) {
  const rng = seed ? seededRng(seed) : null
  const shuffled = rng ? shuffleWithSeed(QUESTIONS, rng) : shuffleArray(QUESTIONS)
  return shuffled.slice(0, count).map(q => {
    const correctText = q.o[q.a]
    const shuffledOpts = rng ? shuffleWithSeed(q.o, rng) : shuffleArray(q.o)
    return { ...q, o: shuffledOpts, a: shuffledOpts.indexOf(correctText) }
  })
}

function getComboMulti(s) { return s >= 10 ? 3 : s >= 5 ? 2 : s >= 3 ? 1.5 : 1 }
function getComboLabel(s) { return s >= 10 ? '🔥 UNSTOPPABLE ×3' : s >= 5 ? '⚡ ON FIRE ×2' : s >= 3 ? '✨ COMBO ×1.5' : '' }
function getComboColor(s) { return s >= 10 ? '#FF3838' : s >= 5 ? '#E17055' : s >= 3 ? '#FDCB6E' : '#888' }

export default function QuizTrivia({ onBack, onHome, game, difficulty, multiplayerMatch }) {
  const { play } = useSound()
  const { reportGameResult } = useProgress()
  const { earnCoins } = useCoins()
  const tc = useThemeColors()
  const matchCtx = useMatch() || {}
  const { updateMatchState, finishMatch, setActiveMatch } = matchCtx
  const { uid: userId } = useAuth()
  const diff = CFG[difficulty?.id] || CFG.easy

  // ── PvP state ──
  const isMultiplayer = !!multiplayerMatch
  const myUid = userId || auth.currentUser?.uid
  const opponentUid = isMultiplayer ? (multiplayerMatch.hostUid === myUid ? multiplayerMatch.guestUid : multiplayerMatch.hostUid) : null
  const opponentData = isMultiplayer ? (multiplayerMatch.state?.[opponentUid] || { score: 0, finished: false }) : null
  const opponentProfile = isMultiplayer
    ? (multiplayerMatch.hostUid === myUid ? multiplayerMatch.guestProfile : multiplayerMatch.hostProfile)
    : null
  const opponentEmote = isMultiplayer ? opponentData?.emote : null
  const myEmoteData = isMultiplayer ? (multiplayerMatch.state?.[myUid]?.emote || null) : null

  // Send emote to opponent via match state
  const sendEmote = useCallback((emoji) => {
    if (!isMultiplayer || !multiplayerMatch?.id || !myUid) return
    const newState = {
      ...multiplayerMatch.state,
      [myUid]: { ...multiplayerMatch.state?.[myUid], emote: { emoji, ts: Date.now() } }
    }
    updateMatchState?.(multiplayerMatch.id, newState)
  }, [isMultiplayer, multiplayerMatch?.id, multiplayerMatch?.state, myUid, updateMatchState])

  const [phase, setPhase] = useState('tutorial')
  const [questions, setQuestions] = useState([])
  const [qIndex, setQIndex] = useState(0)
  const [totalWrong, setTotalWrong] = useState(0)
  const [score, setScore] = useState(0)
  const [streak, setStreak] = useState(0)
  const [bestStreak, setBestStreak] = useState(0)
  const [totalCorrect, setTotalCorrect] = useState(0)
  const [timeLeft, setTimeLeft] = useState(diff.timePerQ)
  const [feedback, setFeedback] = useState(null)
  const [selectedAnswer, setSelectedAnswer] = useState(null)
  const [showConfetti, setShowConfetti] = useState(false)
  const [gameOverReason, setGameOverReason] = useState('')
  const timerRef = useRef(null)
  const fbRef = useRef(null)
  const scoreRef = useRef(0) // For PvP sync without stale closure

  const bestKey = `quiz-trivia-best-${difficulty?.id || 'easy'}`
  const [bestScore, setBestScore] = useState(() => { try { return parseInt(localStorage.getItem(bestKey)) || 0 } catch { return 0 } })

  useEffect(() => () => { clearInterval(timerRef.current); clearTimeout(fbRef.current) }, [])

  // ── PvP: auto-start when match becomes active ──
  useEffect(() => {
    if (isMultiplayer && phase === 'tutorial') setPhase('ready')
    if (isMultiplayer && phase === 'ready') startGame()
  }, [isMultiplayer, phase])

  // ── PvP: sync score to Firestore ──
  useEffect(() => {
    scoreRef.current = score
    if (!isMultiplayer || !multiplayerMatch?.id || phase !== 'playing') return
    const newState = {
      ...multiplayerMatch.state,
      [myUid]: { score, correct: totalCorrect, qIndex, finished: false }
    }
    updateMatchState?.(multiplayerMatch.id, newState)
  }, [score, totalCorrect, qIndex])

  // ── PvP: monitor opponent finish ──
  useEffect(() => {
    if (!isMultiplayer || phase !== 'playing') return
    if (opponentData?.finished && multiplayerMatch?.status === 'active') {
      // Opponent finished — keep playing, but show indicator
    }
    if (multiplayerMatch?.status === 'cancelled') {
      endGame('opponent_quit')
    }
  }, [opponentData?.finished, multiplayerMatch?.status])

  const startTimer = useCallback((q) => {
    clearInterval(timerRef.current)
    setTimeLeft(diff.timePerQ)
    const start = Date.now()
    timerRef.current = setInterval(() => {
      const rem = diff.timePerQ - (Date.now() - start) / 1000
      if (rem <= 0) { clearInterval(timerRef.current); setTimeLeft(0); handleWrong(q, true) }
      else setTimeLeft(rem)
    }, 50)
  }, [diff.timePerQ])

  const advance = useCallback(() => {
    setQIndex(i => {
      const next = i + 1
      if (next >= questions.length) { endGame('complete'); return i }
      setFeedback(null); setSelectedAnswer(null)
      setTimeout(() => startTimer(questions[next]), 50)
      return next
    })
  }, [questions, startTimer])

  const handleWrong = useCallback((q, timeout = false) => {
    clearInterval(timerRef.current); play('error')
    setFeedback({ type: timeout ? 'timeout' : 'wrong', answer: q.o[q.a] })
    setStreak(0)
    setTotalWrong(p => p + 1)
    fbRef.current = setTimeout(() => advance(), 1400)
  }, [play, advance])

  const handleAnswer = useCallback((idx) => {
    if (feedback || selectedAnswer !== null) return
    clearInterval(timerRef.current); setSelectedAnswer(idx)
    const q = questions[qIndex]
    if (idx === q.a) {
      play('success'); const ns = streak + 1; const m = getComboMulti(ns)
      const pts = Math.round((200 + Math.round(timeLeft * 15)) * m)
      setStreak(ns); setBestStreak(p => Math.max(p, ns)); setScore(p => p + pts); setTotalCorrect(p => p + 1)
      setFeedback({ type: 'correct', points: pts, multi: m })
      fbRef.current = setTimeout(() => advance(), 800)
    } else handleWrong(q)
  }, [feedback, selectedAnswer, questions, qIndex, streak, timeLeft, play, advance, handleWrong])

  const endGame = useCallback((reason) => {
    clearInterval(timerRef.current); clearTimeout(fbRef.current)
    setGameOverReason(reason); setPhase('result')

    // PvP: sync final state
    if (isMultiplayer && multiplayerMatch?.id) {
      const finalScore = scoreRef.current
      const newState = {
        ...multiplayerMatch.state,
        [myUid]: { score: finalScore, correct: totalCorrect, qIndex, finished: true }
      }
      updateMatchState?.(multiplayerMatch.id, newState)

      // If opponent also finished, determine winner
      if (opponentData?.finished) {
        const winner = finalScore > opponentData.score ? myUid
          : finalScore < opponentData.score ? opponentUid : 'draw'
        finishMatch?.(multiplayerMatch.id, winner)
      }
    }

    if (reason === 'complete') { setShowConfetti(true); play('win') } else play('gameOver')
  }, [play, isMultiplayer, multiplayerMatch, myUid, opponentUid, opponentData, totalCorrect, qIndex])

  // PvP: if opponent finishes after us, determine winner
  useEffect(() => {
    if (phase !== 'result' || !isMultiplayer) return
    if (opponentData?.finished && multiplayerMatch?.status === 'active') {
      const winner = score > opponentData.score ? myUid
        : score < opponentData.score ? opponentUid : 'draw'
      finishMatch?.(multiplayerMatch.id, winner)
    }
  }, [opponentData?.finished])

  const won = gameOverReason === 'complete'
  const totalAnswered = won ? diff.totalQ : qIndex + 1
  const accuracy = Math.round((totalCorrect / Math.max(totalAnswered, 1)) * 100)
  const stars = won ? calcStars(totalCorrect, diff.totalQ, diff) : 0
  const coinReward = isMultiplayer ? 0 : Math.floor(score / 50) + stars * 5
  const isNewBest = score > bestScore

  // PvP result
  const pvpWon = isMultiplayer && multiplayerMatch?.winner === myUid
  const pvpDraw = isMultiplayer && multiplayerMatch?.winner === 'draw'
  const pvpLost = isMultiplayer && multiplayerMatch?.winner && multiplayerMatch.winner !== myUid && multiplayerMatch.winner !== 'draw'

  useEffect(() => {
    if (phase !== 'result' || isMultiplayer) return
    if (isNewBest) { localStorage.setItem(bestKey, score.toString()); setBestScore(score) }
    if (coinReward > 0) earnCoins(coinReward, 'Quiz Trivia')
    reportGameResult({ gameId: 'quiz-trivia', difficultyId: difficulty?.id || 'easy', score, stars, won, timeSec: 0 })
  }, [phase])

  const startGame = useCallback(() => {
    const seed = isMultiplayer ? multiplayerMatch?.seed : null
    const qs = prepareQuestions(diff.totalQ, seed)
    setQuestions(qs); setQIndex(0); setTotalWrong(0); setScore(0); setStreak(0); setBestStreak(0)
    setTotalCorrect(0); setFeedback(null); setSelectedAnswer(null); setShowConfetti(false); setGameOverReason('')
    setPhase('playing')
    setTimeout(() => startTimer(qs[0]), 100)
  }, [diff, startTimer, isMultiplayer, multiplayerMatch?.seed])

  const accent = '#0984E3'; const accentLight = '#74B9FF'
  const bg = tc.bg; const surface = tc.surface; const textMain = tc.textMain; const textMuted = tc.textMuted
  const timerPct = (timeLeft / diff.timePerQ) * 100
  const timerColor = timerPct > 50 ? '#00B894' : timerPct > 25 ? '#FDCB6E' : '#FF6B6B'

  if (phase === 'tutorial') return <TutorialModal steps={TUTORIAL_STEPS} onClose={() => setPhase('ready')} />

  if (phase === 'ready') return (
    <div style={{ minHeight:'100dvh', background:bg, display:'flex', flexDirection:'column', alignItems:'center', justifyContent:'center', padding:20 }}>
      <div style={{ textAlign:'center', maxWidth:400 }}>
        <div style={{ fontSize:72, marginBottom:12 }}>🇮🇩</div>
        <h1 style={{ fontFamily:"'Fredoka One',cursive", color:accent, fontSize:26, margin:'0 0 8px' }}>Quiz Trivia Indonesia</h1>
        <p style={{ color:textMuted, fontSize:14, marginBottom:24, lineHeight:1.5 }}>Jawab semua soal, raih skor terbaik!<br/>⭐⭐⭐ = akurasi ≥{diff.star3}%</p>
        <div style={{ display:'flex', gap:16, justifyContent:'center', marginBottom:24, flexWrap:'wrap' }}>
          <div style={{ background:surface, borderRadius:12, padding:'12px 20px', textAlign:'center' }}>
            <div style={{ fontSize:20, fontWeight:700, color:accent }}>{diff.totalQ}</div>
            <div style={{ fontSize:11, color:textMuted }}>soal</div>
          </div>
          <div style={{ background:surface, borderRadius:12, padding:'12px 20px', textAlign:'center' }}>
            <div style={{ fontSize:20, fontWeight:700, color:'#00B894' }}>≥{diff.star3}%</div>
            <div style={{ fontSize:11, color:textMuted }}>target ⭐⭐⭐</div>
          </div>
          <div style={{ background:surface, borderRadius:12, padding:'12px 20px', textAlign:'center' }}>
            <div style={{ fontSize:20, fontWeight:700, color:'#FDCB6E' }}>{diff.timePerQ}s</div>
            <div style={{ fontSize:11, color:textMuted }}>per soal</div>
          </div>
        </div>
        {bestScore > 0 && <div style={{ color:textMuted, fontSize:13, marginBottom:16 }}>🏆 Best: {bestScore.toLocaleString()}</div>}
        <button onClick={startGame} style={{ fontFamily:"'Fredoka One',cursive", fontSize:18, padding:'14px 48px', background:`linear-gradient(135deg,${accent},${accentLight})`, color:'#fff', border:'none', borderRadius:14, cursor:'pointer' }}>MULAI! 🚀</button>
        <div style={{ marginTop:16 }}><button onClick={onBack} style={{ background:'none', border:'none', color:textMuted, cursor:'pointer', fontSize:14 }}>← Kembali</button></div>
      </div>
    </div>
  )

  if (phase === 'result') {
    const diffLabel = { easy: '🟢 Mudah', medium: '🟡 Sedang', hard: '🔴 Sulit' }[difficulty?.id] || '🟢 Mudah'

    // PvP result override
    if (isMultiplayer) {
      const waiting = !multiplayerMatch?.winner
      return (
        <div style={{ minHeight:'100dvh', background:bg, display:'flex', flexDirection:'column', alignItems:'center', justifyContent:'center', padding:20 }}>
          {showConfetti && <Confetti />}
          <div style={{ textAlign:'center', maxWidth:400, background:surface, borderRadius:24, padding:32, border:`2px solid ${tc.border}` }}>
            <div style={{ fontSize:64, marginBottom:12 }}>
              {waiting ? '⏳' : pvpWon ? '🏆' : pvpDraw ? '🤝' : '😔'}
            </div>
            <h2 style={{ fontFamily:"'Fredoka One',cursive", fontSize:24, color:textMain, margin:'0 0 8px' }}>
              {waiting ? 'Menunggu lawan selesai...' : pvpWon ? 'KAMU MENANG!' : pvpDraw ? 'SERI!' : 'KAMU KALAH!'}
            </h2>
            <div style={{ display:'flex', justifyContent:'center', gap:24, margin:'20px 0' }}>
              <div style={{ textAlign:'center' }}>
                <div style={{ fontSize:11, fontWeight:800, color:'#6C5CE7' }}>SKOR KAMU</div>
                <div style={{ fontFamily:"'Fredoka One',cursive", fontSize:28, color:'#00B894' }}>{score.toLocaleString()}</div>
              </div>
              <div style={{ fontSize:24, alignSelf:'center' }}>VS</div>
              <div style={{ textAlign:'center' }}>
                <div style={{ fontSize:11, fontWeight:800, color:'#FF6B6B' }}>{opponentProfile?.displayName || 'LAWAN'}</div>
                <div style={{ fontFamily:"'Fredoka One',cursive", fontSize:28, color:'#FF6B6B' }}>{(opponentData?.score || 0).toLocaleString()}</div>
              </div>
            </div>
            <button onClick={() => { setActiveMatch?.(null); onHome() }} style={{
              fontFamily:"'Fredoka One',cursive", fontSize:16, padding:'12px 36px',
              background:'linear-gradient(135deg,#6C5CE7,#A29BFE)', color:'#fff',
              border:'none', borderRadius:14, cursor:'pointer', marginTop:12
            }}>
              KEMBALI
            </button>
          </div>
        </div>
      )
    }

    return (
      <div style={{ minHeight:'100dvh', background:bg }}>
        {showConfetti && <Confetti />}
        <WinModal
          emoji={stars >= 3 ? '🏆' : stars >= 2 ? '🎉' : stars >= 1 ? '😊' : '😔'}
          title={stars >= 3 ? 'LUAR BIASA!' : stars >= 2 ? 'BAGUS!' : stars >= 1 ? 'LUMAYAN!' : 'KEEP TRYING!'}
          subtitle={won ? `Akurasi ${accuracy}% — ${totalCorrect} dari ${diff.totalQ} benar!` : `Selesai! ${totalCorrect} dari ${diff.totalQ} benar.`}
          diffLabel={diffLabel}
          stats={[
            { label: 'Skor', value: score.toLocaleString(), color: '#6C5CE7' },
            { label: 'Benar', value: `${totalCorrect}/${won ? diff.totalQ : qIndex + 1}`, color: '#00B894' },
            { label: 'Akurasi', value: `${accuracy}%`, color: '#FDCB6E' },
            { label: 'Best streak', value: String(bestStreak), color: '#FD79A8' },
            { label: 'Salah', value: String(totalWrong), color: '#FF6B6B' },
          ]}
          stars={stars} coinReward={coinReward}
          highlight={isMultiplayer ? (multiplayerMatch?.winner === myUid ? '⚔️ KAMU MENANG!' : multiplayerMatch?.winner === 'draw' ? '🤝 HASIL SERI!' : multiplayerMatch?.winner ? '💀 KAMU KALAH!' : '') : (isNewBest ? '🏆 Skor baru terbaik!' : '')}
          onRestart={() => setPhase('ready')} onBack={onBack} onHome={onHome}
          dark={tc.dark} gameColor={accent}
          onRematch={isMultiplayer && multiplayerMatch?.winner ? () => matchCtx.requestRematch?.(multiplayerMatch) : null}
        />
      </div>
    )
  }

  // ─── Playing ────────────────────────────────────────────────────────────
  const q = questions[qIndex]
  if (!q) return null
  const comboLabel = getComboLabel(streak)
  const progPct = ((qIndex) / diff.totalQ) * 100

  return (
    <div style={{ minHeight:'100dvh', background:bg, display:'flex', flexDirection:'column' }}>
      {/* PvP Score Bar */}
      {isMultiplayer && (
        <PvpScoreBar
          opponentProfile={opponentProfile}
          opponentScore={opponentData?.score || 0}
          opponentExtra={`${opponentData?.correct || 0} benar`}
          opponentFinished={opponentData?.finished}
          myScore={score}
          opponentEmote={opponentEmote}
          myEmote={myEmoteData}
          onQuit={() => { matchCtx.quitMatch?.(multiplayerMatch?.id); setActiveMatch?.(null); onHome() }}
        />
      )}

      <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', padding:'12px 16px', gap:8 }}>
        <button onClick={onBack} style={{ background:'none', border:'none', color:textMuted, fontSize:20, cursor:'pointer' }}>←</button>
        <div style={{ display:'flex', gap:6, alignItems:'center' }}>
          <span style={{ fontSize:13, fontWeight:700, color:'#00B894' }}>✓ {totalCorrect}</span>
          <span style={{ fontSize:12, color:tc.muted }}>|</span>
          <span style={{ fontSize:13, fontWeight:700, color:'#FF6B6B' }}>✗ {totalWrong}</span>
        </div>
        <div style={{ fontFamily:"'Fredoka One',cursive", color:accent, fontSize:16 }}>{score.toLocaleString()}</div>
      </div>

      <div style={{ height:6, background:surface, margin:'0 16px', borderRadius:3, overflow:'hidden' }}>
        <div style={{ height:'100%', width:`${timerPct}%`, background:timerColor, borderRadius:3, transition:feedback?'none':'width 0.1s linear' }} />
      </div>

      <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', padding:'8px 16px 4px' }}>
        <div style={{ fontSize:13, color:textMuted }}>Soal <span style={{ fontWeight:700, color:accent }}>{qIndex + 1}</span>/{diff.totalQ}</div>
        <div style={{ fontSize:12, color:textMuted }}>{q.cat}</div>
      </div>
      <div style={{ height:4, background:surface, margin:'0 16px 8px', borderRadius:2, overflow:'hidden' }}>
        <div style={{ height:'100%', width:`${progPct}%`, background:accentLight, borderRadius:2, transition:'width 0.3s' }} />
      </div>

      <div style={{ textAlign:'center', height:24, display:'flex', alignItems:'center', justifyContent:'center' }}>
        {comboLabel && <div style={{ fontFamily:"'Fredoka One',cursive", fontSize:15, color:getComboColor(streak), animation:'qtPulse 0.6s ease infinite alternate' }}>{comboLabel}</div>}
        {streak > 0 && streak < 3 && <div style={{ fontSize:13, color:textMuted }}>🔥 Streak: {streak}</div>}
      </div>

      <div style={{ flex:1, display:'flex', flexDirection:'column', alignItems:'center', justifyContent:'center', padding:'0 20px', gap:16 }}>
        <div style={{ background:surface, borderRadius:20, padding:'24px 20px', width:'100%', maxWidth:420, textAlign:'center',
          border: feedback?.type==='correct'?'2px solid #00B894' : feedback?.type==='wrong'||feedback?.type==='timeout'?'2px solid #FF6B6B' : `2px solid ${tc.border}`,
          animation: feedback?.type==='wrong'||feedback?.type==='timeout'?'qtShake 0.4s ease' : feedback?.type==='correct'?'qtPop 0.3s ease' : 'none',
        }}>
          <div style={{ fontSize:32, marginBottom:8 }}>{q.cat}</div>
          <div style={{ fontFamily:"'Nunito',sans-serif", fontSize:16, fontWeight:700, color:textMain, lineHeight:1.5 }}>{q.q}</div>
        </div>

        {feedback && (
          <div style={{ textAlign:'center', animation:'qtFade 0.3s ease' }}>
            {feedback.type === 'correct' && <div style={{ color:'#00B894', fontWeight:700, fontSize:16 }}>✓ Benar! +{feedback.points} {feedback.multi > 1 ? `(×${feedback.multi})` : ''}</div>}
            {feedback.type === 'wrong' && <div style={{ color:'#FF6B6B', fontWeight:700, fontSize:16 }}>✗ Salah! Jawaban: {feedback.answer}</div>}
            {feedback.type === 'timeout' && <div style={{ color:'#FF6B6B', fontWeight:700, fontSize:16 }}>⏰ Waktu habis! Jawaban: {feedback.answer}</div>}
          </div>
        )}

        <div style={{ display:'flex', flexDirection:'column', gap:10, width:'100%', maxWidth:420 }}>
          {q.o.map((opt, i) => {
            const isSel = selectedAnswer === i; const isAns = i === q.a
            let btnBg = surface, btnColor = textMain, btnBorder = tc.border
            if (feedback) {
              if (isAns) { btnBg = '#00B894'; btnColor = '#fff'; btnBorder = '#00B894' }
              else if (isSel) { btnBg = '#FF6B6B'; btnColor = '#fff'; btnBorder = '#FF6B6B' }
              else { btnColor = textMuted }
            }
            return (
              <button key={i} onClick={() => handleAnswer(i)} disabled={!!feedback}
                style={{ fontFamily:"'Nunito',sans-serif", fontSize:15, fontWeight:700, padding:'14px 16px', background:btnBg, color:btnColor, border:`2px solid ${btnBorder}`, borderRadius:14, cursor:feedback?'default':'pointer', transition:'all 0.15s', opacity:feedback&&!isAns&&!isSel?0.5:1, textAlign:'left' }}>
                <span style={{ marginRight:8, opacity:0.6 }}>{String.fromCharCode(65+i)}.</span> {opt}
              </button>
            )
          })}
        </div>
      </div>

      {/* Battle Emotes */}
      {isMultiplayer && phase === 'playing' && (
        <BattleEmotes
          onSendEmote={sendEmote}
          incomingEmote={opponentEmote}
          senderName={opponentProfile?.displayName || 'Lawan'}
          disabled={!!feedback}
        />
      )}

      <style>{`
        @keyframes qtShake { 0%,100%{transform:translateX(0)} 20%{transform:translateX(-8px)} 40%{transform:translateX(8px)} 60%{transform:translateX(-6px)} 80%{transform:translateX(6px)} }
        @keyframes qtPop { 0%{transform:scale(1)} 50%{transform:scale(1.03)} 100%{transform:scale(1)} }
        @keyframes qtPulse { from{transform:scale(1)} to{transform:scale(1.08)} }
        @keyframes qtFade { from{opacity:0;transform:translateY(8px)} to{opacity:1;transform:translateY(0)} }
      `}</style>
    </div>
  )
}

import TutorialModal from '../../components/TutorialModal.jsx'
import Confetti from '../../components/Confetti.jsx'

const TUTORIAL_STEPS = [
  { emoji:'⚡', title:'Reaction Test', desc:'Uji kecepatan reaksimu! Seberapa cepat kamu bisa bereaksi?', tip:'Konsentrasi penuh dan jangan tekan terlalu cepat!' },
  { emoji:'🎯', title:'Mode Tap', desc:'Layar berubah hijau → tap secepat mungkin! Hati-hati, jangan tap saat masih merah.', tip:'Rata-rata reaksi manusia ~250ms. Bisa lebih cepat?' },
  { emoji:'🎨', title:'Mode Warna', desc:'Pilih warna yang benar dari pilihan! Perhatikan teks dan warnanya — bisa menipu!', tip:'Di Hard mode, teks dan warna berbeda (Stroop effect)!' },
  { emoji:'🧠', title:'Mode Sequence', desc:'Ingat urutan warna/angka yang muncul, lalu ulangi! Semakin panjang, semakin susah.', tip:'Buat pola mental untuk mengingat urutan lebih panjang.' },
]

import { useState, useEffect, useCallback, useRef } from 'react'
import { useSettings } from '../../context/SettingsContext.jsx'
import { useSound } from '../../hooks/useSound.js'
import { useProgress } from '../../context/ProgressContext.jsx'
import { useCoins } from '../../context/CoinContext.jsx'
import { useThemeColors } from '../../hooks/useThemeColors.js'
import { useMatch } from '../../context/MatchContext.jsx'
import { useAuth } from '../../context/AuthContext.jsx'
import { auth } from '../../firebase.js'
import { useMascot } from '../../context/MascotContext.jsx'
import PvpScoreBar from '../../components/PvpScoreBar.jsx'
import BattleEmotes from '../../components/BattleEmotes.jsx'
import { GameHeader, StatsBar, ActionButtons, WinModal, BestRecord } from '../../components/GameLayout.jsx'

const CFG = {
  easy:   { rounds: 5, seqStart: 3, seqMax: 6,  colorChoices: 3, stroopMode: false },
  medium: { rounds: 7, seqStart: 4, seqMax: 8,  colorChoices: 4, stroopMode: false },
  hard:   { rounds: 10, seqStart: 4, seqMax: 10, colorChoices: 5, stroopMode: true },
}

const MODES = [
  { id: 'tap', emoji: '🎯', name: 'Tap', desc: 'Tap saat hijau!' },
  { id: 'color', emoji: '🎨', name: 'Warna', desc: 'Pilih warna yang benar' },
  { id: 'sequence', emoji: '🧠', name: 'Sequence', desc: 'Ingat urutan warna' },
]

const SEQ_COLORS = [
  { name: 'Merah', color: '#FF6B6B' },
  { name: 'Biru', color: '#74B9FF' },
  { name: 'Hijau', color: '#00B894' },
  { name: 'Kuning', color: '#FDCB6E' },
  { name: 'Ungu', color: '#A29BFE' },
  { name: 'Pink', color: '#FD79A8' },
  { name: 'Tosca', color: '#00CEC9' },
  { name: 'Oranye', color: '#E17055' },
]

const COLOR_WORDS = ['Merah','Biru','Hijau','Kuning','Ungu','Pink','Tosca','Oranye']
const COLOR_VALUES = ['#FF6B6B','#74B9FF','#00B894','#FDCB6E','#A29BFE','#FD79A8','#00CEC9','#E17055']

export default function ReactionTest({ onBack, onHome, game, difficulty, multiplayerMatch }) {
  const { darkMode } = useSettings()
  const { play } = useSound()
  const { reportGameResult } = useProgress()
  const { earnCoins } = useCoins()
  const matchCtx = useMatch() || {}
  const { updateMatchState, finishMatch, setActiveMatch } = matchCtx
  const { uid: userId } = useAuth()
  const { triggerMascot } = useMascot()
  const tc = useThemeColors()
  const dark = tc.dark
  const bg = tc.bg
  const surface = tc.surface
  const textMain = tc.textMain
  const textMuted = tc.textMuted

  const cfg = CFG[difficulty.id]
  const [showTutorial, setShowTutorial] = useState(() => !localStorage.getItem('bp_tut_reaction-test'))
  const [showConfetti, setShowConfetti] = useState(false)
  const [mode, setMode] = useState(null) // null = mode select
  const [gameState, setGameState] = useState('idle') // idle, waiting, ready, early, result, done
  const [round, setRound] = useState(0)
  const [results, setResults] = useState([])
  const [resetKey, setResetKey] = useState(0)
  const [countdown, setCountdown] = useState(0) // 3,2,1,0
  const [bestAvg, setBestAvg] = useState(() => parseInt(localStorage.getItem(`react-best-${difficulty.id}-${mode}`) || '0'))

  // Tap mode
  const [tapPhase, setTapPhase] = useState('idle') // idle, waiting, go, early, result
  const waitTimerRef = useRef(null)
  const goTimeRef = useRef(null)

  // Color mode
  const [colorTarget, setColorTarget] = useState(null)
  const [colorChoices, setColorChoices] = useState([])
  const [colorDisplayText, setColorDisplayText] = useState('')
  const [colorDisplayColor, setColorDisplayColor] = useState('')
  const colorGoTimeRef = useRef(null)

  // Sequence mode
  const [seqPattern, setSeqPattern] = useState([])
  const [seqShowIdx, setSeqShowIdx] = useState(-1)
  const [seqUserInput, setSeqUserInput] = useState([])
  const [seqPhase, setSeqPhase] = useState('idle') // idle, showing, input, result
  const seqTimerRef = useRef(null)

  const isMultiplayer = !!multiplayerMatch
  const myUid = userId || auth.currentUser?.uid
  const opponentUid = isMultiplayer ? (multiplayerMatch.hostUid === myUid ? multiplayerMatch.guestUid : multiplayerMatch.hostUid) : null
  const opponentData = isMultiplayer ? multiplayerMatch.state?.[opponentUid] || { results: [], finished: false } : null
  const opponentProfile = isMultiplayer ? (multiplayerMatch.hostUid === myUid ? multiplayerMatch.guestProfile : multiplayerMatch.hostProfile) : null
  const opponentEmote = isMultiplayer ? opponentData?.emote : null
  const myEmoteData = isMultiplayer ? (multiplayerMatch.state?.[myUid]?.emote || null) : null

  // Send emote to opponent via match state
  const sendEmote = useCallback((emoji) => {
    if (!isMultiplayer || !multiplayerMatch?.id || !myUid) return
    const newState = {
      ...multiplayerMatch.state,
      [myUid]: { ...multiplayerMatch.state?.[myUid], emote: { emoji, ts: Date.now() } }
    }
    updateMatchState?.(multiplayerMatch?.id, newState)
  }, [isMultiplayer, multiplayerMatch?.id, multiplayerMatch?.state, myUid, updateMatchState])

  const bestKey = `reaction-test-best-${difficulty.id}`
  const [bestScore, setBestScore] = useState(() => parseInt(localStorage.getItem(bestKey) || '0'))

  // Per-mode best scores
  const getBestMode = (m) => parseInt(localStorage.getItem(`rt-best-${m}-${difficulty.id}`) || '0')
  const [bestPerMode] = useState({ tap: getBestMode('tap'), color: getBestMode('color'), sequence: getBestMode('sequence') })

  // Start mode with countdown
  const startMode = (modeId) => {
    play('click')
    setCountdown(3)
    const cdInterval = setInterval(() => {
      setCountdown(prev => {
        if (prev <= 1) {
          clearInterval(cdInterval)
          setMode(modeId)
          return 0
        }
        try { play('flip') } catch(e) {}
        return prev - 1
      })
    }, 700)
  }

  // Auto-start for multiplayer
  useEffect(() => {
    if (isMultiplayer && !mode) {
      startMode('sequence')
    }
  }, [isMultiplayer])

  // Sync results for multiplayer
  useEffect(() => {
    if (isMultiplayer && mode && myUid) {
      const newState = { 
        ...multiplayerMatch.state, 
        [myUid]: { 
          results, 
          round,
          finished: gameState === 'done' 
        } 
      }
      updateMatchState?.(multiplayerMatch?.id, newState)
    }
  }, [results, round, isMultiplayer, mode, gameState, myUid, multiplayerMatch?.id])

  // ═══════ TAP MODE ═══════
  const startTapRound = useCallback(() => {
    setTapPhase('waiting')
    const delay = 1500 + Math.random() * 3000
    waitTimerRef.current = setTimeout(() => {
      setTapPhase('go')
      goTimeRef.current = Date.now()
    }, delay)
  }, [])

  const handleTapClick = useCallback(() => {
    if (tapPhase === 'waiting') {
      clearTimeout(waitTimerRef.current)
      setTapPhase('early')
      try { play('mismatch') } catch(e) {}
      setTimeout(() => {
        setResults(r => [...r, { type: 'tap', time: -1, label: 'Terlalu cepat!' }])
        setRound(r => r + 1)
        setTapPhase('idle')
      }, 1200)
      return
    }
    if (tapPhase === 'go') {
      const reactionTime = Date.now() - goTimeRef.current
      try { play('match') } catch(e) {}
      const rating = reactionTime < 150 ? '⚡ Lightning!' : reactionTime < 250 ? '🔥 Fast!' : reactionTime < 350 ? '👍 Good' : reactionTime < 500 ? '😐 Slow...' : '🐢 Too slow!'
      setResults(r => [...r, { type: 'tap', time: reactionTime, label: `${reactionTime}ms`, rating }])
      setTapPhase('result')
      setTimeout(() => {
        setRound(r => r + 1)
        setTapPhase('idle')
      }, 800)
    }
  }, [tapPhase, play])

  // ═══════ COLOR MODE ═══════
  const startColorRound = useCallback(() => {
    const targetIdx = Math.floor(Math.random() * Math.min(cfg.colorChoices + 2, SEQ_COLORS.length))
    const target = SEQ_COLORS[targetIdx]

    // Stroop effect for hard mode: display text is a DIFFERENT color name, colored in the TARGET color
    let displayText = target.name
    let displayColor = target.color
    if (cfg.stroopMode && Math.random() < 0.6) {
      const otherIdx = (targetIdx + 1 + Math.floor(Math.random() * (SEQ_COLORS.length - 1))) % SEQ_COLORS.length
      displayText = SEQ_COLORS[otherIdx].name
      // The instruction is: "pilih warna yang DITAMPILKAN" (the actual color shown, not the text)
    }

    setColorTarget(target)
    setColorDisplayText(displayText)
    setColorDisplayColor(displayColor)

    // Generate choices
    const choiceSet = new Set([targetIdx])
    while (choiceSet.size < Math.min(cfg.colorChoices, SEQ_COLORS.length)) {
      choiceSet.add(Math.floor(Math.random() * SEQ_COLORS.length))
    }
    const shuffled = [...choiceSet].sort(() => Math.random() - 0.5).map(i => SEQ_COLORS[i])
    setColorChoices(shuffled)
    colorGoTimeRef.current = Date.now()
    setGameState('ready')
  }, [cfg])

  const handleColorChoice = useCallback((chosen) => {
    if (gameState !== 'ready') return
    const reactionTime = Date.now() - colorGoTimeRef.current
    const correct = chosen.name === colorTarget.name
    if (correct) {
      try { play('match') } catch(e) {}
    } else {
      try { play('mismatch') } catch(e) {}
    }
    const rating = !correct ? '❌ Miss' : reactionTime < 300 ? '⚡ Lightning!' : reactionTime < 500 ? '🔥 Fast!' : reactionTime < 800 ? '👍 Good' : '😐 Slow...'
    setResults(r => [...r, { type: 'color', time: correct ? reactionTime : -1, correct, label: correct ? `${reactionTime}ms` : 'Salah!', rating }])
    setGameState('result')
    setTimeout(() => {
      setRound(r => r + 1)
      setGameState('idle')
    }, 800)
  }, [gameState, colorTarget, play])

  // ═══════ SEQUENCE MODE ═══════
  const startSeqRound = useCallback((roundNum) => {
    const len = Math.min(cfg.seqStart + roundNum, cfg.seqMax)
    const pattern = Array.from({ length: len }, () => Math.floor(Math.random() * Math.min(5, SEQ_COLORS.length)))
    setSeqPattern(pattern)
    setSeqUserInput([])
    setSeqPhase('showing')
    setSeqShowIdx(-1)

    // Show sequence one by one
    let idx = 0
    const showNext = () => {
      if (idx < pattern.length) {
        setSeqShowIdx(pattern[idx])
        idx++
        seqTimerRef.current = setTimeout(() => {
          setSeqShowIdx(-1)
          seqTimerRef.current = setTimeout(showNext, 300)
        }, 600)
      } else {
        setSeqPhase('input')
        colorGoTimeRef.current = Date.now()
      }
    }
    seqTimerRef.current = setTimeout(showNext, 500)
  }, [cfg])

  const handleSeqInput = useCallback((colorIdx) => {
    if (seqPhase !== 'input') return
    const newInput = [...seqUserInput, colorIdx]
    setSeqUserInput(newInput)

    const correctSoFar = newInput.every((v, i) => v === seqPattern[i])
    if (!correctSoFar) {
      try { play('mismatch') } catch(e) {}
      const reactionTime = Date.now() - colorGoTimeRef.current
      setResults(r => [...r, { type: 'seq', time: -1, correct: false, label: 'Salah!' }])
      setSeqPhase('result')
      setTimeout(() => {
        setRound(r => r + 1)
        setSeqPhase('idle')
      }, 1000)
      return
    }

    try { play('flip') } catch(e) {}
    if (newInput.length === seqPattern.length) {
      // Complete!
      const reactionTime = Date.now() - colorGoTimeRef.current
      try { play('match') } catch(e) {}
      setResults(r => [...r, { type: 'seq', time: reactionTime, correct: true, seqLen: seqPattern.length, label: `${seqPattern.length} benar` }])
      setSeqPhase('result')
      setTimeout(() => {
        setRound(r => r + 1)
        setSeqPhase('idle')
      }, 800)
    }
  }, [seqPhase, seqUserInput, seqPattern, play])

  // ═══════ ROUND MANAGEMENT ═══════
  useEffect(() => {
    if (!mode) return
    if (round >= cfg.rounds) {
      // Game done!
      finishGame()
      return
    }
    if (mode === 'tap' && tapPhase === 'idle' && round < cfg.rounds) {
      startTapRound()
    }
    if (mode === 'color' && gameState === 'idle' && round < cfg.rounds) {
      setTimeout(() => startColorRound(), 400)
    }
    if (mode === 'sequence' && seqPhase === 'idle' && round < cfg.rounds) {
      setTimeout(() => startSeqRound(round), 400)
    }
  }, [round, mode, tapPhase, gameState, seqPhase])

  // Normal game completion
  useEffect(() => {
    if (gameState === 'done' && round >= cfg.rounds) {
      const validResults = results.filter(r => r.time > 0)
      const avgTime = validResults.length ? Math.round(validResults.reduce((a, b) => a + b.time, 0) / validResults.length) : 0

      // Mascot Reactions based on average time
      if (!isMultiplayer && avgTime > 0) {
        if (avgTime < 250) triggerMascot('Mata elang! Refleks kamu dewa banget! ⚡', 'excited')
        else if (avgTime < 400) triggerMascot('Bagus! Refleks kamu di atas rata-rata! 🔥', 'happy')
        else if (avgTime > 600) triggerMascot('Waduh, sepertinya kamu butuh kopi... ☕', 'sad')
      }

      if (avgTime < bestAvg || bestAvg === 0) setBestAvg(avgTime)
      localStorage.setItem(`react-best-${difficulty.id}-${mode}`, Math.min(avgTime, bestAvg || 9999))

      let stars = 1
      if (mode === 'tap') { stars = avgTime < 250 ? 3 : avgTime < 400 ? 2 : 1 }
      else if (mode === 'color') { stars = avgTime < 500 ? 3 : avgTime < 800 ? 2 : 1 }
      else { stars = avgTime < 800 ? 3 : avgTime < 1200 ? 2 : 1 }

      if (!isMultiplayer) {
        reportGameResult({ gameId: 'reaction-test', difficultyId: difficulty.id, won: true, score: Math.max(0, 1000 - avgTime), stars, timeSec: 0 })
        const coinAmount = { easy: 10, medium: 15, hard: 25 }[difficulty.id] + (stars === 3 ? 10 : 0)
        earnCoins(coinAmount, `Menang Reaction Test (${difficulty.id})`)
      }
    }
  }, [gameState, round, results, cfg.rounds, mode, bestAvg, difficulty.id, earnCoins, reportGameResult, isMultiplayer, triggerMascot])

  const finishGame = useCallback(() => {
    setGameState('done')
    const validResults = results.filter(r => r.time > 0)
    const avgTime = validResults.length > 0 ? Math.round(validResults.reduce((s, r) => s + r.time, 0) / validResults.length) : 9999
    const accuracy = results.length > 0 ? Math.round((validResults.length / results.length) * 100) : 0

    // Score: lower avg time = higher score, + accuracy bonus
    let score = Math.max(0, 2000 - avgTime * 2) + accuracy * 5
    if (mode === 'sequence') {
      const totalSeqLen = validResults.reduce((s, r) => s + (r.seqLen || 0), 0)
      score = totalSeqLen * 100 + accuracy * 3
    }
    score = Math.round(score)

    const stars = accuracy >= 90 ? 3 : accuracy >= 70 ? 2 : 1
    const coinReward = { easy: 15, medium: 25, hard: 40 }
    let coinAmt = (coinReward[difficulty.id] || 15) + Math.floor(score / 100)
    if (stars === 3) coinAmt += 20
    const won = accuracy >= 50

    if (won) {
      setShowConfetti(true)
      try { play('win') } catch(e) {}
    }

    earnCoins(coinAmt, `Reaction Test ${mode} (${difficulty.id})`)
    reportGameResult({
      gameId: 'reaction-test', difficultyId: difficulty.id,
      won, score, stars, timeSec: Math.round(avgTime / 1000 * cfg.rounds),
    })

    // Save best
    if (score > bestScore) {
      localStorage.setItem(bestKey, score)
      setBestScore(score)
    }
    // Save per-mode best
    const modeKey = `rt-best-${mode}-${difficulty.id}`
    const prevModeBest = parseInt(localStorage.getItem(modeKey) || '0')
    if (score > prevModeBest) localStorage.setItem(modeKey, score)

    if (isMultiplayer) {
       // Compare performance
       let isWinner = false
       if (mode === 'sequence') {
          // Compare scores for sequence mode
          const oppValid = opponentData.results.filter(r => r.time > 0)
          const oppAcc = opponentData.results.length > 0 ? Math.round((oppValid.length / opponentData.results.length) * 100) : 0
          const oppSeqLen = oppValid.reduce((s, r) => s + (r.seqLen || 0), 0)
          const oppScore = Math.round(oppSeqLen * 100 + oppAcc * 3)
          isWinner = score > oppScore
       } else {
          // Compare avg times for other modes
          const myAvg = avgTime
          const oppResults = opponentData.results.filter(r => r.time > 0)
          const oppAvg = oppResults.length > 0 ? Math.round(oppResults.reduce((s, r) => s + r.time, 0) / oppResults.length) : 9999
          isWinner = myAvg < oppAvg
       }

       if (isWinner) finishMatch?.(multiplayerMatch.id, myUid)
    }
  }, [results, mode, cfg, difficulty.id, bestScore, isMultiplayer, opponentData, multiplayerMatch, userId])

  const restart = () => {
    if (isMultiplayer) {
      setActiveMatch(null)
      onBack()
      return
    }
    setMode(null)
    setRound(0)
    setResults([])
    setGameState('idle')
    setTapPhase('idle')
    setSeqPhase('idle')
    setShowConfetti(false)
    setResetKey(k => k + 1)
    clearTimeout(waitTimerRef.current)
    clearTimeout(seqTimerRef.current)
  }

  useEffect(() => {
    return () => {
      clearTimeout(waitTimerRef.current)
      clearTimeout(seqTimerRef.current)
    }
  }, [])

  // ═══════ COMPUTE FINAL STATS ═══════
  const validResults = results.filter(r => r.time > 0)
  const avgTime = validResults.length > 0 ? Math.round(validResults.reduce((s, r) => s + r.time, 0) / validResults.length) : 0
  const accuracy = results.length > 0 ? Math.round((validResults.length / results.length) * 100) : 0
  let finalScore = Math.max(0, 2000 - avgTime * 2) + accuracy * 5
  if (mode === 'sequence') {
    const totalSeqLen = validResults.reduce((s, r) => s + (r.seqLen || 0), 0)
    finalScore = totalSeqLen * 100 + accuracy * 3
  }
  finalScore = Math.round(finalScore)
  const finalStars = accuracy >= 90 ? 3 : accuracy >= 70 ? 2 : 1
  const coinAmt = ({ easy: 15, medium: 25, hard: 40 }[difficulty.id] || 15) + Math.floor(finalScore / 100) + (finalStars === 3 ? 20 : 0)

  const duelStats = isMultiplayer ? [
    { 
      label: mode === 'sequence' ? 'Skor' : 'Avg Time', 
      myValue: mode === 'sequence' ? finalScore : avgTime, 
      oppValue: (() => {
        const oppResults = opponentData?.results || []
        const oppValid = oppResults.filter(r => r.time > 0)
        if (mode === 'sequence') {
          const oppAcc = oppResults.length > 0 ? Math.round((oppValid.length / oppResults.length) * 100) : 0
          const oppSeqLen = oppValid.reduce((s, r) => s + (r.seqLen || 0), 0)
          return Math.round(oppSeqLen * 100 + oppAcc * 3)
        }
        return oppValid.length > 0 ? Math.round(oppValid.reduce((s, r) => s + r.time, 0) / oppValid.length) : 0
      })(), 
      color: '#6C5CE7' 
    },
    { 
      label: 'Akurasi', 
      myValue: accuracy, 
      oppValue: (() => {
        const oppResults = opponentData?.results || []
        const oppValid = oppResults.filter(r => r.time > 0)
        return oppResults.length > 0 ? Math.round((oppValid.length / oppResults.length) * 100) : 0
      })(), 
      color: '#00B894' 
    },
  ] : null

  // ═══════ COUNTDOWN SCREEN ═══════
  if (countdown > 0) {
    return (
      <div style={{
        minHeight: '100dvh', background: bg, display: 'flex',
        alignItems: 'center', justifyContent: 'center', flexDirection: 'column',
      }}>
        <div style={{
          fontSize: 120, fontFamily: "'Fredoka One',cursive", color: '#A29BFE',
          animation: 'cdPop 0.6s ease', key: countdown,
          textShadow: '0 0 40px rgba(162,155,254,0.4)',
        }}>
          {countdown}
        </div>
        <div style={{ fontSize: 14, color: tc.textMuted, marginTop: 8 }}>Bersiap...</div>
        <style>{`@keyframes cdPop { 0% { transform: scale(2); opacity: 0; } 40% { transform: scale(0.9); opacity: 1; } 100% { transform: scale(1); } }`}</style>
      </div>
    )
  }

  // ═══════ MODE SELECT SCREEN ═══════
  if (!mode) {
    return (
      <div style={{ minHeight: '100dvh', background: bg, padding: '24px 16px 80px' }}>
        {showTutorial && (
          <TutorialModal steps={TUTORIAL_STEPS} storageKey="bp_tut_reaction-test"
            onClose={() => setShowTutorial(false)} />
        )}
        <GameHeader emoji="⚡" title="Reaction Test" subtitle="Pilih mode permainan"
          diffId={difficulty.id} onBack={onBack} dark={dark} />

        <div style={{ maxWidth: 420, margin: '0 auto', display: 'flex', flexDirection: 'column', gap: 14 }}>
          {MODES.map(m => (
            <button key={m.id} onClick={() => startMode(m.id)}
              style={{
                background: tc.surface, border: `2px solid ${tc.borderCol}`,
                borderRadius: 20, padding: '24px 20px', cursor: 'pointer',
                display: 'flex', alignItems: 'center', gap: 16, textAlign: 'left',
                transition: 'all 0.15s', position: 'relative',
              }}
              onMouseEnter={e => { e.currentTarget.style.borderColor = '#A29BFE'; e.currentTarget.style.transform = 'scale(1.02)' }}
              onMouseLeave={e => { e.currentTarget.style.borderColor = tc.borderCol; e.currentTarget.style.transform = 'scale(1)' }}
            >
              <span style={{ fontSize: 40 }}>{m.emoji}</span>
              <div style={{ flex: 1 }}>
                <div style={{ fontFamily: "'Fredoka One',cursive", fontSize: 20, color: textMain }}>{m.name}</div>
                <div style={{ fontSize: 13, color: tc.textMuted, marginTop: 2 }}>{m.desc}</div>
              </div>
              {bestPerMode[m.id] > 0 && (
                <div style={{
                  textAlign: 'right', fontSize: 11, color: '#A29BFE',
                  fontFamily: "'Fredoka One',cursive",
                }}>
                  <div style={{ fontSize: 16 }}>{bestPerMode[m.id]}</div>
                  <div style={{ fontSize: 9, color: tc.textMuted }}>best</div>
                </div>
              )}
            </button>
          ))}
        </div>

        {bestScore > 0 && (
          <BestRecord label="Skor Terbaik" value={bestScore.toLocaleString()} dark={dark} color="#A29BFE" />
        )}
      </div>
    )
  }

  // ═══════ TAP MODE SCREEN ═══════
  if (mode === 'tap' && gameState !== 'done') {
    const tapBg = tapPhase === 'waiting' ? '#C0392B' : tapPhase === 'go' ? '#00B894' : tapPhase === 'early' ? '#E17055' : tapPhase === 'result' ? '#2d3436' : bg
    const tapText = tapPhase === 'waiting' ? 'Tunggu...' : tapPhase === 'go' ? 'TAP SEKARANG!' : tapPhase === 'early' ? 'Terlalu cepat! ❌' : tapPhase === 'result' ? `${results[results.length-1]?.label || ''}` : ''

    return (
      <div onClick={handleTapClick}
        style={{
          minHeight: '100dvh', background: tapBg, display: 'flex', flexDirection: 'column',
          alignItems: 'center', justifyContent: 'center', cursor: 'pointer',
          transition: 'background 0.15s', userSelect: 'none',
        }}>
        <div style={{ position: 'absolute', top: 16, left: 16, right: 16, display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <button onClick={(e) => { e.stopPropagation(); restart() }} style={{
            background: 'rgba(255,255,255,0.15)', border: 'none', color: '#fff',
            borderRadius: 8, padding: '6px 12px', fontSize: 14, cursor: 'pointer',
          }}>← Kembali</button>
          <span style={{ color: '#fff', fontFamily: "'Fredoka One',cursive", fontSize: 14 }}>
            {round + 1}/{cfg.rounds}
          </span>
        </div>
        {/* Round progress bar */}
        <div style={{ position: 'absolute', top: 52, left: 16, right: 16 }}>
          <div style={{ height: 4, background: 'rgba(255,255,255,0.15)', borderRadius: 100, overflow: 'hidden' }}>
            <div style={{ height: '100%', width: `${(round / cfg.rounds) * 100}%`, background: 'rgba(255,255,255,0.6)', borderRadius: 100, transition: 'width 0.4s ease' }} />
          </div>
        </div>

        <div style={{ fontSize: 60, marginBottom: 16 }}>
          {tapPhase === 'waiting' ? '🔴' : tapPhase === 'go' ? '🟢' : tapPhase === 'early' ? '❌' : '⚡'}
        </div>
        <div style={{ fontFamily: "'Fredoka One',cursive", fontSize: 28, color: '#fff', textAlign: 'center' }}>
          {tapText}
        </div>
        {tapPhase === 'result' && results.length > 0 && (
          <div>
            <div style={{ color: '#FFD700', fontSize: 18, fontWeight: 800, fontFamily: "'Fredoka One',cursive", marginTop: 6, animation: 'winFadeIn 0.3s ease' }}>
              {results[results.length - 1]?.rating || ''}
            </div>
            <div style={{ color: 'rgba(255,255,255,0.7)', fontSize: 14, marginTop: 8 }}>
              Rata-rata: {Math.round(validResults.reduce((s,r)=>s+r.time,0) / Math.max(1, validResults.length))}ms
            </div>
            {isMultiplayer && (
               <div style={{ marginTop: 12, borderTop: '1px solid rgba(255,255,255,0.1)', paddingTop: 12 }}>
                  <div style={{ fontSize: 10, color: 'rgba(255,255,255,0.5)', marginBottom: 4 }}>REAKSI {opponentProfile?.displayName?.toUpperCase() || 'LAWAN'}</div>
                  <div style={{ color: '#FDCB6E', fontFamily: "'Fredoka One',cursive" }}>
                     {opponentData.results[round]?.label || 'Menunggu...'}
                  </div>
               </div>
            )}
          </div>
        )}

        {/* Mini results */}
        <div style={{ position: 'absolute', bottom: 30, display: 'flex', gap: 8, flexWrap: 'wrap', justifyContent: 'center', padding: '0 20px' }}>
          {results.map((r, i) => (
            <span key={i} style={{
              background: r.time > 0 ? 'rgba(0,184,148,0.3)' : 'rgba(255,107,107,0.3)',
              color: '#fff', borderRadius: 100, padding: '4px 10px', fontSize: 11, fontWeight: 700,
            }}>
              {r.label}
            </span>
          ))}
        </div>
      </div>
    )
  }

  // ═══════ COLOR MODE SCREEN ═══════
  if (mode === 'color' && gameState !== 'done') {
    return (
      <div style={{ minHeight: '100dvh', background: bg, padding: '24px 16px 80px' }}>
        <div style={{ position: 'relative' }}>
          <GameHeader emoji="🎨" title="Warna" subtitle={cfg.stroopMode ? 'Pilih WARNA teks (bukan kata!)' : 'Pilih warna yang ditampilkan'}
            diffId={difficulty.id} onBack={restart} dark={dark} />
        </div>

        <div style={{ textAlign: 'center', marginBottom: 8, color: tc.textMuted, fontSize: 13, fontFamily: "'Fredoka One',cursive" }}>
          Round {round + 1}/{cfg.rounds}
        </div>
        {/* Progress bar */}
        <div style={{ maxWidth: 300, margin: '0 auto 12px' }}>
          <div style={{ height: 4, background: dark ? 'rgba(255,255,255,0.08)' : 'rgba(0,0,0,0.06)', borderRadius: 100, overflow: 'hidden' }}>
            <div style={{ height: '100%', width: `${(round / cfg.rounds) * 100}%`, background: '#A29BFE', borderRadius: 100, transition: 'width 0.4s ease' }} />
          </div>
        </div>

        {/* Display target */}
        {gameState === 'ready' && colorTarget && (
          <div style={{
            textAlign: 'center', margin: '30px auto', padding: '30px 20px',
            background: tc.surface, borderRadius: 24, maxWidth: 300,
            border: `2px solid ${tc.borderCol}`,
          }}>
            <div style={{ fontSize: 13, color: tc.textMuted, marginBottom: 8 }}>
              {cfg.stroopMode ? 'Pilih WARNA teks ini:' : 'Warna apa ini?'}
            </div>
            <div style={{
              fontFamily: "'Fredoka One',cursive", fontSize: 40,
              color: colorDisplayColor,
            }}>
              {cfg.stroopMode ? colorDisplayText : '●'}
            </div>
          </div>
        )}

        {/* Choices */}
        {gameState === 'ready' && (
          <div style={{ display: 'grid', gridTemplateColumns: `repeat(${Math.min(colorChoices.length, 3)}, 1fr)`, gap: 12, maxWidth: 400, margin: '20px auto' }}>
            {colorChoices.map(c => (
              <button key={c.name} onClick={() => handleColorChoice(c)}
                style={{
                  background: c.color, border: 'none', borderRadius: 16,
                  padding: '20px 12px', cursor: 'pointer', transition: 'transform 0.1s',
                }}
                onMouseEnter={e => e.currentTarget.style.transform = 'scale(1.05)'}
                onMouseLeave={e => e.currentTarget.style.transform = 'scale(1)'}
              >
                <div style={{ color: '#fff', fontFamily: "'Fredoka One',cursive", fontSize: 14, textShadow: '0 1px 3px rgba(0,0,0,0.3)' }}>
                  {c.name}
                </div>
              </button>
            ))}
          </div>
        )}

        {gameState === 'result' && (
          <div style={{ textAlign: 'center', margin: '40px 0' }}>
            <div style={{ fontSize: 40 }}>{results[results.length - 1]?.correct ? '✅' : '❌'}</div>
            <div style={{ color: '#FFD700', fontSize: 16, fontWeight: 800, fontFamily: "'Fredoka One',cursive", marginTop: 6, animation: 'winFadeIn 0.3s ease' }}>
              {results[results.length - 1]?.rating || ''}
            </div>
          </div>
        )}

        {/* Mini results */}
        <div style={{ display: 'flex', gap: 6, flexWrap: 'wrap', justifyContent: 'center', marginTop: 20 }}>
          {results.map((r, i) => (
            <span key={i} style={{
              background: r.time > 0 ? (dark ? 'rgba(0,184,148,0.15)' : '#E8FFF0') : (dark ? 'rgba(255,107,107,0.15)' : '#FFF0F0'),
              color: r.time > 0 ? '#00B894' : '#FF6B6B',
              borderRadius: 100, padding: '4px 10px', fontSize: 11, fontWeight: 700,
            }}>
              {r.label}
            </span>
          ))}
        </div>
      </div>
    )
  }

  // ═══════ SEQUENCE MODE SCREEN ═══════
  if (mode === 'sequence' && gameState !== 'done') {
    const seqColors = SEQ_COLORS.slice(0, 5)
    return (
      <div style={{ minHeight: '100dvh', background: bg, padding: '24px 16px 80px' }}>
        <GameHeader emoji="🧠" title="Sequence" subtitle="Ingat urutan warna!"
          diffId={difficulty.id} onBack={restart} dark={dark} />

        <div style={{ textAlign: 'center', marginBottom: 8, color: tc.textMuted, fontSize: 13, fontFamily: "'Fredoka One',cursive" }}>
          Round {round + 1}/{cfg.rounds} — Panjang: {seqPattern.length}
        </div>
        {/* Progress bar */}
        <div style={{ maxWidth: 300, margin: '0 auto 12px' }}>
          <div style={{ height: 4, background: dark ? 'rgba(255,255,255,0.08)' : 'rgba(0,0,0,0.06)', borderRadius: 100, overflow: 'hidden' }}>
            <div style={{ height: '100%', width: `${(round / cfg.rounds) * 100}%`, background: '#A29BFE', borderRadius: 100, transition: 'width 0.4s ease' }} />
          </div>
        </div>

        {/* Showing phase */}
        {seqPhase === 'showing' && (
          <div style={{ textAlign: 'center', margin: '40px 0' }}>
            <div style={{ fontSize: 16, color: tc.textMuted, marginBottom: 20 }}>Perhatikan urutan...</div>
            <div style={{ display: 'flex', gap: 12, justifyContent: 'center', flexWrap: 'wrap' }}>
              {seqColors.map((c, i) => (
                <div key={i} style={{
                  width: 60, height: 60, borderRadius: 14,
                  background: seqShowIdx === i ? c.color : (dark ? 'rgba(255,255,255,0.06)' : 'rgba(0,0,0,0.06)'),
                  border: `3px solid ${seqShowIdx === i ? c.color : 'transparent'}`,
                  transition: 'all 0.2s', transform: seqShowIdx === i ? 'scale(1.15)' : 'scale(1)',
                  boxShadow: seqShowIdx === i ? `0 0 20px ${c.color}55` : 'none',
                }} />
              ))}
            </div>
          </div>
        )}

        {/* Input phase */}
        {seqPhase === 'input' && (
          <div style={{ textAlign: 'center', margin: '30px 0' }}>
            <div style={{ fontSize: 16, color: textMain, marginBottom: 12, fontFamily: "'Fredoka One',cursive" }}>
              Ulangi urutan! ({seqUserInput.length}/{seqPattern.length})
            </div>
            {/* Progress dots */}
            <div style={{ display: 'flex', gap: 6, justifyContent: 'center', marginBottom: 20 }}>
              {seqPattern.map((_, i) => (
                <div key={i} style={{
                  width: 12, height: 12, borderRadius: '50%',
                  background: i < seqUserInput.length ? SEQ_COLORS[seqPattern[i]].color : (dark ? 'rgba(255,255,255,0.1)' : 'rgba(0,0,0,0.1)'),
                  transition: 'all 0.2s',
                }} />
              ))}
            </div>
            {/* Input buttons */}
            <div style={{ display: 'flex', gap: 12, justifyContent: 'center', flexWrap: 'wrap' }}>
              {seqColors.map((c, i) => (
                <button key={i} onClick={() => handleSeqInput(i)}
                  style={{
                    width: 65, height: 65, borderRadius: 16, border: 'none',
                    background: c.color, cursor: 'pointer', transition: 'transform 0.1s',
                    boxShadow: `0 4px 12px ${c.color}44`,
                  }}
                  onMouseEnter={e => e.currentTarget.style.transform = 'scale(1.08)'}
                  onMouseLeave={e => e.currentTarget.style.transform = 'scale(1)'}
                >
                  <span style={{ color: '#fff', fontFamily: "'Fredoka One',cursive", fontSize: 11, textShadow: '0 1px 2px rgba(0,0,0,0.3)' }}>
                    {c.name}
                  </span>
                </button>
              ))}
            </div>
          </div>
        )}

        {seqPhase === 'result' && (
          <div style={{ textAlign: 'center', fontSize: 40, margin: '40px 0' }}>
            {results[results.length - 1]?.correct ? '✅' : '❌'}
          </div>
        )}

        {/* Mini results */}
        <div style={{ display: 'flex', gap: 6, flexWrap: 'wrap', justifyContent: 'center', marginTop: 20 }}>
          {results.map((r, i) => (
            <span key={i} style={{
              background: r.correct ? (dark ? 'rgba(0,184,148,0.15)' : '#E8FFF0') : (dark ? 'rgba(255,107,107,0.15)' : '#FFF0F0'),
              color: r.correct ? '#00B894' : '#FF6B6B',
              borderRadius: 100, padding: '4px 10px', fontSize: 11, fontWeight: 700,
            }}>
              {r.label}
            </span>
          ))}
        </div>

        {/* Battle Emotes */}
        {isMultiplayer && (
          <BattleEmotes
            onSendEmote={sendEmote}
            incomingEmote={opponentEmote}
            senderName={opponentProfile?.displayName || 'Lawan'}
            disabled={seqPhase === 'showing'}
          />
        )}
      </div>
    )
  }

  // ═══════ DONE SCREEN ═══════
  const maxTime = Math.max(...results.map(r => r.time > 0 ? r.time : 0), 1)

  return (
    <div style={{ minHeight: '100dvh', background: bg, padding: '24px 16px 80px' }}>
      {showConfetti && <Confetti />}

      {/* Results chart behind modal */}
      {mode === 'tap' && results.length > 0 && (
        <div style={{
