                    animation: `barGrow 0.5s ${i * 0.1}s ease both`,
                  }} />
                  <div style={{ fontSize: 9, color: tc.textMuted, marginTop: 3 }}>R{i+1}</div>
                </div>
              )
            })}
          </div>
          <div style={{ display: 'flex', justifyContent: 'center', gap: 12, marginTop: 10, fontSize: 10, color: tc.textMuted }}>
