}

const rand  = (a, b) => a + Math.random() * (b - a)
const dist2 = (a, b) => (a.x-b.x)**2 + (a.y-b.y)**2

// ─── Food Types ───────────────────────────────────────────────────────────────
const FOOD_TYPE = { NORMAL: 'normal', GOLDEN: 'golden', POISON: 'poison', SHIELD: 'shield' }

// ─── Helpers ──────────────────────────────────────────────────────────────────
function spawnFood(mapSize) {
  return {
    x: rand(60, mapSize - 60),
    y: rand(60, mapSize - 60),
    color: FOOD_COLORS[Math.floor(Math.random() * FOOD_COLORS.length)],
    r: rand(5, 9),
    pulse: rand(0, Math.PI * 2),
    type: FOOD_TYPE.NORMAL,
  }
}

function spawnGoldenFood(mapSize) {
  return {
    x: rand(100, mapSize - 100),
    y: rand(100, mapSize - 100),
    color: '#FFD700',
    r: rand(9, 13),
    pulse: rand(0, Math.PI * 2),
    type: FOOD_TYPE.GOLDEN,
    ttl: 600, // ~10 seconds at 60fps
    sparkle: 0,
  }
}

function spawnPoisonFood(mapSize) {
  return {
    x: rand(100, mapSize - 100),
    y: rand(100, mapSize - 100),
    color: '#2ECC40',
    r: rand(6, 10),
    pulse: rand(0, Math.PI * 2),
    type: FOOD_TYPE.POISON,
    toxicPulse: 0,
  }
}

function spawnShieldPowerup(mapSize) {
  return {
    x: rand(120, mapSize - 120),
    y: rand(120, mapSize - 120),
    color: '#00BFFF',
    r: rand(10, 14),
    pulse: rand(0, Math.PI * 2),
    type: FOOD_TYPE.SHIELD,
    ttl: 480, // ~8 seconds at 60fps
    rotation: 0,
  }
}

function makeWorm(x, y, angle, len = 24) {
  const segs = []
  for (let i = 0; i < len; i++) {
    segs.push({ x: x - Math.cos(angle) * i * SEG_GAP, y: y - Math.sin(angle) * i * SEG_GAP })
  }
  return { segs, angle, score: 0, alive: true, respawnTimer: 0 }
}

// ─── AI brain — smarter with aggression, avoidance, and encircle ─────────────
function botThink(bot, foods, mapSize, cfg, allWorms) {
  const head = bot.segs[0]
  const margin = 150
  const myLen = bot.segs.length

  // Wall avoidance — highest priority
  const nearWall = head.x < margin || head.x > mapSize - margin ||
                   head.y < margin || head.y > mapSize - margin
  if (nearWall) {
    const toCenter = Math.atan2(mapSize / 2 - head.y, mapSize / 2 - head.x)
    let da = toCenter - bot.angle
    while (da >  Math.PI) da -= Math.PI * 2
    while (da < -Math.PI) da += Math.PI * 2
    bot.angle += da * 0.22
    bot.wantBoost = false
    return
  }

  // Poison avoidance — flee from nearby poison food
  let poisonAngle = null
  let poisonDist = Infinity
  for (const f of foods) {
    if (f.type !== FOOD_TYPE.POISON) continue
    const d2 = dist2(head, f)
    if (d2 < 80 * 80 && d2 < poisonDist) {
      poisonDist = d2
      poisonAngle = Math.atan2(head.y - f.y, head.x - f.x)
    }
  }
  if (poisonAngle !== null && poisonDist < 50 * 50) {
    let da = poisonAngle - bot.angle
    while (da >  Math.PI) da -= Math.PI * 2
    while (da < -Math.PI) da += Math.PI * 2
    bot.angle += da * 0.2
    bot.wantBoost = false
    return
  }

  // Danger check — avoid bigger worms' bodies
  let dangerAngle = null
  let dangerDist = Infinity
  for (const w of allWorms) {
    if (w === bot || !w.alive) continue
    // Only fear worms that are bigger
    if (w.segs.length <= myLen * 0.8) continue
    for (let i = 0; i < w.segs.length; i += 3) {
      const d2 = dist2(head, w.segs[i])
      if (d2 < 100 * 100 && d2 < dangerDist) {
        dangerDist = d2
        dangerAngle = Math.atan2(head.y - w.segs[i].y, head.x - w.segs[i].x)
      }
    }
  }

  if (dangerAngle !== null && dangerDist < 80 * 80) {
    // Flee!
    let da = dangerAngle - bot.angle
    while (da >  Math.PI) da -= Math.PI * 2
    while (da < -Math.PI) da += Math.PI * 2
    bot.angle += da * 0.25
    bot.wantBoost = dangerDist < 50 * 50
    return
  }

  // Aggression — try to cut off smaller worms
  if (myLen > 30) {
    let prey = null, preyD = Infinity
    for (const w of allWorms) {
      if (w === bot || !w.alive) continue
      if (w.segs.length >= myLen * 0.7) continue // Only hunt much smaller
      const d2 = dist2(head, w.segs[0])
      if (d2 < 250 * 250 && d2 < preyD) {
        preyD = d2
        prey = w
      }
    }
    if (prey) {
      // Aim slightly ahead of prey's direction
      const preyHead = prey.segs[0]
      const preyAngle = prey.angle || 0
      const leadDist = 60
      const targetX = preyHead.x + Math.cos(preyAngle) * leadDist
      const targetY = preyHead.y + Math.sin(preyAngle) * leadDist
      const target = Math.atan2(targetY - head.y, targetX - head.x)
      let da = target - bot.angle
      while (da >  Math.PI) da -= Math.PI * 2
      while (da < -Math.PI) da += Math.PI * 2
      bot.angle += da * 0.15
      bot.wantBoost = preyD < 120 * 120
      return
    }
  }

  // Seek food — prefer golden, then normal, avoid poison
  let best = null, bestD = Infinity, bestScore = 0
  for (const f of foods) {
    if (f.type === FOOD_TYPE.POISON) continue // skip poison
    const d = dist2(head, f)
    // Golden food is 3× more attractive (divide distance effectively)
    const attractiveness = f.type === FOOD_TYPE.GOLDEN ? 3 : f.type === FOOD_TYPE.SHIELD ? 2 : 1
    const effectiveD = d / attractiveness
    if (effectiveD < bestD) { bestD = effectiveD; best = f }
  }
  if (best) {
    const target = Math.atan2(best.y - head.y, best.x - head.x)
    let da = target - bot.angle
    while (da >  Math.PI) da -= Math.PI * 2
    while (da < -Math.PI) da += Math.PI * 2
    bot.angle += da * cfg.turn
    // Boost towards golden food
    bot.wantBoost = best.type === FOOD_TYPE.GOLDEN && bestD < 200 * 200
    // Occasionally add slight random wobble for natural movement
    bot.angle += (Math.random() - 0.5) * 0.02
  } else {
    bot.wantBoost = false
  }
}

// ─── Image Cache ──────────────────────────────────────────────────────────────
const skinImagesCache = {}
function getSkinImage(url) {
  if (!url) return null
  if (skinImagesCache[url]) return skinImagesCache[url]
  const img = new Image()
  img.src = url
  img.onload = () => { img.loaded = true }
  skinImagesCache[url] = img
  return img
}

// ─── Draw Worm (no shadowBlur — offscreen glow via pre-drawn circle) ─────────
function drawWorm(ctx, worm, skin, camX, camY, W, H, isPlayer) {
  const segs = worm.segs
  const len  = segs.length
  const useImage = skin.isImage
  const headImg = useImage ? getSkinImage(skin.headImg) : null
  const bodyImg = useImage ? getSkinImage(skin.bodyImg) : null
  const ready = headImg?.loaded && bodyImg?.loaded

  // Body — back to front
  for (let i = len - 1; i >= 1; i--) {
    const s  = segs[i]
    const sx = s.x - camX, sy = s.y - camY
    if (sx < -30 || sx > W + 30 || sy < -30 || sy > H + 30) continue

    const t  = i / len
    const baseR  = SEG_R * (1 - t * 0.30)

    if (useImage && ready) {
      const r = baseR * 1.6
      const prev = segs[i-1]
      const ang = Math.atan2(prev.y - s.y, prev.x - s.x)
      ctx.save()
      ctx.translate(sx, sy)
      ctx.rotate(ang)
      ctx.drawImage(bodyImg, -r, -r, r*2, r*2)
      ctx.restore()
    } else {
      const r = baseR
      const ev = i % 2 === 0
      ctx.fillStyle = ev ? skin.body : skin.head + 'cc'
      ctx.beginPath()
      ctx.arc(sx, sy, r, 0, Math.PI * 2)
      ctx.fill()

      // Highlight dot — cheap alternative to glow
      if (i % 4 === 0) {
        ctx.fillStyle = 'rgba(255,255,255,0.10)'
        ctx.beginPath()
        ctx.arc(sx - r * 0.3, sy - r * 0.3, r * 0.25, 0, Math.PI * 2)
        ctx.fill()
      }
    }
  }

  // Head
  const h  = segs[0]
  const hx = h.x - camX, hy = h.y - camY
  if (hx >= -30 && hx <= W + 30 && hy >= -30 && hy <= H + 30) {
    if (useImage && ready) {
      const r = SEG_R * 1.8
      // Glow ring
      ctx.globalAlpha = 0.25
      ctx.fillStyle   = skin.glow
      ctx.beginPath()
      ctx.arc(hx, hy, r + 4, 0, Math.PI * 2)
      ctx.fill()
      ctx.globalAlpha = 1

      ctx.save()
      ctx.translate(hx, hy)
      ctx.rotate(worm.angle)
      ctx.drawImage(headImg, -r, -r, r*2, r*2)
      ctx.restore()
    } else {
      // Glow ring (1 cheap ring instead of shadowBlur)
      ctx.globalAlpha = 0.22
      ctx.fillStyle   = skin.glow
      ctx.beginPath()
      ctx.arc(hx, hy, SEG_R + 5, 0, Math.PI * 2)
      ctx.fill()
      ctx.globalAlpha = 1

      ctx.fillStyle = skin.head
      ctx.beginPath()
      ctx.arc(hx, hy, SEG_R, 0, Math.PI * 2)
      ctx.fill()

      // Eyes
      const ang = worm.angle
      const eOff = SEG_R * 0.52
      ;[ang - 0.42, ang + 0.42].forEach(ea => {
        const ex = hx + Math.cos(ea) * eOff
        const ey = hy + Math.sin(ea) * eOff
        ctx.fillStyle = '#fff'
        ctx.beginPath(); ctx.arc(ex, ey, SEG_R * 0.30, 0, Math.PI * 2); ctx.fill()
        ctx.fillStyle = '#0a0a1a'
        ctx.beginPath(); ctx.arc(ex + Math.cos(ang)*1.4, ey + Math.sin(ang)*1.4, SEG_R * 0.14, 0, Math.PI * 2); ctx.fill()
      })
    }

    // Name tag (bots only)
    if (!isPlayer) {
      ctx.fillStyle = 'rgba(255,255,255,0.5)'
      ctx.font = '10px Nunito,sans-serif'
      ctx.textAlign = 'center'
      ctx.fillText(skin.name, hx, hy - SEG_R - 6)
    }
  }
}

// ─── Draw Food ────────────────────────────────────────────────────────────────
function drawFood(ctx, foods, camX, camY, W, H, tick) {
  for (const f of foods) {
    const fx = f.x - camX, fy = f.y - camY
    if (fx < -20 || fx > W + 20 || fy < -20 || fy > H + 20) continue
    const pr = f.r + Math.sin(f.pulse) * 1.8

    if (f.type === FOOD_TYPE.GOLDEN) {
      // Golden — shimmering gold with star sparkle
      const flicker = 0.6 + Math.sin(tick * 0.15) * 0.4
      // Outer glow ring
      ctx.globalAlpha = 0.35 * flicker
      ctx.fillStyle = '#FFD700'
      ctx.beginPath(); ctx.arc(fx, fy, pr + 8, 0, Math.PI * 2); ctx.fill()
      ctx.globalAlpha = 0.2
      ctx.fillStyle = '#FFF8DC'
      ctx.beginPath(); ctx.arc(fx, fy, pr + 14, 0, Math.PI * 2); ctx.fill()
      ctx.globalAlpha = 1
      // Core
      ctx.fillStyle = '#FFD700'
      ctx.beginPath(); ctx.arc(fx, fy, pr, 0, Math.PI * 2); ctx.fill()
      // Inner bright spot
      ctx.fillStyle = '#FFF8DC'
      ctx.beginPath(); ctx.arc(fx - pr * 0.2, fy - pr * 0.2, pr * 0.4, 0, Math.PI * 2); ctx.fill()
      // Star sparkle cross
      ctx.strokeStyle = `rgba(255,248,220,${0.5 + Math.sin(tick * 0.2) * 0.3})`
      ctx.lineWidth = 1.5
      const sLen = pr * 1.2
      ctx.beginPath(); ctx.moveTo(fx - sLen, fy); ctx.lineTo(fx + sLen, fy); ctx.stroke()
      ctx.beginPath(); ctx.moveTo(fx, fy - sLen); ctx.lineTo(fx, fy + sLen); ctx.stroke()
      // TTL fading — blink when about to expire
      if (f.ttl < 180) {
        const blink = Math.sin(tick * 0.4) > 0
        if (!blink) { continue }
      }
    } else if (f.type === FOOD_TYPE.POISON) {
      // Poison — dark green with toxic aura
      const toxPulse = 0.5 + Math.sin(tick * 0.1 + f.toxicPulse) * 0.3
      // Toxic aura
      ctx.globalAlpha = 0.15 * toxPulse
      ctx.fillStyle = '#00FF00'
      ctx.beginPath(); ctx.arc(fx, fy, pr + 10, 0, Math.PI * 2); ctx.fill()
      ctx.globalAlpha = 0.25
      ctx.fillStyle = '#1a472a'
      ctx.beginPath(); ctx.arc(fx, fy, pr + 5, 0, Math.PI * 2); ctx.fill()
      ctx.globalAlpha = 1
      // Core — dark green
      ctx.fillStyle = '#2ECC40'
      ctx.beginPath(); ctx.arc(fx, fy, pr, 0, Math.PI * 2); ctx.fill()
      // Skull hint — simple X eyes
      ctx.strokeStyle = '#0a2e0a'
      ctx.lineWidth = 1.5
      const ex = pr * 0.3
      // Left X
      ctx.beginPath(); ctx.moveTo(fx - ex - 2, fy - 2); ctx.lineTo(fx - ex + 2, fy + 2); ctx.stroke()
      ctx.beginPath(); ctx.moveTo(fx - ex + 2, fy - 2); ctx.lineTo(fx - ex - 2, fy + 2); ctx.stroke()
      // Right X
      ctx.beginPath(); ctx.moveTo(fx + ex - 2, fy - 2); ctx.lineTo(fx + ex + 2, fy + 2); ctx.stroke()
      ctx.beginPath(); ctx.moveTo(fx + ex + 2, fy - 2); ctx.lineTo(fx + ex - 2, fy + 2); ctx.stroke()
    } else if (f.type === FOOD_TYPE.SHIELD) {
      // Shield — bright blue with rotating ring
      const rot = (f.rotation || 0)
      // Outer rotating ring
      ctx.save()
      ctx.translate(fx, fy)
      ctx.rotate(rot)
      ctx.strokeStyle = 'rgba(0,191,255,0.5)'
      ctx.lineWidth = 2
      ctx.beginPath(); ctx.arc(0, 0, pr + 8, 0, Math.PI * 1.2); ctx.stroke()
      ctx.beginPath(); ctx.arc(0, 0, pr + 8, Math.PI * 1.4, Math.PI * 2); ctx.stroke()
      ctx.restore()
      // Glow
      ctx.globalAlpha = 0.2
      ctx.fillStyle = '#00BFFF'
      ctx.beginPath(); ctx.arc(fx, fy, pr + 12, 0, Math.PI * 2); ctx.fill()
      ctx.globalAlpha = 1
      // Core
      ctx.fillStyle = '#00BFFF'
      ctx.beginPath(); ctx.arc(fx, fy, pr, 0, Math.PI * 2); ctx.fill()
      // Shield icon — simple chevron
      ctx.fillStyle = '#FFF'
      ctx.font = `${Math.floor(pr * 1.1)}px sans-serif`
      ctx.textAlign = 'center'
      ctx.textBaseline = 'middle'
      ctx.fillText('🛡', fx, fy + 1)
      // TTL blink
      if (f.ttl < 150) {
        const blink = Math.sin(tick * 0.4) > 0
        if (!blink) { continue }
      }
    } else {
      // Normal food
      // Soft outer ring (cheap glow)
      ctx.globalAlpha = 0.18
      ctx.fillStyle   = f.color
      ctx.beginPath(); ctx.arc(fx, fy, pr + 4, 0, Math.PI * 2); ctx.fill()
      ctx.globalAlpha = 1

      ctx.fillStyle = f.color
      ctx.beginPath(); ctx.arc(fx, fy, pr, 0, Math.PI * 2); ctx.fill()

      // Specular
      ctx.fillStyle = 'rgba(255,255,255,0.55)'
      ctx.beginPath(); ctx.arc(fx - pr * 0.3, fy - pr * 0.3, pr * 0.26, 0, Math.PI * 2); ctx.fill()
    }
  }
}

// ─── Component ────────────────────────────────────────────────────────────────
export default function SlitherWorm({ onBack, onHome, game, difficulty }) {
  const canvasRef  = useRef(null)
  const gameRef    = useRef(null)
  const stickRef   = useRef({ active: false, dx: 0, dy: 0, bcx: 0, bcy: 0 })
  const boostRef   = useRef(false)
  const animRef    = useRef(null)
  const { play }   = useSound()
  const { reportGameResult } = useProgress()
  const { earnCoins, getActiveSkin } = useCoins()
  const { vibrateLight, vibrateMedium, vibrateError } = useHaptics()
  const tc = useThemeColors()
  const { startScoreSession } = useLeaderboard()
  const PLAYER_SKIN = getActiveSkin ? getActiveSkin() : DEFAULT_PLAYER_SKIN

  const cfg = CFG[difficulty.id]
  const SL_DIFF = { easy: '🟢 Mudah', medium: '🟡 Sedang', hard: '🔴 Sulit' }

  const [phase, setPhase]       = useState('idle')
  const [deathCause, setDeathCause] = useState('wall')
  const [showTutorial, setShowTutorial] = useState(() => !localStorage.getItem('bp_tut_slither-worm'))
  const [showConfetti, setShowConfetti] = useState(false)
  const [score, setScore]       = useState(0)
  const [length, setLength]     = useState(0)
  const [kills, setKills]       = useState(0)
  const [knobPos, setKnobPos]   = useState({ x: 0, y: 0 })
  const [boosting, setBoosting] = useState(false)
  const [shielded, setShielded] = useState(false)
  const [bestScore, setBestScore] = useState(
    () => parseInt(localStorage.getItem(`slither-best-${difficulty.id}`) || '0')
  )
  const joyRef = useRef(null)

  // ── Init ──
  function initGame(canvas) {
    const M = cfg.mapSize
    const player = makeWorm(M / 2, M / 2, 0, 28)
    player.shielded = false
    player.shieldTimer = 0
    const bots   = BOT_SKINS.slice(0, cfg.bots).map((skin, i) => {
      // Variable sizes: ~30% small, ~50% medium, ~20% large
      const sizeRoll = Math.random()
      const len = sizeRoll < 0.3 ? Math.floor(rand(15, 22))
                : sizeRoll < 0.8 ? Math.floor(rand(24, 38))
                : Math.floor(rand(40, 60))
      return {
        ...makeWorm(rand(200, M - 200), rand(200, M - 200), rand(0, Math.PI * 2), len),
        skin, wantBoost: false,
      }
    })
    const foods  = Array.from({ length: cfg.foodCount }, () => spawnFood(M))
    // Add initial special foods
    const poisonCount = { easy: 3, medium: 4, hard: 5 }[difficulty.id] || 3
    for (let i = 0; i < poisonCount; i++) foods.push(spawnPoisonFood(M))
    foods.push(spawnGoldenFood(M))
    return {
      player, bots, foods, particles: [], speedLines: [],
      score: 0, kills: 0, mapSize: M,
      cam: { x: M / 2 - (canvas._logicalW || canvas.width) / 2, y: M / 2 - (canvas._logicalH || canvas.height) / 2 },
      tick: 0,
      goldenTimer: 0,   // frames until next golden spawn
      shieldTimer: 0,   // frames until next shield spawn
    }
  }

  function sizeCanvas() {
    const c = canvasRef.current
    if (!c) return { w:0, h:0 }
    const parent = c.parentElement
    if (!parent) return { w:0, h:0 }
    const rect = parent.getBoundingClientRect()
    const dpr = Math.min(window.devicePixelRatio || 1, 2)
    const w = Math.floor(rect.width)
    const h = Math.floor(rect.height)
    c.width = w * dpr
    c.height = h * dpr
    c.style.width = w + 'px'
    c.style.height = h + 'px'
    const ctx = c.getContext('2d')
    ctx.setTransform(dpr, 0, 0, dpr, 0, 0)
    // Store logical size for game code
    c._logicalW = w
    c._logicalH = h
    return { w, h }
  }

  function startGame() {
    const canvas = canvasRef.current
    if (!canvas) return
    const { w, h } = sizeCanvas()
    if (w === 0 || h === 0) return
    gameRef.current = initGame(canvas)
    setScore(0); setLength(0); setKills(0)
    if (startScoreSession) startScoreSession(game.id)
    setPhase('playing')
  }

  // ── Resize ──
  useEffect(() => {
    sizeCanvas()
    const fn = () => { sizeCanvas() }
    fn()
    window.addEventListener('resize', fn)
    const orientFn = () => setTimeout(fn, 200)
    window.addEventListener('orientationchange', orientFn)
    return () => { window.removeEventListener('resize', fn); window.removeEventListener('orientationchange', orientFn) }
  }, [])

  // ── Game loop ──
  useEffect(() => {
    if (phase !== 'playing') return
    const canvas = canvasRef.current
    const ctx    = canvas.getContext('2d')

    // Pre-draw grid to offscreen canvas once
    const gridCanvas = document.createElement('canvas')
    gridCanvas.width  = 700
    gridCanvas.height = 700
    const gc = gridCanvas.getContext('2d')
    gc.strokeStyle = 'rgba(162,155,254,0.045)'
    gc.lineWidth = 0.5
    const GS = 70
    for (let x = 0; x <= 700; x += GS) { gc.beginPath(); gc.moveTo(x,0); gc.lineTo(x,700); gc.stroke() }
    for (let y = 0; y <= 700; y += GS) { gc.beginPath(); gc.moveTo(0,y); gc.lineTo(700,y); gc.stroke() }

    let lastTime = 0

    function update(dt) {
      const g = gameRef.current
      if (!g) return
      const M  = g.mapSize
      const p  = g.player
      const spd = (boostRef.current ? cfg.speed * cfg.boostMul : cfg.speed)

      // Player steering
      if (stickRef.current.active) {
        const { dx, dy } = stickRef.current
        if (Math.abs(dx) > 0.04 || Math.abs(dy) > 0.04) {
          const target = Math.atan2(dy, dx)
          let da = target - p.angle
          while (da >  Math.PI) da -= Math.PI * 2
          while (da < -Math.PI) da += Math.PI * 2
          // Turn faster proportional to stick distance for snappier control
          const stickMag = Math.sqrt(dx * dx + dy * dy)
          p.angle += da * (cfg.turn + stickMag * 0.08)
        }
      }

      // Move player
      const nx = p.segs[0].x + Math.cos(p.angle) * spd
      const ny = p.segs[0].y + Math.sin(p.angle) * spd

      // Wall death
      if (nx < SEG_R || nx > M - SEG_R || ny < SEG_R || ny > M - SEG_R) {
        if (!p.shielded) {
          p.alive = false
          play('gameOver')
          vibrateError()
          const fs = g.score
          if (fs > bestScore) { localStorage.setItem(`slither-best-${difficulty.id}`, fs); setBestScore(fs); setShowConfetti(true); setTimeout(()=>setShowConfetti(false),100) }
          setDeathCause('wall')
          setPhase('dead')
          return
        }
        // Shield bounces off wall — redirect towards center
        p.angle = Math.atan2(M / 2 - ny, M / 2 - nx)
        return
      }

      // Player head hits bot body → Player dies (unless shielded)
      for (const bot of g.bots) {
        if (!bot.alive) continue
        // Check against bot body segments (skip head, index 0)
        for (let si = 3; si < bot.segs.length; si++) {
          if (dist2({ x: nx, y: ny }, bot.segs[si]) < (SEG_R * 1.9) ** 2) {
            if (p.shielded) {
              // Shield kills the bot instead!
              bot.alive = false; bot.respawnTimer = 220
              g.score += Math.floor(bot.segs.length * 2)
              g.kills += 1
              play('levelUp')
              vibrateMedium()
              setScore(g.score); setKills(g.kills)
              for (let pi = 0; pi < 12; pi++) {
                g.particles.push({ x: bot.segs[0].x, y: bot.segs[0].y, vx: rand(-4,4), vy: rand(-4,4), r: rand(3,7), color: '#00BFFF', life: 1 })
              }
              const drop = Math.min(30, Math.floor(bot.segs.length / 2))
              for (let i = 0; i < drop; i++) {
                const bs = bot.segs[i * 2] || bot.segs[0]
                g.foods.push({ x: bs.x + rand(-14,14), y: bs.y + rand(-14,14), color: bot.skin.head, r: rand(6,10), pulse: 0, type: FOOD_TYPE.NORMAL })
              }
              break
            }
            p.alive = false
            play('gameOver')
            vibrateError()
            const fs = g.score
            if (fs > bestScore) { localStorage.setItem(`slither-best-${difficulty.id}`, fs); setBestScore(fs); setShowConfetti(true); setTimeout(()=>setShowConfetti(false),100) }
            // Drop player pellets
            const drop = Math.min(25, Math.floor(p.segs.length / 3))
            for (let i = 0; i < drop; i++) {
              const ps = p.segs[i * 3] || p.segs[0]
              g.foods.push({ x: ps.x + rand(-12,12), y: ps.y + rand(-12,12), color: PLAYER_SKIN.head, r: rand(5,9), pulse: 0, type: FOOD_TYPE.NORMAL })
            }
            setDeathCause('bot')
            setPhase('dead')
            return
          }
        }
      }

      p.segs.unshift({ x: nx, y: ny })

      // Shield timer countdown
      if (p.shielded) {
        p.shieldTimer -= 1
        if (p.shieldTimer <= 0) {
          p.shielded = false
          setShielded(false)
        }
      }

      // Food eating
      let grew = 0
      let poisoned = false
      g.foods = g.foods.filter(f => {
        if (dist2(p.segs[0], f) < (SEG_R + f.r + 2) ** 2) {
          if (f.type === FOOD_TYPE.POISON) {
            // Poison — lose segments!
            if (!p.shielded) {
              poisoned = true
              const loseCount = Math.min(8, Math.floor(p.segs.length * 0.25))
              for (let pi = 0; pi < loseCount && p.segs.length > 5; pi++) {
                const removed = p.segs.pop()
                // Drop food pellets from lost segments
                g.foods.push({ x: removed.x + rand(-8,8), y: removed.y + rand(-8,8), color: '#2ECC40', r: rand(3,5), pulse: 0, type: FOOD_TYPE.NORMAL })
              }
              // Poison particles
              for (let pi = 0; pi < 10; pi++) {
                g.particles.push({
                  x: f.x, y: f.y, vx: rand(-3, 3), vy: rand(-3, 3),
                  r: rand(3, 7), color: '#2ECC40', life: 1.2,
                })
              }
            } else {
              // Shield absorbs poison — just eat particles
              for (let pi = 0; pi < 6; pi++) {
                g.particles.push({ x: f.x, y: f.y, vx: rand(-2, 2), vy: rand(-2, 2), r: rand(2, 4), color: '#00BFFF', life: 0.8 })
              }
            }
            return false
          }
          if (f.type === FOOD_TYPE.SHIELD) {
            // Shield power-up!
            p.shielded = true
            p.shieldTimer = 300 // ~5 seconds
            setShielded(true)
            play('levelUp')
            vibrateMedium()
            for (let pi = 0; pi < 10; pi++) {
              g.particles.push({ x: f.x, y: f.y, vx: rand(-3, 3), vy: rand(-3, 3), r: rand(3, 7), color: '#00BFFF', life: 1.2 })
            }
            return false
          }
          // Normal or Golden
          const multiplier = f.type === FOOD_TYPE.GOLDEN ? 3 : 1
          g.score += Math.round(f.r) * multiplier
          grew += Math.ceil(f.r / 2) * (f.type === FOOD_TYPE.GOLDEN ? 2 : 1)
          // Spawn eat particles
          const pColor = f.type === FOOD_TYPE.GOLDEN ? '#FFD700' : f.color
          const pCount = f.type === FOOD_TYPE.GOLDEN ? 12 : 6
          for (let pi = 0; pi < pCount; pi++) {
            g.particles.push({
              x: f.x, y: f.y, vx: rand(-2, 2), vy: rand(-2, 2),
              r: rand(2, 5), color: pColor, life: f.type === FOOD_TYPE.GOLDEN ? 1.5 : 1,
            })
          }
          return false
        }
        return true
      })
      if (poisoned) {
        play('gameOver')
        vibrateMedium()
        setLength(p.segs.length)
      }
      if (grew > 0) {
        play('eat')
        vibrateLight()
        const tail = p.segs[p.segs.length - 1]
        for (let i = 0; i < grew; i++) p.segs.push({ ...tail })
        setScore(g.score); setLength(p.segs.length)
      } else if (!poisoned) {
        p.segs.pop()
      }

      // Update particles
      g.particles = g.particles.filter(pt => {
        pt.x += pt.vx; pt.y += pt.vy; pt.life -= 0.04; pt.r *= 0.97
        return pt.life > 0
      })

      // Speed lines & Boost extra glow update
      if (boostRef.current) {
         if (Math.random() > 0.4 && p.segs.length > 2) {
             const randPos = p.segs[Math.floor(Math.random() * (p.segs.length * 0.8))];
             g.particles.push({
                 x: randPos.x + rand(-8,8), y: randPos.y + rand(-8,8),
                 vx: -Math.cos(p.angle) * rand(2, 5) + rand(-1,1), vy: -Math.sin(p.angle) * rand(2, 5) + rand(-1,1),
                 r: rand(4, 9), color: PLAYER_SKIN.glow, life: 1.2
             });
         }
         g.speedLines = g.speedLines || []
         for(let i=0; i<3; i++) {
           g.speedLines.push({
               x: rand(0, canvasRef.current._logicalW || canvasRef.current.width),
               y: rand(0, canvasRef.current._logicalH || canvasRef.current.height),
               len: rand(40, 150),
               life: 1.0,
           })
         }
      }

      if (g.speedLines) {
         g.speedLines = g.speedLines.filter(sl => {
            sl.life -= 0.08;
            sl.x -= Math.cos(p.angle) * 45;
            sl.y -= Math.sin(p.angle) * 45;
            return sl.life > 0;
         })
      }

      // Bots update
      const allWorms = [g.player, ...g.bots]
      g.bots.forEach(bot => {
        if (!bot.alive) {
          bot.respawnTimer -= 1
          if (bot.respawnTimer <= 0) {
            const sizeRoll = Math.random()
            const len = sizeRoll < 0.3 ? Math.floor(rand(15, 22))
                      : sizeRoll < 0.8 ? Math.floor(rand(24, 38))
                      : Math.floor(rand(40, 55))
            const nb = makeWorm(rand(200, M - 200), rand(200, M - 200), rand(0, Math.PI * 2), len)
            bot.segs  = nb.segs
            bot.angle = nb.angle
            bot.alive = true
            bot.wantBoost = false
          }
          return
        }

        botThink(bot, g.foods, M, cfg, allWorms)
        const botBoost = bot.wantBoost ? 1.3 : 1.0
        const bspd = cfg.speed * 0.88 * botBoost
        const bnx  = bot.segs[0].x + Math.cos(bot.angle) * bspd
        const bny  = bot.segs[0].y + Math.sin(bot.angle) * bspd

        // Bot wall death → respawn
        if (bnx < SEG_R || bnx > M - SEG_R || bny < SEG_R || bny > M - SEG_R) {
          bot.alive = false; bot.respawnTimer = 180

          // Drop food pellets where bot died
          const drop = Math.min(20, Math.floor(bot.segs.length / 3))
          for (let i = 0; i < drop; i++) {
            const bs = bot.segs[i * 3] || bot.segs[0]
            g.foods.push({ x: bs.x + rand(-12,12), y: bs.y + rand(-12,12), color: bot.skin.head, r: rand(5,8), pulse: 0 })
          }
          return
        }

        // Bot head hits player body → Bot dies (player gets kill)
        for (let si = 3; si < p.segs.length; si++) {
          if (dist2({ x: bnx, y: bny }, p.segs[si]) < (SEG_R * 1.9) ** 2) {
            bot.alive = false; bot.respawnTimer = 220
            g.score  += Math.floor(bot.segs.length * 2)
            g.kills  += 1
            play('levelUp')
            vibrateMedium()
            setScore(g.score); setKills(g.kills)

            // Kill celebration particles
            for (let pi = 0; pi < 12; pi++) {
              g.particles.push({
                x: bnx, y: bny, vx: rand(-4, 4), vy: rand(-4, 4),
                r: rand(3, 7), color: bot.skin.glow, life: 1,
              })
            }

            const drop = Math.min(30, Math.floor(bot.segs.length / 2))
            for (let i = 0; i < drop; i++) {
              const bs = bot.segs[i * 2] || bot.segs[0]
              g.foods.push({ x: bs.x + rand(-14,14), y: bs.y + rand(-14,14), color: bot.skin.head, r: rand(6,10), pulse: 0 })
            }
            return
          }
        }

        // Head-to-head collision → both die but player gets points
        if (dist2({ x: bnx, y: bny }, p.segs[0]) < (SEG_R * 2.2) ** 2) {
          bot.alive = false; bot.respawnTimer = 220
          g.score  += Math.floor(bot.segs.length * 2)
          g.kills  += 1
          play('levelUp')
          vibrateMedium()
          setScore(g.score); setKills(g.kills)

          // Drop pellets
          const drop2 = Math.min(30, Math.floor(bot.segs.length / 2))
          for (let i = 0; i < drop2; i++) {
            const bs = bot.segs[i * 2] || bot.segs[0]
            g.foods.push({ x: bs.x + rand(-14,14), y: bs.y + rand(-14,14), color: bot.skin.head, r: rand(6,10), pulse: 0 })
          }
          return
        }

        bot.segs.unshift({ x: bnx, y: bny })

        // Bots eat food too
        g.foods = g.foods.filter(f => {
          if (dist2(bot.segs[0], f) < (SEG_R + f.r) ** 2) {
            if (f.type === FOOD_TYPE.POISON) {
              // Bot eats poison — dies!
              bot.alive = false; bot.respawnTimer = 250
              const drop = Math.min(20, Math.floor(bot.segs.length / 3))
              for (let i = 0; i < drop; i++) {
                const bs = bot.segs[i * 3] || bot.segs[0]
                g.foods.push({ x: bs.x + rand(-12,12), y: bs.y + rand(-12,12), color: bot.skin.head, r: rand(5,8), pulse: 0, type: FOOD_TYPE.NORMAL })
              }
              for (let pi = 0; pi < 8; pi++) {
                g.particles.push({ x: bot.segs[0].x, y: bot.segs[0].y, vx: rand(-3,3), vy: rand(-3,3), r: rand(3,6), color: '#2ECC40', life: 1 })
              }
              return false
            }
            if (f.type === FOOD_TYPE.SHIELD) {
              // Bot ignores shield (just removes it)
              return false
            }
            const ts = bot.segs[bot.segs.length - 1]
            const growCount = f.type === FOOD_TYPE.GOLDEN ? 3 : 1
            for (let gi = 0; gi < growCount; gi++) bot.segs.push({ ...ts })
            return false
          }
          return true
        })
        bot.segs.pop()

        // Bot-to-bot kills — bot head hits other bot body
        for (const other of g.bots) {
          if (other === bot || !other.alive) continue
          for (let si = 3; si < other.segs.length; si++) {
            if (dist2({ x: bnx, y: bny }, other.segs[si]) < (SEG_R * 1.8) ** 2) {
              bot.alive = false; bot.respawnTimer = 200
              // Drop pellets from dead bot
              const drop = Math.min(25, Math.floor(bot.segs.length / 3))
              for (let i = 0; i < drop; i++) {
                const bs = bot.segs[i * 3] || bot.segs[0]
                g.foods.push({ x: bs.x + rand(-14,14), y: bs.y + rand(-14,14), color: bot.skin.head, r: rand(5,9), pulse: 0 })
              }
              // Other bot grows from kill
              const ts = other.segs[other.segs.length - 1]
              for (let i = 0; i < Math.min(8, Math.floor(bot.segs.length / 4)); i++) {
                other.segs.push({ ...ts })
              }
              break
            }
          }
          if (!bot.alive) break
        }
      })

      // Replenish food
      const normalCount = g.foods.filter(f => f.type === FOOD_TYPE.NORMAL).length
      while (normalCount + (g.foods.length - normalCount) < cfg.foodCount) g.foods.push(spawnFood(M))

      // Spawn special foods on timers
      g.goldenTimer = (g.goldenTimer || 0) + 1
      g.shieldTimer = (g.shieldTimer || 0) + 1
      const goldenCount = g.foods.filter(f => f.type === FOOD_TYPE.GOLDEN).length
      if (g.goldenTimer > 480 && goldenCount < 2) { // ~8 seconds
        g.foods.push(spawnGoldenFood(M))
        g.goldenTimer = 0
      }
      const shieldCount = g.foods.filter(f => f.type === FOOD_TYPE.SHIELD).length
      if (g.shieldTimer > 1200 && shieldCount < 1) { // ~20 seconds
        g.foods.push(spawnShieldPowerup(M))
        g.shieldTimer = 0
      }
      // Replenish poison if eaten
      const poisonTarget = { easy: 3, medium: 4, hard: 5 }[difficulty.id] || 3
      const poisonCount = g.foods.filter(f => f.type === FOOD_TYPE.POISON).length
      if (poisonCount < poisonTarget && Math.random() < 0.005) {
        g.foods.push(spawnPoisonFood(M))
      }

      // Update food TTL and animations
      g.foods = g.foods.filter(f => {
        f.pulse += 0.05
        if (f.type === FOOD_TYPE.GOLDEN || f.type === FOOD_TYPE.SHIELD) {
          f.ttl -= 1
          if (f.ttl <= 0) return false
        }
        if (f.type === FOOD_TYPE.SHIELD) f.rotation = (f.rotation || 0) + 0.03
        if (f.type === FOOD_TYPE.POISON) f.toxicPulse = (f.toxicPulse || 0) + 0.02
        return true
      })

      // Camera — slightly faster follow for better feel
      const cW = canvas._logicalW || canvas.width, cH = canvas._logicalH || canvas.height
      g.cam.x += (nx - cW / 2 - g.cam.x) * 0.12
      g.cam.y += (ny - cH / 2 - g.cam.y) * 0.12
      g.cam.x  = Math.max(0, Math.min(M - cW,  g.cam.x))
      g.cam.y  = Math.max(0, Math.min(M - cH, g.cam.y))
      g.tick++
    }

    function draw() {
      const g = gameRef.current
      if (!g) return
      const W = canvas._logicalW || canvas.width, H = canvas._logicalH || canvas.height
      const cx = g.cam.x, cy = g.cam.y

      // Background
      ctx.fillStyle = '#07071a'
      ctx.fillRect(0, 0, W, H)

      // Tiled grid (offscreen cache)
      const gw = gridCanvas.width
      const ox = -(cx % gw), oy = -(cy % gw)
      for (let x = ox; x < W; x += gw)
        for (let y = oy; y < H; y += gw)
          ctx.drawImage(gridCanvas, x, y)

      // Arena border
      ctx.strokeStyle = 'rgba(255,107,107,0.6)'
      ctx.lineWidth   = 2.5
      ctx.strokeRect(2 - cx, 2 - cy, g.mapSize - 4, g.mapSize - 4)
      ctx.strokeStyle = 'rgba(255,107,107,0.15)'
      ctx.lineWidth   = 14
      ctx.strokeRect(2 - cx, 2 - cy, g.mapSize - 4, g.mapSize - 4)

      // Food
      drawFood(ctx, g.foods, cx, cy, W, H, g.tick)

      // Bots
      g.bots.forEach(bot => {
        if (bot.alive) drawWorm(ctx, bot, bot.skin, cx, cy, W, H, false)
      })

      // Player
      drawWorm(ctx, g.player, PLAYER_SKIN, cx, cy, W, H, true)

      // Shield visual on player
      if (g.player.shielded) {
        const ph = g.player.segs[0]
        const phx = ph.x - cx, phy = ph.y - cy
        const shieldAlpha = 0.25 + Math.sin(g.tick * 0.1) * 0.1
        ctx.globalAlpha = shieldAlpha
        ctx.strokeStyle = '#00BFFF'
        ctx.lineWidth = 3
        ctx.beginPath()
        ctx.arc(phx, phy, SEG_R + 8, 0, Math.PI * 2)
        ctx.stroke()
        // Shield glow on body segments  
        for (let si = 0; si < g.player.segs.length; si += 4) {
          const s = g.player.segs[si]
          const sx = s.x - cx, sy = s.y - cy
          if (sx < -30 || sx > W + 30 || sy < -30 || sy > H + 30) continue
          ctx.globalAlpha = shieldAlpha * 0.4
          ctx.fillStyle = '#00BFFF'
          ctx.beginPath()
          ctx.arc(sx, sy, SEG_R * 0.8, 0, Math.PI * 2)
          ctx.fill()
        }
        ctx.globalAlpha = 1
      }

      // Boost trail / Body glow intensification
      if (boostRef.current && g.player.segs.length > 3) {
        ctx.globalAlpha = 0.25
        ctx.fillStyle   = PLAYER_SKIN.glow
        // Emit trail around random segments towards the tail
        for (let i = 0; i < 8; i++) {
          const sIdx = g.player.segs.length - 1 - Math.floor(Math.random() * 12);
          if (sIdx > 0 && sIdx < g.player.segs.length) {
            const ts = g.player.segs[sIdx]
            ctx.beginPath()
            ctx.arc(ts.x - cx + rand(-8,8), ts.y - cy + rand(-8,8), rand(4,8), 0, Math.PI * 2)
            ctx.fill()
          }
        }
        ctx.globalAlpha = 1
      }

      // Eat/Boost particles
      g.particles.forEach(pt => {
        const px = pt.x - cx, py = pt.y - cy
        if (px < -30 || px > W + 30 || py < -30 || py > H + 30) return
        ctx.globalAlpha = Math.min(1, pt.life)
        ctx.fillStyle = pt.color
        ctx.beginPath()
        ctx.arc(px, py, Math.max(0.1, pt.r), 0, Math.PI * 2)
        ctx.fill()
      })
      ctx.globalAlpha = 1

      ctx.shadowBlur = 0

      // Speed Lines (Screen space)
      if (g.speedLines && g.speedLines.length > 0) {
          ctx.save();
          ctx.lineCap = 'round';
          g.speedLines.forEach(sl => {
             ctx.globalAlpha = sl.life * 0.35;
             ctx.strokeStyle = '#ffffff'; 
             ctx.lineWidth = rand(1, 2.5);
             ctx.beginPath();
             ctx.moveTo(sl.x, sl.y);
             ctx.lineTo(sl.x - Math.cos(g.player.angle)*sl.len, sl.y - Math.sin(g.player.angle)*sl.len);
             ctx.stroke();
          });
          ctx.restore();
      }

      // ── Minimap ──
      const mmSize = 110, mmMargin = 12
      const mmX = W - mmSize - mmMargin, mmY = H - mmSize - mmMargin
      ctx.fillStyle = 'rgba(7,7,26,0.7)'
      ctx.strokeStyle = 'rgba(162,155,254,0.3)'
      ctx.lineWidth = 1
      ctx.fillRect(mmX, mmY, mmSize, mmSize); ctx.strokeRect(mmX, mmY, mmSize, mmSize)
      const mmScale = mmSize / g.mapSize
      // Food dots
      ctx.fillStyle = 'rgba(255,255,255,0.12)'
      for (let fi = 0; fi < g.foods.length; fi += 4) {
        const f = g.foods[fi]
        ctx.fillRect(mmX + f.x * mmScale, mmY + f.y * mmScale, 1, 1)
      }
      // Bots on minimap
      g.bots.forEach(b => {
        if (!b.alive) return
        ctx.fillStyle = b.skin.head + '99'
        ctx.beginPath()
        ctx.arc(mmX + b.segs[0].x * mmScale, mmY + b.segs[0].y * mmScale, Math.max(2, b.segs.length * 0.04), 0, Math.PI * 2)
        ctx.fill()
      })
      // Player on minimap
      const ph = g.player.segs[0]
      ctx.fillStyle = '#4ecdc4'
      ctx.beginPath()
      ctx.arc(mmX + ph.x * mmScale, mmY + ph.y * mmScale, 3, 0, Math.PI * 2)
      ctx.fill()
      // Player view rect
      ctx.strokeStyle = 'rgba(78,205,196,0.5)'
      ctx.lineWidth = 0.5
      ctx.strokeRect(mmX + cx * mmScale, mmY + cy * mmScale, W * mmScale, H * mmScale)

      // ── Leaderboard HUD (top 5) ──
      const ranking = [
        { name: 'Kamu', len: g.player.segs.length, color: '#4ecdc4', alive: g.player.alive },
        ...g.bots.map(b => ({ name: b.skin.name, len: b.alive ? b.segs.length : 0, color: b.skin.head, alive: b.alive }))
      ].filter(r => r.alive).sort((a, b) => b.len - a.len).slice(0, 5)

      const lbX = W - 120 - mmMargin, lbY = mmMargin
      ctx.fillStyle = 'rgba(7,7,26,0.55)'
      ctx.fillRect(lbX, lbY, 120, 14 + ranking.length * 18)
      ctx.font = '700 9px Nunito,sans-serif'
      ctx.fillStyle = 'rgba(255,255,255,0.3)'
      ctx.textAlign = 'left'
      ctx.fillText('TOP WORMS', lbX + 8, lbY + 11)
      ranking.forEach((r, i) => {
        const ry = lbY + 16 + i * 18
        const isMe = r.name === 'Kamu'
        ctx.fillStyle = r.color + (isMe ? '' : '88')
        ctx.beginPath(); ctx.arc(lbX + 12, ry + 5, 3, 0, Math.PI * 2); ctx.fill()
        ctx.fillStyle = isMe ? '#fff' : 'rgba(255,255,255,0.45)'
        ctx.font = isMe ? '700 11px Nunito,sans-serif' : '600 10px Nunito,sans-serif'
        ctx.fillText(r.name, lbX + 20, ry + 9)
        ctx.textAlign = 'right'
        ctx.fillText(r.len, lbX + 114, ry + 9)
        ctx.textAlign = 'left'
      })
    }

    function loop(ts) {
      const dt = ts - lastTime
      // Cap to ~60fps tick — skip if tab is hidden
      if (dt >= 14) {
        update(dt)
        draw()
        lastTime = ts
      }
      animRef.current = requestAnimationFrame(loop)
    }
    animRef.current = requestAnimationFrame(loop)
    return () => cancelAnimationFrame(animRef.current)
  }, [phase])

  // ── Keyboard ──
  useEffect(() => {
    const held = {}
    function sync() {
      const dx = (held['ArrowRight']||held['d']?1:0) - (held['ArrowLeft']||held['a']?1:0)
      const dy = (held['ArrowDown'] ||held['s']?1:0) - (held['ArrowUp']  ||held['w']?1:0)
      stickRef.current = dx||dy ? { active:true, dx, dy } : { active:false, dx:0, dy:0 }
      const b = !!held[' '] || !!held['Shift']
      boostRef.current = b; setBoosting(b)
    }
    const dn = e => { held[e.key]=true;  sync() }
    const up = e => { delete held[e.key]; sync() }
    window.addEventListener('keydown', dn)
    window.addEventListener('keyup',   up)
    return () => { window.removeEventListener('keydown', dn); window.removeEventListener('keyup', up) }
  }, [])

  // ── Report to global progress on death ──
  useEffect(() => {
    if (phase === 'dead' && score > 0) {
      const stars = score >= 100 ? 3 : score >= 50 ? 2 : 1
      reportGameResult({
        gameId: 'slither-worm',
        difficultyId: difficulty.id,
        won: false,
        score,
        stars,
        timeSec: 0,
      })
      // Coin reward based on score
      const coinAmount = Math.max(5, Math.min(Math.floor(score / 5), 30))
      earnCoins(coinAmount, `Slither Worm — skor ${score}`)
    }
  }, [phase])

  useEffect(() => {
    const joy = joyRef.current
    if (!joy) return

    let active = false

    const handleStart = (e) => {
      if (e.cancelable) e.preventDefault()
      active = true
      updateJoy(e)
    }

    const handleMove = (e) => {
      if (!active) return
      if (e.cancelable) e.preventDefault()
      updateJoy(e)
    }

    const handleEnd = (e) => {
      if (!active) return
      active = false
      stickRef.current = { active: false, dx: 0, dy: 0 }
      setKnobPos({ x: 0, y: 0 })
    }

    const updateJoy = (e) => {
      const rect = joy.getBoundingClientRect()
      const bcx = rect.left + rect.width / 2
      const bcy = rect.top + rect.height / 2
      const t = e.touches ? e.touches[0] : e
      const dx = t.clientX - bcx, dy = t.clientY - bcy
      const d = Math.sqrt(dx * dx + dy * dy) || 1
      const max = 50
      const nx = (dx / d) * Math.min(d, max) / max
      const ny = (dy / d) * Math.min(d, max) / max
      stickRef.current = { active: true, dx: nx, dy: ny }
      setKnobPos({ x: nx * 38, y: ny * 38 })
    }

    joy.addEventListener('touchstart', handleStart, { passive: false })
    window.addEventListener('touchmove', handleMove, { passive: false })
    window.addEventListener('touchend', handleEnd)

    joy.addEventListener('mousedown', handleStart)
    window.addEventListener('mousemove', handleMove)
    window.addEventListener('mouseup', handleEnd)

    return () => {
      joy.removeEventListener('touchstart', handleStart)
      window.removeEventListener('touchmove', handleMove)
      window.removeEventListener('touchend', handleEnd)
      joy.removeEventListener('mousedown', handleStart)
      window.removeEventListener('mousemove', handleMove)
      window.removeEventListener('mouseup', handleEnd)
    }
  }, [phase])

  const DLABEL = { easy:'🟢 Mudah', medium:'🟡 Sedang', hard:'🔴 Sulit' }

  return (
    <>
      {showTutorial && <TutorialModal steps={TUTORIAL_STEPS_SW} color="#4ECDC4" onClose={()=>{ setShowTutorial(false); localStorage.setItem('bp_tut_slither-worm','1') }} />}
      {showConfetti && <Confetti active={showConfetti} onDone={()=>setShowConfetti(false)} />}

    <div style={{ width:'100%', height: typeof CSS !== 'undefined' && CSS.supports('height','100dvh') ? '100dvh' : '100vh', background:'#07071a', position:'relative', overflow:'hidden', userSelect:'none' }}>
      <canvas ref={canvasRef} style={{ width:'100%', height:'100%', display:'block', touchAction:'none' }} />

      {/* ── HUD ── */}
      {phase === 'playing' && (
        <div style={{ position:'absolute', top:0, left:0, right:0, zIndex:10, display:'flex', alignItems:'center', justifyContent:'space-between', padding:'10px 16px', background:'linear-gradient(to bottom,rgba(7,7,26,0.88),transparent)' }}>
          <button onClick={() => { play('click'); onBack() }}
            style={{ background:'rgba(255,255,255,0.07)', border:'1.5px solid rgba(255,255,255,0.12)', borderRadius:10, padding:'7px 14px', color:'rgba(255,255,255,0.7)', fontSize:15, cursor:'pointer', fontFamily:"'Nunito',sans-serif", fontWeight:700 }}>
            ←
          </button>
          <div style={{ display:'flex', gap:18, alignItems:'center' }}>
            {[
              { v:score,  label:'SKOR',    c:'#4ecdc4' },
              { v:length, label:'PANJANG', c:'#a29bfe' },
              { v:kills,  label:'KILLS',   c:'#ff6b6b' },
              { v:bestScore, label:'REKOR',c:'#ffd93d' },
            ].map(s => (
              <div key={s.label} style={{ textAlign:'center' }}>
                <div style={{ fontFamily:"'Fredoka One',cursive", fontSize:20, color:s.c, lineHeight:1 }}>{s.v}</div>
                <div style={{ fontSize:9, color:'rgba(255,255,255,0.3)', fontWeight:700, letterSpacing:'0.5px' }}>{s.label}</div>
              </div>
            ))}
          </div>
          <div style={{ display:'flex', alignItems:'center', gap:8 }}>
            {shielded && (
              <span style={{ background:'rgba(0,191,255,0.15)', color:'#00BFFF', border:'1.5px solid rgba(0,191,255,0.4)', borderRadius:100, padding:'5px 12px', fontSize:12, fontFamily:"'Fredoka One',cursive", animation:'shieldPulse 1s ease infinite' }}>
                🛡 SHIELD
              </span>
            )}
