        ctx.globalAlpha=0.08;ctx.fillStyle=b.color;ctx.beginPath();ctx.arc(b.x,b.y,b.w+30,0,Math.PI*2);ctx.fill();ctx.globalAlpha=1;
        if (b.img && b.img.complete && b.img.naturalWidth > 0) {
