          if(b.enraged){ ctx.globalAlpha=0.5; ctx.filter='drop-shadow(0 0 10px #ff0000) hue-rotate(45deg)'; ctx.drawImage(b.img, b.x - b.w*0.8, b.y - b.h*0.8, b.w*1.6, b.h*1.6); ctx.filter='none'; ctx.globalAlpha=1; }
